class ProgressReporter:
    def __init__(self, total: int, enabled: bool = True) -> None:
        self.total = max(0, total)
        self.enabled = enabled and self.total > 0
        self.done = 0
        self.start = time.time()
        self.last_tty_draw = 0.0
        self.is_tty = sys.stderr.isatty()
        self.next_non_tty_log = 0.05

        if self.enabled and not self.is_tty:
            print(f"[progress] 0/{self.total} (0.0%)", file=sys.stderr, flush=True)

    def _render_tty(self) -> None:
        now = time.time()
        if self.done < self.total and (now - self.last_tty_draw) < 0.08:
            return
        self.last_tty_draw = now

        ratio = self.done / self.total if self.total else 1.0
        width = 30
        filled = int(width * ratio)
        bar = "#" * filled + "-" * (width - filled)
        elapsed = max(0.0, now - self.start)
        rate = self.done / elapsed if elapsed > 0 else 0.0
        eta = (self.total - self.done) / rate if rate > 0 else 0.0
        msg = f"\r[{bar}] {self.done}/{self.total} {ratio*100:5.1f}%  elapsed {elapsed:5.1f}s  eta {eta:5.1f}s"
        print(msg, end="", file=sys.stderr, flush=True)
        if self.done >= self.total:
            print(file=sys.stderr, flush=True)

    def _render_non_tty(self) -> None:
        ratio = self.done / self.total if self.total else 1.0
        if self.done >= self.total or ratio >= self.next_non_tty_log:
            print(f"[progress] {self.done}/{self.total} ({ratio*100:.1f}%)", file=sys.stderr, flush=True)
            self.next_non_tty_log += 0.05

    def update(self, inc: int = 1) -> None:
        if not self.enabled:
            return
        self.done = min(self.total, self.done + max(0, inc))
        if self.is_tty:
            self._render_tty()
        else:
            self._render_non_tty()


@lru_cache(maxsize=200_000)
def normalize(text: str | None) -> str:
    if text is None:
        return ""
    stripped = text.strip()
    if not stripped:
        return ""
    if "\n" in stripped or "\t" in stripped or "\r" in stripped or "  " in stripped:
        return re.sub(r"\s+", " ", stripped)
    return stripped


@lru_cache(maxsize=200_000)
def normalize_id(value: str) -> str:
    return normalize(value).upper().replace("_", ":")


@lru_cache(maxsize=200_000)
def format_ontology_id_for_output(value: str) -> str:
    efo_id = normalize_id(value)
    if not efo_id:
        return ""
    return efo_id.replace(":", "_")


@lru_cache(maxsize=200_000)
def norm_key(value: str) -> str:
    return normalize(value).lower()


@lru_cache(maxsize=50_000)
def normalize_input_type(value: str) -> str:
    key = norm_key(value).replace("-", "_").replace(" ", "_")
    return INPUT_TYPE_ALIASES.get(key, "auto")


@lru_cache(maxsize=200_000)
def strip_wrapping_quotes(value: str) -> str:
    text = normalize(value)
    if len(text) >= 2:
        if (text[0] == text[-1] and text[0] in {'"', "'"}):
            inner = normalize(text[1:-1])
            return inner
    return text


@lru_cache(maxsize=50_000)
def normalize_entity_type(value: str) -> str:
    key = norm_key(value).replace("-", "_").replace(" ", "_")
    return ENTITY_TYPE_ALIASES.get(key, "auto")


def effective_name_mode(default_name_mode: str, input_type: str) -> str:
    kind = normalize_input_type(input_type)
    if kind == "protein_name":
        # Protein-name inputs are often not uniquely resolvable via strict alias
        # lookup; enable fuzzy candidate retrieval but rely on validation gates.
        return "fuzzy"
    if kind == "metabolite_name":
        # Metabolite free-text names are commonly synonym-heavy and benefit from
        # lexical candidate retrieval before downstream validation gates.
        return "fuzzy"
    if kind == "gene_symbol":
        return "strict"
    if kind == "gene_id":
        return "strict"
    if kind == "accession":
        return "strict"
    if kind == "metabolite_id":
        return "strict"
    return default_name_mode


def tokenize(text: str) -> set[str]:
    return {tok for tok in re.split(r"[^a-z0-9]+", text.lower()) if tok}


@lru_cache(maxsize=200_000)
def canonical_accession(value: str) -> str:
    token = normalize(value).upper()
    if UNIPROT_ACCESSION_RE.match(token):
        return token
    if "-" in token:
        base = token.split("-", 1)[0]
        if UNIPROT_ACCESSION_RE.match(base):
            return base
    return ""


@lru_cache(maxsize=200_000)
def gene_id_alias_variants(value: str, include_unprefixed_numeric: bool = False) -> tuple[str, ...]:
    token = normalize(value).upper().replace(" ", "")
    if not token:
        return ()
    variants: set[str] = set()

    ensembl_match = ENSEMBL_GENE_ID_RE.match(token)
    if ensembl_match:
        variants.add(token.split(".", 1)[0])

    entrez_match = ENTREZ_GENE_ID_RE.match(token)
    if entrez_match:
        digits = entrez_match.group(1)
        variants.add(f"NCBIGENE:{digits}")
        variants.add(f"GENEID:{digits}")
        variants.add(f"ENTREZ:{digits}")
        if include_unprefixed_numeric:
            variants.add(digits)

    return tuple(sorted(variants))


@lru_cache(maxsize=200_000)
def canonical_metabolite_id(value: str) -> str:
    token = normalize(value).upper().replace(" ", "")
    if not token:
        return ""
    token = token.replace("_", ":")

    hmdb_match = HMDB_ID_RE.match(token)
    if hmdb_match:
        digits = hmdb_match.group(1)
        # HMDB accessions are typically zero-padded to 7+ digits.
        return f"HMDB{digits.zfill(7)}"

    chebi_match = CHEBI_ID_RE.match(token)
    if chebi_match:
        return f"CHEBI:{chebi_match.group(1)}"

    kegg_match = KEGG_ID_RE.match(token)
    if kegg_match:
        return kegg_match.group(1).upper()

    return ""


@lru_cache(maxsize=200_000)
def normalize_lipid_panel_phrase(value: str) -> str:
    phrase = normalize(value)
    if not phrase:
        return ""
    phrase = LIPID_PANEL_PREFIX_RE.sub("", phrase)
    phrase = normalize(re.sub(r"\s*\([^)]*\)", " ", phrase))
    phrase = normalize(phrase)
    for pattern, replacement in LIPID_PANEL_REPLACEMENTS:
        phrase = pattern.sub(replacement, phrase)
    phrase = normalize(re.sub(r"\s+", " ", phrase))
    return phrase


@lru_cache(maxsize=200_000)
def lipid_panel_query_variants(value: str) -> tuple[str, ...]:
    query = normalize(value)
    if not query:
        return ()
    variants: set[str] = {query}
    normalized = normalize_lipid_panel_phrase(query)
    if normalized:
        variants.add(normalized)

    for variant in list(variants):
        base = normalize(variant)
        if not base:
            continue
        singular_forms = {
            normalize(base.replace("cholesteryl esters", "cholesteryl ester")),
            normalize(base.replace("phospholipids", "phospholipid")),
            normalize(base.replace("triglycerides", "triglyceride")),
        }
        for form in singular_forms:
            if form:
                variants.add(form)
        if "/" in base:
            variants.add(normalize(base.replace("/", " / ")))
        for form in {base, *singular_forms}:
            if form and LIPID_MEASUREMENT_VARIANT_RE.match(norm_key(form)):
                variants.add(normalize(f"{form} measurement"))
                variants.add(normalize(f"{form} level"))

    return tuple(v for v in variants if v)


def query_has_protein_cue(value: str) -> bool:
    normalized = normalize(value)
    if PROTEIN_CUE_RE.search(normalized):
        return True
    folded = normalize_lipid_panel_phrase(normalized)
    return bool(folded and PROTEIN_CUE_RE.search(folded))


def query_has_metabolite_cue(value: str) -> bool:
    normalized = normalize(value)
    if METABOLITE_CUE_RE.search(normalized):
        return True
    folded = normalize_lipid_panel_phrase(normalized)
    return bool(folded and METABOLITE_CUE_RE.search(folded))


@lru_cache(maxsize=300_000)
def metabolite_descriptor_tag(value: str) -> str:
    text = norm_key(value)
    if not text:
        return ""
    if "free cholesterol" in text:
        return "free_cholesterol"
    if "cholesteryl ester" in text or "cholesterol ester" in text or "esterified cholesterol" in text:
        return "cholesteryl_ester"
    if re.search(r"\bcholesterol\b", text):
        return "cholesterol"
    if re.search(r"\bphospholipid(?:s)?\b", text):
        return "phospholipid"
    if re.search(r"\btriglyceride(?:s)?\b", text):
        return "triglyceride"
    return ""


@lru_cache(maxsize=300_000)
def has_lipid_chain_signature(value: str) -> bool:
    text = norm_key(value)
    if not text:
        return False
    return re.search(r"\b(?:c)?\d{1,2}:\d{1,2}\b", text) is not None


@lru_cache(maxsize=300_000)
def lipoprotein_class_tags(value: str) -> frozenset[str]:
    text = norm_key(value)
    if not text:
        return frozenset()
    tags: set[str] = set()
    for token in ("vldl", "ldl", "hdl", "idl"):
        if re.search(rf"\b{token}\b", text):
            tags.add(token)
    return frozenset(tags)


@lru_cache(maxsize=300_000)
def lipoprotein_size_tags(value: str) -> frozenset[str]:
    text = norm_key(value)
    if not text:
        return frozenset()
    tags: set[str] = set()
    if re.search(r"\bvery small\b", text):
        tags.add("very_small")
    if re.search(r"\bvery large\b", text) or re.search(r"\bextremely large\b", text):
        tags.add("very_large")
    # Add base sizes only when the "very" qualifiers are absent.
    if "very small" not in text and re.search(r"\bsmall\b", text):
        tags.add("small")
    if "very large" not in text and "extremely large" not in text and re.search(r"\blarge\b", text):
        tags.add("large")
    if re.search(r"\bmedium\b", text):
        tags.add("medium")
    return frozenset(tags)


@lru_cache(maxsize=300_000)
def apolipoprotein_subtype_tags(value: str) -> frozenset[str]:
    text = norm_key(value)
    if not text:
        return frozenset()
    tags: set[str] = set()
    if re.search(r"\b(?:apo[-\s]?a1|apoa1|apolipoprotein\s+a[-\s]?(?:1|i))\b", text):
        tags.add("a1")
    if re.search(r"\b(?:apo[-\s]?a2|apoa2|apolipoprotein\s+a[-\s]?(?:2|ii))\b", text):
        tags.add("a2")
    if re.search(
        r"\b(?:apo[-\s]?(?:b(?:100)?|8|β|Β|в|В|ß)|apob|apolipoprotein\s+b(?:[-\s]?100)?)\b",
        text,
    ):
        tags.add("b")
    return frozenset(tags)


@lru_cache(maxsize=300_000)
def protein_discriminator_tags(value: str) -> frozenset[str]:
    text = norm_key(value)
    if not text:
        return frozenset()
    tags: set[str] = set()
    for tok in subject_core_tokens(text):
        if any(ch.isdigit() for ch in tok):
            tags.add(tok)
            continue
        if tok in ROMAN_NUMERAL_TOKENS:
            tags.add(tok)
            continue
        if split_symbol_tail(tok) is not None:
            tags.add(tok)
    return frozenset(tags)


@lru_cache(maxsize=200_000)
def has_all_lipoprotein_scope(value: str) -> bool:
    text = norm_key(value)
    if not text:
        return False
    return re.search(r"\bin all (?:vldl|ldl|hdl|idl)\b", text) is not None


@lru_cache(maxsize=300_000)
def measurement_state_tags(value: str) -> frozenset[str]:
    text = norm_key(value)
    if not text:
        return frozenset()
    tags: set[str] = set()
    if re.search(r"\bfasting\b|\bduring fasting\b", text):
        tags.add("fasting")
    if re.search(r"\bpostprandial\b|\bafter meal\b|\bnon[- ]fasting\b", text):
        tags.add("postprandial")
    if re.search(r"\bgestational\b|\bgravid\b|\bpregnan", text):
        tags.add("gestational")
    return frozenset(tags)


def condition_mismatch_penalty(query: str, label: str, synonyms: list[str]) -> float:
    query_tags = measurement_state_tags(query)
    candidate_tags = measurement_state_tags(" ".join([label] + synonyms))
    if not candidate_tags:
        return 0.0
    if query_tags:
        if query_tags & candidate_tags:
            return 0.0
        # Query requested a specific state, candidate does not match it.
        return 0.25
    # Query is unqualified; avoid selecting state-specific terms by default.
    return 0.12


@lru_cache(maxsize=400_000)
def normalize_metabolite_alias_text(value: str, ascii_fallback: str = "") -> str:
    raw = normalize(value)
    if not raw:
        raw = normalize(ascii_fallback)
    if not raw:
        return ""
    # ChEBI names.tsv frequently contains HTML formatting tags.
    clean = html.unescape(raw)
    clean = HTML_TAG_RE.sub("", clean)
    clean = normalize(clean)
    if not clean:
        clean = normalize(ascii_fallback)
    if not clean:
        return ""
    # Normalize common minus glyph variants and excessive punctuation spacing.
    clean = clean.replace("\u2212", "-")
    clean = clean.replace("<", " ").replace(">", " ")
    clean = re.sub(r"\s*([,/;:+])\s*", r"\1 ", clean)
    clean = re.sub(r"\s+", " ", clean).strip(" _")
    clean = normalize(clean)
    canonical = canonical_metabolite_id(clean)
    if canonical:
        return canonical
    return clean


@lru_cache(maxsize=400_000)
def metabolite_alias_quality_rank(alias: str) -> tuple[int, int, int, int, str]:
    text = normalize_metabolite_alias_text(alias)
    if not text:
        return (9, 9, 9, 999, "")
    lower = text.lower()
    toks = tokenize(lower)
    letters = sum(ch.isalpha() for ch in text)
    digits = sum(ch.isdigit() for ch in text)
    punct = sum((not ch.isalnum()) and (not ch.isspace()) for ch in text)
    length_penalty = 0
    if len(text) < 3:
        length_penalty = 3
    elif len(text) > 120:
        length_penalty = 3
    elif len(text) > 80:
        length_penalty = 2
    elif len(text) > 50:
        length_penalty = 1

    noise_penalty = 0
    if METABOLITE_NOISE_RE.match(text):
        noise_penalty += 3
    if letters == 0 and not canonical_metabolite_id(text):
        noise_penalty += 3
    if digits > letters and letters > 0:
        noise_penalty += 1
    if punct > max(2, len(text) // 3):
        noise_penalty += 1
    if len(toks) == 1 and len(next(iter(toks), "")) <= 2 and not canonical_metabolite_id(text):
        noise_penalty += 2

    # Prefer commonly used names over synthetic markup-like labels.
    commonness_penalty = 0
    if re.search(r"\b(?:iupac|brand name)\b", lower):
        commonness_penalty += 1
    return (noise_penalty, length_penalty, commonness_penalty, len(text), lower)


@lru_cache(maxsize=400_000)
def keep_metabolite_alias(alias: str) -> bool:
    text = normalize_metabolite_alias_text(alias)
    if not text:
        return False
    if canonical_metabolite_id(text):
        return True
    if len(text) < 2:
        return False
    if METABOLITE_NOISE_RE.match(text):
        return False
    letters = sum(ch.isalpha() for ch in text)
    if letters == 0 and sum(ch.isdigit() for ch in text) > 0:
        return False
    return True


def prune_metabolite_aliases(label: str, aliases: list[str], ids: list[str], max_aliases: int = 64) -> list[str]:
    label_clean = normalize_metabolite_alias_text(label)
    cleaned: set[str] = set()
    for alias in aliases:
        alias_clean = normalize_metabolite_alias_text(alias)
        if alias_clean and keep_metabolite_alias(alias_clean):
            cleaned.add(alias_clean)
    if label_clean:
        cleaned.add(label_clean)
    for met_id in ids:
        canonical = canonical_metabolite_id(met_id)
        if canonical:
            cleaned.add(canonical)

    ids_only = sorted([a for a in cleaned if canonical_metabolite_id(a)])
    text_aliases = [a for a in cleaned if not canonical_metabolite_id(a)]
    text_aliases.sort(key=metabolite_alias_quality_rank)

    if len(text_aliases) > max_aliases:
        text_aliases = text_aliases[:max_aliases]
    return sorted(set(ids_only + text_aliases))


def extract_metabolite_ids_from_text(value: str) -> list[str]:
    text = normalize(value)
    if not text:
        return []
    ids: set[str] = set()
    # Try direct canonical parse first.
    direct = canonical_metabolite_id(text)
    if direct:
        ids.add(direct)

    for raw in re.split(r"[|;, \t]+", text):
        token = normalize(raw)
        if not token:
            continue
        canonical = canonical_metabolite_id(token)
        if canonical:
            ids.add(canonical)

    for match in METABOLITE_CHEBI_INLINE_RE.findall(text):
        ids.add(f"CHEBI:{match}")
    for match in METABOLITE_HMDB_INLINE_RE.findall(text):
        ids.add(f"HMDB{match.zfill(7)}")
    for match in METABOLITE_KEGG_INLINE_RE.findall(text):
        ids.add(match.upper())
    return sorted(ids)


def choose_chebi_primary_label(name_rows: list[tuple[str, str, str]]) -> str:
    if not name_rows:
        return ""

    type_rank = {
        "INN": 0,
        "UNIPROT NAME": 1,
        "SYNONYM": 2,
        "IUPAC NAME": 3,
        "BRAND NAME": 4,
        "": 5,
    }
    status_rank = {
        "1": 0,
        "3": 1,
        "9": 2,
        "": 3,
    }

    best = ""
    best_key: tuple[int, int, int, int, str] | None = None
    for name, row_type, status_id in name_rows:
        clean = normalize_metabolite_alias_text(name)
        if not clean or not keep_metabolite_alias(clean):
            continue
        type_key = type_rank.get(normalize(row_type).upper(), 6)
        status_key = status_rank.get(normalize(status_id), 4)
        quality = metabolite_alias_quality_rank(clean)
        key = (type_key, status_key, *quality)
        if best_key is None or key < best_key:
            best_key = key
            best = clean
    return best


def metabolite_id_bucket(met_id: str) -> str:
    mid = canonical_metabolite_id(met_id)
    if mid.startswith("HMDB"):
        return "hmdb"
    if mid.startswith("CHEBI:"):
        return "chebi"
    if re.match(r"^[CD]\d{5}$", mid):
        return "kegg"
    return "other"


@lru_cache(maxsize=100_000)
def query_variants(query: str) -> tuple[str, ...]:
    q = normalize(query)
    variants: set[str] = {q}
    parts = [normalize(p) for p in MULTI_ID_SEP_RE.split(q) if normalize(p)]
    variants.update(parts)
    for part in list(variants):
        variants.update(lipid_panel_query_variants(part))
    for part in list(variants):
        canonical = canonical_accession(part)
        if canonical:
            variants.add(canonical)
        metabolite_id = canonical_metabolite_id(part)
        if metabolite_id:
            variants.add(metabolite_id)
    return tuple(v for v in variants if v)


def is_measurement_like(label: str, synonyms: list[str]) -> bool:
    bag = tokenize(label)
    for syn in synonyms:
        bag |= tokenize(syn)
    return bool(bag & MEASUREMENT_KEYWORDS)


def similarity_score_prepared(query_lower: str, query_toks: set[str], label: str, synonyms: list[str]) -> float:
    label_toks = tokenize(label)
    overlap = len(query_toks & label_toks) / max(len(query_toks), 1)

    seq = difflib.SequenceMatcher(None, query_lower, label.lower()).ratio()
    syn_best = 0.0
    for syn in synonyms:
        syn_best = max(syn_best, difflib.SequenceMatcher(None, query_lower, syn.lower()).ratio())

    keyword_bonus = 0.2 if label_toks & MEASUREMENT_KEYWORDS else 0.0
    score = 0.45 * seq + 0.35 * syn_best + 0.2 * overlap + keyword_bonus
    return min(1.0, max(0.0, score))


def similarity_score(query: str, label: str, synonyms: list[str]) -> float:
    query_lower = query.lower()
    query_toks = tokenize(query)
    return similarity_score_prepared(query_lower, query_toks, label, synonyms)


def load_query_inputs(path: Path) -> list[tuple[str, str]]:
    if not path.exists():
        raise FileNotFoundError(f"Input file not found: {path}")

    suffix = path.suffix.lower()
    if suffix in {".txt", ".list"}:
        return [(normalize(line), "auto") for line in path.read_text(encoding="utf-8").splitlines() if normalize(line)]

    delimiter = "\t" if suffix in {".tsv", ".tab"} else ","
    with path.open("r", encoding="utf-8", newline="") as handle:
        rows = list(csv.reader(handle, delimiter=delimiter))

    if not rows:
        return []

    # Support single-column headerless TSV/CSV lists where every line is a query.
    # If the first value is a known header name, skip it; otherwise include all rows.
    if rows and len(rows[0]) == 1 and all(len(r) <= 1 for r in rows):
        first = normalize(rows[0][0] if rows[0] else "")
        start_idx = 1 if first.lower() in SEARCHABLE_COLUMNS else 0
        values: list[tuple[str, str]] = []
        for r in rows[start_idx:]:
            raw = r[0] if r else ""
            if raw and normalize(raw):
                values.append((normalize(raw), "auto"))
        return values

    # Multi-column inputs are treated as headered tabular files.
    fieldnames = rows[0]
    field_lookup = {normalize(f).lower(): f for f in fieldnames}
    source_field = None
    for name in SEARCHABLE_COLUMNS:
        if name in field_lookup:
            source_field = field_lookup[name]
            break
    if source_field is None:
        source_field = fieldnames[0]
    type_field = None
    for name in INPUT_TYPE_COLUMNS:
        if name in field_lookup:
            type_field = field_lookup[name]
            break

    values: list[tuple[str, str]] = []
    with path.open("r", encoding="utf-8", newline="") as handle:
        reader = csv.DictReader(handle, delimiter=delimiter)
        for row in reader:
            raw = row.get(source_field, "")
            if raw and normalize(raw):
                raw_type = row.get(type_field, "") if type_field else ""
                values.append((normalize(raw), normalize_input_type(raw_type)))
    return values


def load_queries(path: Path) -> list[str]:
    return [query for query, _input_type in load_query_inputs(path)]


@lru_cache(maxsize=50_000)
def normalize_trait_input_type(value: str) -> str:
    key = norm_key(value).replace("-", "_").replace(" ", "_")
    return TRAIT_INPUT_TYPE_ALIASES.get(key, "auto")


@lru_cache(maxsize=50_000)
def normalize_trait_scale(value: str) -> str:
    key = norm_key(value).replace("-", "_").replace(" ", "_")
    return TRAIT_SCALE_ALIASES.get(key, "auto")


@lru_cache(maxsize=50_000)
def normalize_trait_data_type(value: str) -> str:
    key = norm_key(value).replace("-", "_").replace(" ", "_")
    return TRAIT_DATA_TYPE_ALIASES.get(key, "auto")


@lru_cache(maxsize=50_000)
def normalize_trait_column_key(value: str) -> str:
    return norm_key(value).replace("-", "_").replace(" ", "_")


@lru_cache(maxsize=200_000)
def normalize_icd10_code(value: str) -> str:
    token = normalize(value).upper()
    if not token:
        return ""
    token = token.replace("ICD-10", "ICD10").replace("ICD 10", "ICD10")

    def compact_to_strict(raw: str) -> str:
        compact = normalize(raw).upper().replace("ICD10", "").replace(" ", "")
        compact = compact.strip("()[]{}")
        if STRICT_ICD10_CODE_RE.fullmatch(compact):
            return compact
        # Common compact form in union-style strings, for example A071 -> A07.1
        compact_match = re.fullmatch(rf"({ICD10_CODE_HEAD_RE})([0-9A-Z]{{1,4}})", compact)
        if compact_match:
            return f"{compact_match.group(1)}.{compact_match.group(2)}"
        return ""

    # Parse tokenized segments first so mixed strings like Union#A071#A07.1
    # resolve to the most specific strict code.
    segmented_candidates: list[str] = []
    for raw_part in re.split(r"[\s,;|#/\\]+", token):
        code = compact_to_strict(raw_part)
        if code:
            segmented_candidates.append(code)
    if segmented_candidates:
        segmented_candidates.sort(key=lambda item: ("." not in item, -len(item), item))
        return segmented_candidates[0]

    strict_match = re.search(rf"\b({ICD10_CODE_HEAD_RE}(?:\.[0-9A-Z]{{1,4}})?)\b", token)
    if strict_match:
        return strict_match.group(1)

    compact_match = re.search(rf"\b({ICD10_CODE_HEAD_RE}[0-9A-Z]{{1,4}})\b", token)
    if compact_match:
        compact_code = compact_to_strict(compact_match.group(1))
        if compact_code:
            return compact_code

    if ":" in token:
        token = token.split(":", 1)[0]
    token = token.replace("ICD10", "").strip().replace(" ", "")
    return token


def is_strict_icd10_code(value: str) -> bool:
    token = normalize(value).upper()
    return bool(token and STRICT_ICD10_CODE_RE.fullmatch(token))


def is_context_free_icd10_code(value: str) -> bool:
    token = normalize(value).upper()
    return bool(token and CONTEXT_FREE_ICD10_CODE_RE.fullmatch(token))


@lru_cache(maxsize=1_000_000)
def icd10_code_matches(code: str, target: str, *, include_descendants: bool = True) -> bool:
    """Match ICD10 codes with boundary-aware exact/family semantics.

    - Exact mode: code == target
    - Family mode:
      - target with dot: prefix family (for example M54.4 -> M54.40)
      - 3-char target without dot: chapter-category family (for example C44 -> C44.6)
      - non-strict short targets (for example "S", "T", "V"): raw prefix fallback
    """
    code_norm = normalize_icd10_code(code)
    target_norm = normalize_icd10_code(target)
    code_strict = is_strict_icd10_code(code_norm)
    target_strict = is_strict_icd10_code(target_norm)
    if code_strict and target_strict:
        if code_norm == target_norm:
            return True
        if not include_descendants:
            return False
        if "." in target_norm:
            return code_norm.startswith(target_norm)
        return code_norm.startswith(f"{target_norm}.")

    code_raw = normalize(code).upper().strip()
    target_raw = normalize(target).upper().strip()
    if not code_raw or not target_raw:
        return False
    if include_descendants:
        return code_raw.startswith(target_raw)
    return code_raw == target_raw


def icd10_code_matches_any(
    code: str,
    targets: tuple[str, ...],
    *,
    include_descendants: bool = True,
) -> bool:
    return any(
        icd10_code_matches(code, target, include_descendants=include_descendants)
        for target in targets
    )


class ICD10CodeMatchView(str):
    """String wrapper with boundary-aware ICD10 family matching on startswith()."""

    def startswith(  # type: ignore[override]
        self,
        prefix: str | tuple[str, ...],
        start: int = 0,
        end: int | None = None,
    ) -> bool:
        # Keep native substring behavior if explicit start/end are used.
        if start != 0 or end is not None:
            return super().startswith(prefix, start, len(self) if end is None else end)
        if isinstance(prefix, tuple):
            targets = tuple(str(item) for item in prefix)
            return icd10_code_matches_any(str(self), targets, include_descendants=True)
        return icd10_code_matches(str(self), str(prefix), include_descendants=True)


def query_explicitly_mentions_icd10(text: str) -> bool:
    return bool(re.search(r"\bICD\s*-?\s*10\b", normalize(text), re.IGNORECASE))


@lru_cache(maxsize=500_000)
def query_has_leading_icd10_token(query_text: str, candidate_code: str) -> bool:
    query_norm = normalize(query_text)
    code = normalize_icd10_code(candidate_code)
    if not query_norm or not is_strict_icd10_code(code):
        return False
    code_variants: list[str] = [code]
    compact_code = code.replace(".", "")
    if compact_code and compact_code not in code_variants:
        code_variants.append(compact_code)
    for variant in code_variants:
        if re.match(
            rf"^\s*(?:ICD\s*-?\s*10\s*)?{re.escape(variant)}(?:\b|[:\-\s]|$)",
            query_norm,
            re.IGNORECASE,
        ):
            return True
    # Union/hash-formatted rows often encode field/code tokens as prefixes
    # (for example Union#M2571#M25.71 ...). Treat those as ICD-leading inputs.
    if "#" in query_norm and re.match(r"^\s*(?:Union#)?\d{1,7}#", query_norm, re.IGNORECASE):
        hash_parts = [normalize(part) for part in query_norm.split("#") if normalize(part)]
        for part in hash_parts[:3]:
            part_code = normalize_icd10_code(part)
            if part_code == code and is_strict_icd10_code(part_code):
                return True
    return False


def query_supports_inferred_icd10(query_text: str, candidate_code: str) -> bool:
    code = normalize_icd10_code(candidate_code)
    if not is_strict_icd10_code(code):
        return False
    query_key = norm_key(query_text)
    # Guard against HLA-B27 marker rows (for example "B27 positive/negative")
    # being misinterpreted as infectious-mononucleosis ICD10 code B27.
    if code == "B27" and (
        bool(re.search(r"\bb27\b\s*(?:positive|negative)\b", query_key))
        or "ankylosing spondylitis" in query_key
    ):
        return False
    if query_explicitly_mentions_icd10(query_text):
        return True
    if not is_context_free_icd10_code(code):
        return False
    return query_has_leading_icd10_token(query_text, code)


@lru_cache(maxsize=500_000)
def icd10_parent_fallback_codes(value: str) -> tuple[str, ...]:
    token = normalize_icd10_code(value)
    if not is_strict_icd10_code(token):
        return ()

    variants: list[str] = []
    if "." in token:
        head, tail = token.split(".", 1)
        for width in range(len(tail) - 1, 0, -1):
            parent = f"{head}.{tail[:width]}"
            if parent != token and is_strict_icd10_code(parent) and parent not in variants:
                variants.append(parent)
        if head != token and is_strict_icd10_code(head) and head not in variants:
            variants.append(head)
    return tuple(variants)


@lru_cache(maxsize=500_000)
def extract_icd10_code_from_xref(value: str) -> str:
    raw = normalize(value)
    if not raw:
        return ""
    decoded = urllib.parse.unquote(raw)
    for pattern in (ICD10_XREF_RE, ICD10_XREF_URL_RE):
        match = pattern.search(decoded)
        if match:
            code = normalize_icd10_code(match.group(1))
            if code:
                return code
    return ""


@lru_cache(maxsize=500_000)
def extract_mondo_id(value: str) -> str:
    raw = normalize(value)
    if not raw:
        return ""
    direct = canonicalize_trait_ontology_id(raw)
    if trait_ontology_prefix(direct) == "MONDO":
        return direct
    decoded = urllib.parse.unquote(raw)
    match = MONDO_CURIE_RE.search(decoded)
    if not match:
        return ""
    token = canonicalize_trait_ontology_id(match.group(0))
    return token if trait_ontology_prefix(token) == "MONDO" else ""


@lru_cache(maxsize=200_000)
def normalize_phecode(value: str) -> str:
    token = normalize(value)
    if not token:
        return ""
    match = re.search(r"\b([0-9]{1,4}(?:\.[0-9A-Z]{1,4})?)\b", token.upper())
    if match:
        return match.group(1)
    return token.replace(" ", "")


@lru_cache(maxsize=200_000)
def looks_like_phecode_token(value: str) -> bool:
    raw = normalize(value).upper()
    if not raw:
        return False
    raw = raw.replace("PHECODE", "").replace("PHE", "").strip(" :#-")
    return bool(re.fullmatch(r"[0-9]{1,4}(?:\.[0-9A-Z]{1,4})?", raw))


@lru_cache(maxsize=200_000)
def canonicalize_trait_ontology_id(value: str) -> str:
    raw = normalize(value)
    if not raw:
        return ""
    token = raw.split()[0]
    if token.lower().startswith("http"):
        token = token.rsplit("/", 1)[-1]
    if ":" in token:
        parts = token.split(":")
        last = parts[-1]
        if re.match(r"^[A-Za-z]+_[0-9A-Za-z]+$", last):
            token = last
        elif (
            len(parts) >= 2
            and re.match(r"^[A-Za-z]+$", parts[-2])
            and re.match(r"^[0-9A-Za-z_]+$", last)
        ):
            token = f"{parts[-2].upper()}_{last}"
        else:
            token = last
    token = token.replace(":", "_")
    if "_" in token:
        prefix, local = token.split("_", 1)
        return f"{prefix.upper()}_{local}"
    return token.upper()


def trait_ontology_prefix(ontology_id: str) -> str:
    oid = canonicalize_trait_ontology_id(ontology_id)
    if "_" not in oid:
        return oid
    return oid.split("_", 1)[0]


def split_multi_ids(value: str) -> list[str]:
    return [normalize(part) for part in re.split(r"[|,;]+", str(value)) if normalize(part)]


def split_multi_labels(value: str, expected_n: int) -> list[str]:
    raw = normalize(value)
    if not raw:
        return []
    if "|" in raw:
        return [normalize(part) for part in raw.split("|") if normalize(part)]
    if expected_n > 1 and "," in raw:
        return [normalize(part) for part in raw.split(",") if normalize(part)]
    return [raw]


def informative_trait_tokens(text: str) -> set[str]:
    toks = {tok for tok in tokenize(text) if len(tok) >= 3}
    filtered = {tok for tok in toks if tok not in TRAIT_STOP_TOKENS}
    return filtered or toks


def trait_nonweak_tokens(tokens: set[str]) -> set[str]:
    return {
        tok
        for tok in tokens
        if tok
        and tok not in TRAIT_STOP_TOKENS
        and tok not in TRAIT_WEAK_FUZZY_TOKENS
    }


def trait_anchor_tokens(tokens: set[str]) -> set[str]:
    anchors: set[str] = set()
    for tok in trait_nonweak_tokens(tokens):
        if len(tok) < 4:
            continue
        if tok in DISEASE_HINT_TOKENS:
            continue
        if tok in TRAIT_LOCATION_NONSPECIFIC_TOKENS:
            continue
        anchors.add(tok)
    return anchors


@lru_cache(maxsize=300_000)
def trim_trailing_weak_trait_tokens(text: str) -> str:
    key = norm_key(text)
    if not key:
        return ""
    toks = [tok for tok in re.findall(r"[a-z0-9]+", key) if tok]
    while toks and toks[-1] in TRAIT_PIPE_RIGHT_WEAK_TOKENS:
        toks.pop()
    return " ".join(toks)


@lru_cache(maxsize=300_000)
def strip_trait_query_noise(text: str) -> str:
    clean = normalize(text)
    if not clean:
        return ""
    for pattern, replacement in TRAIT_QUERY_NOISE_SUBS:
        clean = pattern.sub(replacement, clean)
    clean = re.sub(r"\s+", " ", clean).strip()
    return normalize(clean)


@lru_cache(maxsize=300_000)
def strip_trait_response_suffix(text: str) -> str:
    clean = normalize(text)
    if not clean:
        return ""
    stripped = clean
    for pattern in TRAIT_RESPONSE_VALUE_SUFFIX_PATTERNS:
        stripped = pattern.sub("", stripped).strip()
    return normalize(stripped)


@lru_cache(maxsize=300_000)
def strip_trait_response_scale_suffix(text: str) -> str:
    clean = normalize(text)
    if not clean:
        return ""
    stripped = clean
    for pattern in TRAIT_RESPONSE_SCALE_SUFFIX_PATTERNS:
        stripped = pattern.sub("", stripped).strip()
    return normalize(stripped)


@lru_cache(maxsize=300_000)
def canonicalize_comparative_size_response(text: str) -> str:
    clean = normalize(text)
    if not clean:
        return ""
    match = TRAIT_COMPARATIVE_SIZE_RESPONSE_RE.match(clean)
    if not match:
        return ""
    prefix = normalize(match.group("prefix"))
    if not prefix:
        return ""
    option_raw = normalize(match.group("option"))
    option_key = norm_key(option_raw)
    option_key = re.sub(r"[^a-z0-9 ]+", " ", option_key)
    option_key = normalize(re.sub(r"\s+", " ", option_key))
    if not option_key:
        return ""

    canonical_option = ""
    if "height size at age" in prefix:
        if option_key in {"sho", "short", "shorte", "shorter"}:
            canonical_option = "shorter"
        elif option_key in {"tal", "tall", "talle", "taller"}:
            canonical_option = "taller"
        elif option_key in {"abo", "about", "abou", "about average", "average", "avg"}:
            canonical_option = "about average"
    elif "body size at age" in prefix:
        if option_key in {"thin", "thine", "thinne", "thinner", "slim", "slimmer"}:
            canonical_option = "thinner"
        elif option_key in {"plu", "plump", "plumpe", "plumper", "chubby", "heavier"}:
            canonical_option = "plumper"
        elif option_key in {"abo", "about", "abou", "about average", "average", "avg"}:
            canonical_option = "about average"

    if not canonical_option:
        return ""
    return normalize(f"{prefix} - {canonical_option}")


@lru_cache(maxsize=300_000)
def trait_query_looks_response_scale(text: str) -> bool:
    clean = normalize(text)
    if not clean:
        return False
    return bool(TRAIT_RESPONSE_SCALE_CONTEXT_RE.search(clean))


@lru_cache(maxsize=300_000)
def trait_cache_exact_norm_variants(text: str) -> tuple[str, ...]:
    clean = normalize(text)
    if not clean:
        return ()
    candidates = [
        clean,
        strip_trait_query_noise(clean),
        normalize(re.sub(r"\([^)]*\)", " ", clean)),
        strip_trait_response_suffix(clean),
        strip_trait_response_scale_suffix(clean),
        strip_trait_response_suffix(strip_trait_query_noise(clean)),
        strip_trait_response_scale_suffix(strip_trait_query_noise(clean)),
    ]
    canonical_comparative = canonicalize_comparative_size_response(clean)
    if canonical_comparative:
        candidates.extend(
            [
                canonical_comparative,
                normalize(re.sub(r"\([^)]*\)", " ", canonical_comparative)),
                strip_trait_response_suffix(canonical_comparative),
                strip_trait_response_scale_suffix(canonical_comparative),
            ]
        )

    deduped: list[str] = []
    seen: set[str] = set()
    for candidate in candidates:
        key = norm_key(candidate)
        if key and key not in seen:
            seen.add(key)
            deduped.append(key)
    return tuple(deduped)


@lru_cache(maxsize=300_000)
def survey_trait_concept_variants(text: str) -> tuple[str, ...]:
    clean = normalize(text)
    if not clean:
        return ()
    variants: list[str] = []
    base = strip_trait_response_scale_suffix(strip_trait_response_suffix(clean))
    if base and base != clean:
        variants.append(base)
        variants.append(f"{base} self reported")
        variants.append(f"ease of {base}")
        variants.append(f"ease of {base} self reported")
        variants.append(f"difficulty {base}")
        variants.append(f"difficulty {base} self reported")
    deduped: list[str] = []
    seen: set[str] = set()
    for variant in variants:
        key = normalize(variant)
        if key and key not in seen:
            seen.add(key)
            deduped.append(key)
    return tuple(deduped)


@lru_cache(maxsize=300_000)
def trait_field_context_variants(text: str) -> tuple[str, ...]:
    clean = normalize(re.sub(r"_+", " ", text))
    if not clean:
        return ()
    compact = normalize(re.sub(r"\s+", " ", clean))
    raw_parts = [normalize(part) for part in re.split(r"_+", normalize(text)) if normalize(part)]
    if raw_parts and re.fullmatch(r"\d{1,7}", raw_parts[0]):
        raw_parts = raw_parts[1:]
    raw_parts = [
        part
        for part in raw_parts
        if norm_key(part)
        not in {
            "illness",
            "code",
            "sr",
            "phe10",
            "combined",
            "anyinst",
            "bin",
        }
    ]
    summary_markers = {"inst", "instance", "anyinst", "mean", "median", "sd", "se", "raw", "adj", "adjusted", "rint", "bin", "ord", "cont"}
    stop_idx = next((idx for idx, part in enumerate(raw_parts) if norm_key(part) in summary_markers), len(raw_parts))
    core_parts = raw_parts[:stop_idx]
    cut_idx: int | None = None
    protected_numeric_context = {"age", "type", "grade", "stage"}
    for idx, part in enumerate(core_parts):
        if not re.fullmatch(r"\d+", part):
            continue
        if idx >= len(core_parts) - 1:
            continue
        prev = norm_key(core_parts[idx - 1]) if idx > 0 else ""
        if prev in protected_numeric_context:
            continue
        cut_idx = idx
        break
    if cut_idx is not None:
        core_parts = core_parts[:cut_idx]
    title = normalize(" ".join(core_parts)) or compact
    semantic_title = normalize_trait_semantic_text(title)
    semantic_tokens = [
        tok
        for tok in re.findall(r"[a-z0-9]+", semantic_title)
        if tok and tok not in TRAIT_STOP_TOKENS and not tok.isdigit()
    ]
    variants: list[str] = []
    for candidate in (compact, title, semantic_title):
        key = normalize(candidate)
        if key:
            variants.append(key)
    if semantic_tokens:
        for size in range(1, min(3, len(semantic_tokens)) + 1):
            if size == 1:
                starts = sorted({0, len(semantic_tokens) - 1})
            else:
                starts = range(0, len(semantic_tokens) - size + 1)
            for start in starts:
                ngram_tokens = semantic_tokens[start : start + size]
                ngram = " ".join(ngram_tokens)
                tail_token = ngram_tokens[-1]
                if (
                    not ngram
                    or is_generic_trait_label(ngram)
                    or tail_token in TRAIT_FIELD_CONTEXT_WEAK_TAIL_TOKENS
                ):
                    continue
                variants.append(ngram)
                variants.append(f"{ngram} measurement")
                variants.append(f"{ngram} self reported")
    deduped: list[str] = []
    seen: set[str] = set()
    for variant in variants:
        key = normalize(variant)
        if key and key not in seen:
            seen.add(key)
            deduped.append(key)
    return tuple(deduped)


def derive_primary_trait_query_from_additional_info(text: str) -> str:
    variants = trait_field_context_variants(text)
    if not variants:
        return ""
    blocked_tokens = {
        "illness",
        "code",
        "sr",
        "phe10",
        "combined",
        "anyinst",
        "bin",
        "measurement",
        "self",
        "reported",
    }
    best = ""
    best_score = -1
    for variant in variants:
        tokens = [tok for tok in re.findall(r"[a-z0-9]+", norm_key(variant)) if tok]
        if not tokens:
            continue
        informative = [tok for tok in tokens if tok not in blocked_tokens and not tok.isdigit()]
        if not informative:
            continue
        score = len(informative) * 10 - len(tokens)
        if any(tok in {"measurement", "self", "reported"} for tok in tokens):
            score -= 3
        if score > best_score:
            best = normalize(" ".join(informative))
            best_score = score
    return best


@lru_cache(maxsize=300_000)
def normalize_trait_semantic_text(text: str) -> str:
    key = norm_key(strip_trait_query_noise(text))
    if not key:
        return ""
    for pattern, replacement in TRAIT_CANONICAL_SIMILARITY_SUBS:
        key = pattern.sub(replacement, key)
    tokens = [TRAIT_BEHAVIOR_TOKEN_CANONICAL.get(tok, tok) for tok in re.findall(r"[a-z0-9]+", key)]
    collapsed: list[str] = []
    for tok in tokens:
        if not tok:
            continue
        if tok in TRAIT_SEMANTIC_DROP_TOKENS:
            continue
        if collapsed and collapsed[-1] == tok:
            continue
        collapsed.append(tok)
    return " ".join(collapsed).strip()


@lru_cache(maxsize=300_000)
def trait_query_exact_norm_variants(text: str) -> tuple[str, ...]:
    variants: list[str] = []
    canonical_comparative = canonicalize_comparative_size_response(text)
    base_candidates = [
        norm_key(text),
        norm_key(strip_trait_query_noise(text)),
        norm_key(strip_trait_response_suffix(strip_trait_query_noise(text))),
        norm_key(strip_trait_response_scale_suffix(strip_trait_query_noise(text))),
        normalize_trait_semantic_text(text),
        normalize_trait_semantic_text(strip_trait_response_suffix(text)),
    ]
    if canonical_comparative:
        base_candidates.extend(
            [
                norm_key(canonical_comparative),
                norm_key(strip_trait_response_suffix(canonical_comparative)),
                normalize_trait_semantic_text(canonical_comparative),
                normalize_trait_semantic_text(strip_trait_response_suffix(canonical_comparative)),
            ]
        )
    base_candidates.extend(normalize(candidate) for candidate in survey_trait_concept_variants(text))
    for candidate in base_candidates:
        if candidate and candidate not in variants:
            variants.append(candidate)
        paren_stripped = normalize(re.sub(r"\([^)]*\)", " ", candidate))
        paren_norm = norm_key(paren_stripped)
        if paren_norm and paren_norm not in variants:
            variants.append(paren_norm)
        paren_semantic = normalize_trait_semantic_text(paren_stripped)
        if paren_semantic and paren_semantic not in variants:
            variants.append(paren_semantic)
        trimmed = trim_trailing_weak_trait_tokens(candidate)
        if trimmed and trimmed not in variants:
            variants.append(trimmed)
        if "|" in candidate:
            for part in candidate.split("|"):
                part_norm = norm_key(part)
                if part_norm and part_norm not in variants:
                    variants.append(part_norm)
                part_trimmed = trim_trailing_weak_trait_tokens(part_norm)
                if part_trimmed and part_trimmed not in variants:
                    variants.append(part_trimmed)
    return tuple(variants)


@lru_cache(maxsize=300_000)
def normalize_trait_text_for_similarity(text: str) -> str:
    return normalize_trait_semantic_text(text)


@lru_cache(maxsize=300_000)
def trait_has_negation(text: str) -> bool:
    raw = normalize(text)
    if not raw:
        return False
    clean = normalize_trait_text_for_similarity(raw) or norm_key(raw)
    if not clean:
        return False
    # "with or without X" is an inclusive clinical expression, not a strict
    # negation cue that should block validation.
    clean = re.sub(r"\bwith\s+or\s+without\b", " ", clean, flags=re.IGNORECASE)
    # ICD10 phrase boilerplate and "not cancer" disambiguators are not true
    # trait-negation cues for mapping confidence.
    clean = re.sub(r"\bnot\s+(?:elsewhere|otherwise)\s+classified\b", " ", clean, flags=re.IGNORECASE)
    clean = re.sub(r"\bnot\s+specified\b", " ", clean, flags=re.IGNORECASE)
    clean = re.sub(r"\bnot\s+cancer\b", " ", clean, flags=re.IGNORECASE)
    clean = re.sub(r"\bnon\s+cancer\b", " ", clean, flags=re.IGNORECASE)
    return any(pattern.search(clean) for pattern in TRAIT_NEGATION_FLAG_PATTERNS)


@lru_cache(maxsize=300_000)
def trait_is_noninformative_negation(text: str) -> bool:
    raw = normalize(text)
    if not raw:
        return False
    return any(pattern.search(raw) for pattern in TRAIT_NONINFORMATIVE_NEGATION_PATTERNS)


@lru_cache(maxsize=200_000)
def extract_ukb_field_ids(text: str) -> tuple[str, ...]:
    key = normalize(text)
    if not key:
        return ()
    field_ids: list[str] = []
    for match in UKB_DATA_FIELD_RE.findall(key):
        field_id = normalize(match)
        if field_id and field_id not in field_ids:
            field_ids.append(field_id)
    trailing_match = UKB_TRAILING_FIELD_ID_RE.search(key)
    if trailing_match:
        field_id = normalize(trailing_match.group(1))
        if field_id and field_id not in field_ids:
            field_ids.append(field_id)
    for match in UKB_UNDERSCORE_TRAIT_RE.findall(key):
        field_id = normalize(match[0])
        if field_id and field_id not in field_ids:
            field_ids.append(field_id)
    return tuple(field_ids)


@lru_cache(maxsize=200_000)
def extract_explicit_ukb_field_ids(text: str) -> tuple[str, ...]:
    """Extract only explicit UKB data-field IDs from text.

    This intentionally ignores generic underscore forms like `5111_15` so that
    non-UKB rows (for example assay IDs) do not pollute UKB field-code lookup.
    """
    key = normalize(text)
    if not key:
        return ()
    field_ids: list[str] = []
    for match in UKB_DATA_FIELD_RE.findall(key):
        field_id = normalize(match)
        if field_id and field_id not in field_ids:
            field_ids.append(field_id)
    return tuple(field_ids)


@lru_cache(maxsize=200_000)
def parse_ukb_hashed_trait_text(text: str) -> tuple[str, str, str]:
    """Parse common UKB coded trait strings like `20002#1425#cerebral aneurysm`.

    Returns `(field_id, code, label)` with empty strings when a component is not
    present or the pattern does not match.
    """
    raw = normalize(text)
    if not raw:
        return ("", "", "")
    field_id = ""
    remainder = ""
    match = UKB_HASHED_TRAIT_RE.match(raw)
    if match:
        field_id = normalize(match.group(1))
        remainder = normalize(match.group(2))
    else:
        underscore_match = UKB_UNDERSCORE_TRAIT_RE.search(raw)
        if not underscore_match:
            return ("", "", "")
        field_id = normalize(underscore_match.group(1))
        remainder = normalize(underscore_match.group(2))
    if not field_id or not remainder:
        return ("", "", "")

    parts = [normalize(part) for part in remainder.split("#")]

    def clean_label(raw_label: str, parsed_field_id: str) -> str:
        label = normalize(raw_label)
        if not label:
            return ""
        label = re.sub(r"\+\s*/\s*-?\s*", " with or without ", label, flags=re.IGNORECASE)
        label = re.sub(r"\+\s*\|\s*-\s*", " with or without ", label, flags=re.IGNORECASE)
        label = re.sub(
            rf"\s*\(UKB(?:\s*data)?\s*field\s*(?:{re.escape(parsed_field_id)}|[0-9]{{1,7}})\)\s*$",
            "",
            label,
            flags=re.IGNORECASE,
        )
        label = re.sub(rf"^\s*{ICD10_CODE_HEAD_RE}(?:\.[0-9A-Z]{{1,4}})?\s+", "", label, flags=re.IGNORECASE)
        label = re.sub(rf"^\s*{ICD10_CODE_HEAD_RE}[0-9A-Z]{{1,4}}\s+", "", label, flags=re.IGNORECASE)
        label = re.sub(r"\bdvt\b", "deep venous thrombosis", label, flags=re.IGNORECASE)
        if "|" in label:
            pipe_parts = [normalize(part) for part in label.split("|") if normalize(part)]
            if pipe_parts:
                # UKB coded disease labels often use `|` as alias-ish separators
                # (for example "aortic regurgitation | incompetence"). Keep the
                # clinical anchor phrase and only drop a weak trailing segment.
                right_tokens = set(tokenize(norm_key(pipe_parts[-1])))
                right_is_weak = bool(right_tokens) and right_tokens.issubset(TRAIT_PIPE_RIGHT_WEAK_TOKENS)
                if right_is_weak and len(pipe_parts) > 1:
                    kept = [part for part in pipe_parts[:-1] if part]
                    label = " ".join(kept) if kept else pipe_parts[0]
                else:
                    label = " ".join(pipe_parts)
            else:
                label = label.replace("|", " ")
        return normalize(label)

    if "_" in remainder and "#" not in remainder:
        token_parts = [normalize(part) for part in remainder.split("_") if normalize(part)]
        if token_parts:
            # Example: 100580_Alcohol_consumed_1_Yes_AnyInst__BIN
            # Keep the field-title chunk before the response-code segment.
            numeric_idx = next((idx for idx, tok in enumerate(token_parts) if tok.isdigit()), -1)
            title_parts = token_parts[:numeric_idx] if numeric_idx > 0 else token_parts
            response_code = token_parts[numeric_idx] if numeric_idx >= 0 else ""
            title_label = clean_label(" ".join(title_parts), field_id)
            if title_label:
                return (field_id, response_code, title_label)

    if len(parts) == 1:
        return (field_id, "", clean_label(parts[0], field_id))

    code = normalize(parts[0])
    label = clean_label("#".join(parts[1:]), field_id)
    return (field_id, code, label)


@lru_cache(maxsize=200_000)
def parse_ukb_illness_code_sr_token(text: str) -> tuple[str, str, str]:
    raw = normalize(text)
    if not raw:
        return ("", "", "")
    match = UKB_ILLNESS_CODE_SR_RE.match(raw)
    if not match:
        return ("", "", "")
    field_id = normalize(match.group(1))
    code = normalize(match.group(2))
    label = normalize(match.group(3).replace("_", " "))
    if not field_id or not label:
        return ("", "", "")
    return (field_id, code, label)


@lru_cache(maxsize=300_000)
def parse_icd10_labeled_trait_text(text: str) -> tuple[str, str]:
    """Parse text snippets that embed ICD10 code + label.

    Examples:
    - `Union#M2571#M25.71 Osteophyte (Shoulder region)`
    - `40001#I269#I26.9 Pulmonary embolism without mention of acute cor pulmonale`
    """
    raw = normalize(text)
    if not raw:
        return ("", "")

    candidates: list[str] = [raw]
    if "#" in raw:
        last_segment = normalize(raw.rsplit("#", 1)[-1])
        if last_segment:
            candidates.insert(0, last_segment)

    for segment in candidates:
        clean = normalize(segment)
        if not clean:
            continue
        prefixed_match = re.match(
            rf"^\s*ICD\s*-?\s*10\s+({ICD10_CODE_HEAD_RE}(?:\.[0-9A-Z]{{1,4}})?)\s*:\s*(.+)$",
            clean,
            re.IGNORECASE,
        )
        if prefixed_match:
            code = normalize_icd10_code(prefixed_match.group(1))
            label = normalize(prefixed_match.group(2))
            if is_strict_icd10_code(code) and label:
                return code, label
            continue
        strict_match = re.match(rf"^\s*({ICD10_CODE_HEAD_RE}(?:\.[0-9A-Z]{{1,4}})?)\s+(.+)$", clean, re.IGNORECASE)
        if strict_match:
            code = normalize_icd10_code(strict_match.group(1))
            label = normalize(strict_match.group(2))
            if is_strict_icd10_code(code) and label:
                return code, label
            continue
        compact_match = re.match(rf"^\s*({ICD10_CODE_HEAD_RE}[0-9A-Z]{{1,4}})\s+(.+)$", clean, re.IGNORECASE)
        if compact_match:
            code = normalize_icd10_code(compact_match.group(1))
            label = normalize(compact_match.group(2))
            if is_strict_icd10_code(code) and label:
                return code, label

    return ("", "")


def ukb_title_query_variants(field_id: str, title: str) -> tuple[str, ...]:
    fid = normalize(field_id)
    clean_title = normalize(title)
    if not fid or not clean_title:
        return ()
    variants = [
        clean_title,
        f"{clean_title} (UKB data field {fid})",
        f"{clean_title} (UKB data field {fid}) (Gene-based burden)",
    ]
    variants.extend(trait_field_context_variants(clean_title))
    deduped: list[str] = []
    seen: set[str] = set()
    for variant in variants:
        key = normalize(variant)
        if key and key not in seen:
            seen.add(key)
            deduped.append(key)
    return tuple(deduped)


@lru_cache(maxsize=200_000)
def extract_ukb_category_ids(text: str) -> tuple[str, ...]:
    key = normalize(text)
    if not key:
        return ()
    category_ids: list[str] = []
    for match in UKB_CATEGORY_RE.findall(key):
        category_id = normalize(match)
        if category_id and category_id not in category_ids:
            category_ids.append(category_id)
    return tuple(category_ids)


def ukb_category_query_variants(category_id: str, title: str, path_titles: tuple[str, ...]) -> tuple[str, ...]:
    cid = normalize(category_id)
    clean_title = normalize(title)
    clean_path = tuple(normalize(item) for item in path_titles if normalize(item))

    variants: list[str] = []
    if clean_title:
        variants.append(clean_title)
    if clean_path:
        variants.append(" ".join(clean_path))
        variants.append(" > ".join(clean_path))
    if cid and clean_title:
        variants.append(f"Category {cid} {clean_title}")
        variants.append(f"Category {cid}: {clean_title}")

    deduped: list[str] = []
    seen: set[str] = set()
    for variant in variants:
        key = normalize(variant)
        if key and key not in seen:
            seen.add(key)
            deduped.append(key)
    return tuple(deduped)


def ukb_category_path_titles(
    category_id: str,
    *,
    category_titles: dict[str, str],
    category_parents: dict[str, tuple[str, ...]],
    max_depth: int = 12,
) -> tuple[str, ...]:
    cid = normalize(category_id)
    if not cid:
        return ()
    seen: set[str] = set()
    chain: list[str] = []
    current = cid
    depth = 0
    while current and depth < max_depth and current not in seen:
        seen.add(current)
        chain.append(current)
        parents = category_parents.get(current, ())
        current = parents[0] if parents else ""
        depth += 1
    chain.reverse()
    return tuple(normalize(category_titles.get(cat_id, "")) for cat_id in chain if normalize(category_titles.get(cat_id, "")))


def load_ukb_field_category_index(path: Path | None) -> tuple[dict[str, str], dict[str, tuple[str, ...]]]:
    if path is None or not path.exists():
        return {}, {}

    field_to_category: dict[str, str] = {}
    category_to_fields: dict[str, list[str]] = {}
    try:
        with path.open("r", encoding="utf-8", newline="") as handle:
            reader = csv.DictReader(handle, delimiter="\t")
            for row in reader:
                field_id = normalize(row.get("field_id", ""))
                category_id = normalize(row.get("main_category", ""))
                if not field_id or not category_id:
                    continue
                field_to_category[field_id] = category_id
                if field_id not in category_to_fields.setdefault(category_id, []):
                    category_to_fields[category_id].append(field_id)
    except OSError:
        return {}, {}

    frozen_category_to_fields = {cat: tuple(field_ids) for cat, field_ids in category_to_fields.items()}
    return field_to_category, frozen_category_to_fields


def load_ukb_category_title_index(path: Path | None) -> dict[str, str]:
    if path is None or not path.exists():
        return {}

    titles: dict[str, str] = {}
    try:
        with path.open("r", encoding="utf-8", errors="replace", newline="") as handle:
            reader = csv.DictReader(handle, delimiter="\t")
            for row in reader:
                category_id = normalize(row.get("category_id", ""))
                title = normalize(row.get("title", ""))
                if not category_id or not title:
                    continue
                titles[category_id] = title
    except OSError:
        return {}
    return titles


def load_ukb_category_parent_index(path: Path | None) -> dict[str, tuple[str, ...]]:
    if path is None or not path.exists():
        return {}

    parents: dict[str, list[str]] = {}
    try:
        with path.open("r", encoding="utf-8", errors="replace", newline="") as handle:
            reader = csv.DictReader(handle, delimiter="\t")
            for row in reader:
                parent_id = normalize(row.get("parent_id", ""))
                child_id = normalize(row.get("child_id", ""))
                if not parent_id or not child_id:
                    continue
                if parent_id not in parents.setdefault(child_id, []):
                    parents[child_id].append(parent_id)
    except OSError:
        return {}

    return {child_id: tuple(parent_ids) for child_id, parent_ids in parents.items()}


def normalize_negation_target(token: str) -> str:
    tok = norm_key(token)
    if len(tok) <= 3:
        return tok
    if tok.endswith("ies"):
        return tok[:-3] + "y"
    if tok.endswith("s") and not tok.endswith("ss"):
        return tok[:-1]
    return tok


def extract_negated_trait_targets(text: str) -> set[str]:
    key = normalize_trait_text_for_similarity(text)
    if not key:
        return set()
    toks = [tok for tok in re.split(r"[^a-z0-9]+", key) if tok]
    targets: set[str] = set()
    for idx, tok in enumerate(toks[:-1]):
        if tok not in TRAIT_NEGATION_CUES:
            continue
        target = ""
        for next_tok in toks[idx + 1 :]:
            if next_tok in TRAIT_NEGATION_SKIP_TOKENS:
                continue
            target = normalize_negation_target(next_tok)
            break
        if not target or target in TRAIT_STOP_TOKENS:
            continue
        targets.add(target)
    return targets


def trait_negation_mismatch(query_text: str, candidate_text: str) -> bool:
    qnorm = normalize_trait_text_for_similarity(query_text)
    cnorm = normalize_trait_text_for_similarity(candidate_text)
    if not qnorm or not cnorm:
        return False
    q_neg = extract_negated_trait_targets(qnorm)
    c_neg = extract_negated_trait_targets(cnorm)
    if not q_neg and not c_neg:
        return False
    if q_neg == c_neg:
        return False
    q_toks = {normalize_negation_target(tok) for tok in tokenize(qnorm)}
    c_toks = {normalize_negation_target(tok) for tok in tokenize(cnorm)}
    return bool((q_neg & c_toks) or (c_neg & q_toks))


def trait_looks_multi_concept(text: str) -> bool:
    key = normalize_trait_text_for_similarity(text)
    if not key:
        return False
    if key.startswith("treatment or medication use"):
        return False
    if TRAIT_MULTI_CONNECTOR_RE.search(key):
        return True
    toks = set(tokenize(key))
    return bool(toks & TRAIT_MULTI_HINT_TOKENS)


def skip_multi_mapped_cache_fuzzy_candidate(
    *,
    query_text: str,
    query_tokens: set[str],
    record: TraitCacheRecord,
    mapped_id_count: int | None = None,
) -> bool:
    # For single-trait queries, avoid fuzzy promotion of composite cache rows
    # (e.g. "Crohn's disease or Leprosy") that can inject unrelated terms.
    count = mapped_id_count if mapped_id_count is not None else len(record.mapped_ids)
    if count <= 1:
        return False
    if not query_tokens:
        return False
    if trait_looks_multi_concept(query_text):
        return False

    candidate_text = record.lookup_text or record.reported_trait
    if not trait_looks_multi_concept(candidate_text):
        return False

    candidate_norm = normalize_trait_text_for_similarity(candidate_text)
    candidate_tokens = informative_trait_tokens(candidate_norm)
    if not candidate_tokens:
        return False
    return query_tokens.issubset(candidate_tokens)


def has_disease_hint(text: str) -> bool:
    toks = tokenize(text)
    if any(tok in DISEASE_HINT_TOKENS for tok in toks):
        return True
    return any(tok.endswith(DISEASE_SUFFIX_HINTS) for tok in toks)


def background_trait_primary_clause_candidate(
    *,
    query_raw: str,
    query_label: str,
    query_key: str,
    is_icd_context: bool,
    strict_manual_cache_locked: bool,
    current_matched_via: str,
) -> str:
    if strict_manual_cache_locked or not is_icd_context:
        return ""
    if " in " not in query_key or " in situ " in f" {query_key} ":
        return ""
    if current_matched_via == "icd10_specific_override":
        return ""
    primary_part, tail_part = query_label.split(" in ", 1)
    primary_phrase = normalize(primary_part.strip(" ,;:"))
    tail_phrase = normalize(tail_part.strip(" ,;:"))
    if not primary_phrase or not tail_phrase:
        return ""
    primary_key = norm_key(primary_phrase)
    tail_key = norm_key(tail_phrase)
    if not primary_key or not tail_key:
        return ""
    if primary_key in BACKGROUND_TRAIT_PRIMARY_CLAUSE_GENERIC_PRIMARY_KEYS:
        return ""
    if BACKGROUND_TRAIT_PRIMARY_CLAUSE_TAIL_BLOCKLIST_RE.search(tail_key):
        return ""
    tail_has_disease_context = (
        has_disease_hint(tail_key)
        or "classified elsewhere" in tail_key
        or bool(BACKGROUND_TRAIT_PRIMARY_CLAUSE_TAIL_DISEASE_HINT_RE.search(tail_key))
    )
    if not tail_has_disease_context:
        return ""
    return primary_phrase


def has_ukb_disease_context(text: str) -> bool:
    key = norm_key(text)
    if not key:
        return False
    if has_disease_hint(key):
        return True
    return any(phrase in key for phrase in UKB_DISEASE_CATEGORY_PHRASES)


def is_generic_trait_label(label: str) -> bool:
    key = norm_key(label)
    if not key:
        return True
    if key in GENERIC_TRAIT_LABEL_KEYS:
        return True
    toks = [tok for tok in tokenize(key) if tok not in TRAIT_STOP_TOKENS]
    if len(toks) <= 1 and any(tok in GENERIC_TRAIT_LABEL_KEYS for tok in toks):
        return True
    return False


def candidate_is_broad_umbrella_trait(candidate: Candidate) -> bool:
    key = norm_key(candidate.label)
    if not key:
        return True
    if key in {
        "mental health",
        "cancer",
        "family history",
        "birth measurement",
    }:
        return True
    match = re.fullmatch(r"([a-z ]+?)(?:system )?(disease|disorder|symptom)s?", key)
    if not match:
        return False
    prefix_tokens = [tok for tok in tokenize(match.group(1)) if tok not in {"or", "and"}]
    if not prefix_tokens:
        return True
    broad_prefix_tokens = {
        "mental",
        "behavioural",
        "behavioral",
        "bone",
        "joint",
        "soft",
        "tissue",
        "musculoskeletal",
        "respiratory",
        "digestive",
        "abdominal",
        "gastrointestinal",
        "genitourinary",
        "urinary",
        "cardiovascular",
        "heart",
        "eye",
        "ear",
        "skin",
        "liver",
        "kidney",
    }
    return all(tok in broad_prefix_tokens for tok in prefix_tokens)


def trait_query_explicit_cancer_family(text: str) -> str:
    key = normalize_trait_text_for_similarity(text) or norm_key(text)
    if not key:
        return ""
    toks = set(tokenize(key))
    if "carcinoma" in toks:
        return "carcinoma"
    if "cancer" in toks:
        return "cancer"
    return ""


def candidate_primary_cancer_family(candidate: Candidate) -> str:
    label_text = normalize(candidate.label)
    label_parts = split_multi_labels(label_text, expected_n=max(1, len(split_multi_ids(candidate.efo_id))))
    labels = [label_text, *label_parts]
    for label in labels:
        toks = set(tokenize(normalize_trait_text_for_similarity(label) or norm_key(label)))
        if "benign" in toks:
            # Benign neoplasms should not satisfy explicit cancer-family intent.
            continue
        if "carcinoma" in toks:
            return "carcinoma"
        if "cancer" in toks:
            return "cancer"
        # In EFO/MONDO, many malignant entities are labeled as "neoplasm"
        # with cancer synonyms. Treat those as cancer-family for selection.
        if toks & {"neoplasm", "tumor", "tumour", "malignancy"}:
            return "cancer"
    return ""


def trait_query_contradicts_candidate(query_text: str, candidate: Candidate) -> bool:
    query_key = normalize_trait_text_for_similarity(query_text) or norm_key(query_text)
    label_key = normalize_trait_text_for_similarity(candidate.label) or norm_key(candidate.label)
    if not query_key or not label_key:
        return False
    query_key_spaced = query_key.replace("-", " ")
    label_key_spaced = label_key.replace("-", " ")
    query_tokens = set(tokenize(query_key))
    label_tokens = set(tokenize(label_key))
    if (
        "cutaneous" in label_tokens
        and query_tokens.isdisjoint({"cutaneous", "skin", "dermal", "epidermal"})
        and query_tokens.isdisjoint({"superficial", "mycosis", "mycoses", "fungal"})
    ):
        return True
    if "vomiting" in query_tokens and "nausea" not in query_tokens and {"vomiting", "nausea"}.issubset(label_tokens):
        return True
    scar_query_tokens = {"scar", "scarring", "fibrosis", "fibrotic"}
    if (query_tokens & scar_query_tokens) and "atrophy" in label_tokens and not (label_tokens & scar_query_tokens):
        return True
    if (
        "follicular" in query_tokens
        and "thyroid" in label_tokens
        and "thyroid" not in query_tokens
        and "adenoma" in label_tokens
        and "adenoma" not in query_tokens
    ):
        return True
    if (
        "follicular" in query_tokens
        and "thyroid" in label_tokens
        and "thyroid" not in query_tokens
        and query_tokens.isdisjoint({"carcinoma", "adenoma", "neoplasm", "cancer", "thyroid"})
    ):
        return True
    if (query_tokens & {"injury", "wound", "trauma", "contusion", "laceration", "fracture"}) and "hiv" in label_tokens and "hiv" not in query_tokens:
        return True
    q_neg = extract_negated_trait_targets(query_text)
    if "non hodgkin lymphoma" in query_key_spaced:
        q_neg = set()
    if q_neg:
        label_tokens = {normalize_negation_target(tok) for tok in tokenize(label_key)}
        candidate_tokens = {
            normalize_negation_target(tok)
            for tok in tokenize(normalize_trait_phrase_aliases(candidate.label) or candidate.label)
        }
        if q_neg & (label_tokens | candidate_tokens):
            return True
    if "non melanoma" in query_key_spaced and "melanoma" in label_key_spaced and "non melanoma" not in label_key_spaced:
        return True
    if "sleep apnea" in query_key and label_key == "sleep disorder":
        return True
    if "cholelithiasis" in query_key and label_key == "gallstones":
        return True
    specific_cancer_site_match = re.search(
        r"\b(?:malignant neoplasm|carcinoma|melanoma)\s+of\s+(.+)$",
        query_key_spaced,
        flags=re.IGNORECASE,
    )
    if (
        specific_cancer_site_match
        and "screening" not in query_key_spaced
        and "personal history of" not in query_key_spaced
        and "family history of" not in query_key_spaced
    ):
        site_fragment = specific_cancer_site_match.group(1)
        site_fragment = re.sub(r"\bukb\s+data\s+field\s+\d+.*$", "", site_fragment, flags=re.IGNORECASE)
        site_fragment = re.sub(r"\([^)]*\)", " ", site_fragment).strip()
        site_tokens = informative_trait_tokens(
            normalize_trait_text_for_similarity(site_fragment) or norm_key(site_fragment)
        )
        generic_site_tokens = {
            "malignant",
            "neoplasm",
            "carcinoma",
            "cancer",
            "melanoma",
            "tumor",
            "tumour",
            "gland",
            "organ",
            "system",
            "site",
            "sites",
            "unspecified",
            "other",
            "overlapping",
            "except",
            "including",
            "upper",
            "lower",
            "inner",
            "outer",
            "quadrant",
        }
        site_tokens = {tok for tok in site_tokens if tok not in generic_site_tokens}
        label_tokens = informative_trait_tokens(label_key)
        # Keep subsite specificity: if the query names a concrete subsite
        # qualifier (for example ascending/sigmoid/quadrant), require at least
        # one such qualifier in the mapped label rather than accepting a broad
        # organ-only cancer term.
        broad_site_roots = {
            "colon",
            "colonic",
            "rectum",
            "rectal",
            "bowel",
            "intestine",
            "intestinal",
            "breast",
            "lung",
            "brain",
            "liver",
            "kidney",
            "renal",
            "bladder",
            "ovary",
            "testis",
            "thyroid",
            "stomach",
            "pancreas",
            "esophagus",
            "uterus",
            "cervix",
            "skin",
            "prostate",
            "hepatic",
            "bile",
            "duct",
        }
        detailed_site_tokens = {tok for tok in site_tokens if tok not in broad_site_roots}
        if (
            "melanoma" in query_key_spaced
            and "melanoma" in label_tokens
        ):
            pass
        elif detailed_site_tokens and detailed_site_tokens.isdisjoint(label_tokens):
            return True
        elif site_tokens and not (site_tokens & label_tokens):
            return True
    if query_tokens and query_tokens.issubset(
        {"cancer", "carcinoma", "neoplasm", "tumor", "tumour", "malignant", "situ"}
    ):
        label_location_hints = {
            tok
            for tok in trait_location_hint_tokens(label_key)
            if tok not in TRAIT_LOCATION_NONSPECIFIC_TOKENS
        }
        # Generic cancer wording should not map to a specific site cancer when
        # the query itself does not carry a site hint.
        if label_location_hints:
            return True
    unspecified_site_query = bool(
        re.search(r"\b(?:other and )?unspecified\b", query_key_spaced)
        and (
            "site" in query_key_spaced
            or "sites" in query_key_spaced
            or "genital organ" in query_key_spaced
            or "genital organs" in query_key_spaced
            or "parts of" in query_key_spaced
        )
    )
    if unspecified_site_query:
        query_hints = {
            tok
            for tok in trait_location_hint_tokens(query_key)
            if tok not in TRAIT_LOCATION_NONSPECIFIC_TOKENS
        }
        label_hints = {
            tok
            for tok in trait_location_hint_tokens(label_key)
            if tok not in TRAIT_LOCATION_NONSPECIFIC_TOKENS
        }
        # "other/unspecified site" inputs should not be narrowed to a
        # concrete organ/site unless that site is explicit in the query.
        if label_hints and (not query_hints or label_hints.isdisjoint(query_hints)):
            return True
    if "malignant" in query_tokens and "benign" in label_tokens:
        return True
    if "benign" in query_tokens and "malignant" in label_tokens:
        return True
    if (
        ("bipolar i disorder" in query_key_spaced or "bipolar ii disorder" in query_key_spaced)
        and "bipolar" not in label_key_spaced
        and "depress" in label_key_spaced
    ):
        return True
    if "no bipolar or depression" in query_key_spaced and (
        "bipolar" in label_key_spaced or "depress" in label_key_spaced
    ):
        return True
    return False


def canonicalize_candidate_component_order(query_text: str, candidate: Candidate) -> Candidate:
    ids = [canonicalize_trait_ontology_id(part) for part in split_multi_ids(candidate.efo_id)]
    labels = split_multi_labels(candidate.label, expected_n=len(ids))
    if len(ids) < 2 or len(ids) != len(labels):
        return candidate
    query_key = normalize_trait_phrase_aliases(query_text) or normalize_trait_text_for_similarity(query_text) or norm_key(query_text)
    query_tokens = re.findall(r"[a-z0-9]+", query_key)
    if not query_tokens:
        return candidate
    token_positions: dict[str, int] = {}
    for idx, token in enumerate(query_tokens):
        token_positions.setdefault(token, idx)

    def component_rank(item: tuple[str, str]) -> tuple[int, int, str]:
        term_id, label = item
        label_key = normalize_trait_phrase_aliases(label) or normalize_trait_text_for_similarity(label) or norm_key(label)
        label_tokens = list(informative_trait_tokens(label_key))
        positions = [token_positions[tok] for tok in label_tokens if tok in token_positions]
        return (
            min(positions) if positions else 10**6,
            -len(positions),
            term_id,
        )

    ordered = sorted(zip(ids, labels), key=component_rank)
    ordered_ids = [term_id for term_id, _label in ordered]
    if ordered_ids == ids:
        return candidate
    ordered_labels = [label for _term_id, label in ordered]
    return Candidate(
        efo_id="|".join(ordered_ids),
        label="|".join(ordered_labels),
        score=candidate.score,
        matched_via=candidate.matched_via,
        evidence=candidate.evidence,
        is_validated=candidate.is_validated,
        roundtrip_status=candidate.roundtrip_status,
        roundtrip_accessions=candidate.roundtrip_accessions,
        roundtrip_symbols=candidate.roundtrip_symbols,
    )


def candidate_is_family_history(candidate: Candidate) -> bool:
    key = norm_key(candidate.label)
    return key.startswith("family history")


def build_multi_concept_exact_candidate(
    *,
    query_text: str,
    ontology_exact_index: dict[str, set[str]],
    ontology_terms: dict[str, TraitOntologyTerm],
    measurement_term_ids: set[str],
    icd10_mode: bool = False,
) -> Candidate | None:
    query_norm = normalize_trait_text_for_similarity(query_text)
    if not query_norm:
        return None
    if " without " in query_norm:
        query_norm = normalize(query_norm.split(" without ", 1)[0])
        if not query_norm:
            return None
    if any(
        phrase in query_norm
        for phrase in {
            "classified elsewhere",
            "cause of disease",
            "cause of diseases",
            "other disorders of",
            "other diseases of",
            "other specified disorders of",
            "unspecified disorder of",
            "unspecified disorders of",
        }
    ):
        return None
    query_tokens = [tok for tok in re.findall(r"[a-z0-9]+", query_norm) if tok and tok not in TRAIT_STOP_TOKENS]
    if len(query_tokens) < 2:
        return None

    term_support: dict[str, set[str]] = {}
    max_ngram = min(4, len(query_tokens))
    for size in range(max_ngram, 0, -1):
        for start in range(0, len(query_tokens) - size + 1):
            ngram = " ".join(query_tokens[start : start + size]).strip()
            if not ngram or is_generic_trait_label(ngram):
                continue
            for oid in exact_ontology_term_ids_for_keys(
                (ngram,),
                ontology_exact_index=ontology_exact_index,
                ontology_terms=ontology_terms,
            ):
                term = ontology_terms.get(oid)
                if term is None:
                    continue
                if icd10_mode and size == 1 and len(ngram) <= 4 and ngram.isalpha():
                    # Guard ICD10 multi-exact decomposition against short-token
                    # acronym collisions (for example "face" -> "FACE").
                    term_label_tokens = informative_trait_tokens(
                        normalize_trait_text_for_similarity(term.label)
                    )
                    if ngram not in term_label_tokens:
                        continue
                branch = trait_term_branch(
                    term_id=oid,
                    label=term.label,
                    ontology_terms=ontology_terms,
                    measurement_term_ids=measurement_term_ids,
                )
                if branch != "non_measurement":
                    continue
                candidate_probe = Candidate(
                    efo_id=oid,
                    label=term.label,
                    score=0.0,
                    matched_via="",
                    evidence="",
                    is_validated=False,
                )
                if is_generic_trait_label(term.label):
                    continue
                if candidate_is_broad_umbrella_trait(candidate_probe):
                    continue
                if candidate_is_family_history(
                    candidate_probe
                ):
                    continue
                if candidate_has_go_mapping(oid) or candidate_has_uberon_mapping(oid):
                    continue
                if candidate_is_laterality_only_entity(
                    candidate_probe
                ):
                    continue
                if candidate_is_descriptor_only_entity(candidate_probe):
                    continue
                if candidate_is_anatomy_or_substance_entity(candidate_probe):
                    continue
                if candidate_is_non_disease_entity(candidate_probe, ontology_terms=ontology_terms):
                    continue
                if candidate_is_nonhuman_animal_specific(
                    candidate_probe,
                    ontology_terms=ontology_terms,
                ):
                    continue
                if norm_key(term.label) in TRAIT_MULTI_COMPONENT_DISALLOWED_LABEL_KEYS:
                    continue
                term_support.setdefault(oid, set()).add(ngram)

    if len(term_support) < 2:
        return None

    ranked = sorted(
        term_support.items(),
        key=lambda item: (
            -max(len(s.split()) for s in item[1]),
            -len(item[1]),
            TRAIT_PREFERRED_PREFIX_ORDER.get(trait_ontology_prefix(item[0]), 999),
            item[0],
        ),
    )
    chosen: list[tuple[str, set[str]]] = []
    used_support: set[str] = set()
    for term_id, supports in ranked:
        novel_support = {s for s in supports if s not in used_support}
        if not novel_support and chosen:
            continue
        term_label_tokens = informative_trait_tokens(
            normalize_trait_text_for_similarity(ontology_terms[term_id].label)
        )
        if any(
            term_label_tokens
            and term_label_tokens.issubset(
                informative_trait_tokens(
                    normalize_trait_text_for_similarity(ontology_terms[existing_id].label)
                )
            )
            for existing_id, _existing_supports in chosen
        ):
            continue
        chosen.append((term_id, supports))
        used_support.update(supports)
        if len(chosen) == 2:
            break

    if len(chosen) < 2:
        return None

    ids = [term_id for term_id, _supports in chosen]
    labels = [ontology_terms[term_id].label for term_id in ids]
    if len({norm_key(label) for label in labels}) < 2:
        return None
    if any(is_generic_trait_label(label) for label in labels):
        return None
    return Candidate(
        efo_id="|".join(ids),
        label="|".join(labels),
        score=0.9,
        matched_via="efo_obo_exact_multi",
        evidence="multiple exact ontology subphrase matches in efo.obo",
        is_validated=True,
    )


def trait_query_is_catchall(text: str) -> bool:
    key = normalize_trait_text_for_similarity(text) or norm_key(text)
    if not key:
        return False
    return bool(
        re.search(r"\bother\b", key)
        or re.search(r"\bproblem(?:s)?\b", key)
        or re.search(r"\bdisorder\b", key)
    )


def candidate_has_unmatched_location_specificity(query_text: str, label_text: str) -> bool:
    query_hints = trait_location_hint_tokens(query_text)
    label_hints = trait_location_hint_tokens(label_text)
    if not query_hints or not label_hints:
        return False
    if not query_hints.isdisjoint(label_hints):
        return False
    return bool(label_hints - query_hints)


def candidate_has_unsupported_pathology_specificity(query_text: str, label_text: str) -> bool:
    query_key = normalize_trait_text_for_similarity(query_text)
    label_key = normalize_trait_text_for_similarity(label_text)
    if not query_key or not label_key:
        return False
    unsupported_groups = (
        {"neoplasm", "tumor", "tumour", "cancer", "carcinoma", "sarcoma", "malignancy"},
        {"abnormality"},
    )
    query_tokens = set(re.findall(r"[a-z0-9]+", query_key))
    label_tokens = set(re.findall(r"[a-z0-9]+", label_key))
    for group in unsupported_groups:
        if label_tokens & group and not query_tokens & group:
            return True
    return False


def trait_query_label_overlap_ratio(query_text: str, label_text: str) -> float:
    query_norm = normalize_trait_text_for_similarity(query_text)
    label_norm = normalize_trait_text_for_similarity(label_text)
    query_tokens = informative_trait_tokens(query_norm)
    label_tokens = informative_trait_tokens(label_norm)
    if not query_tokens or not label_tokens:
        return 0.0
    return len(query_tokens & label_tokens) / max(1, len(query_tokens))


def trait_nonweak_overlap(query_text: str, label_text: str) -> set[str]:
    query_norm = normalize_trait_text_for_similarity(query_text)
    label_norm = normalize_trait_text_for_similarity(label_text)
    query_tokens = informative_trait_tokens(query_norm)
    label_tokens = informative_trait_tokens(label_norm)
    if not query_tokens or not label_tokens:
        return set()
    overlap = query_tokens & label_tokens
    return trait_nonweak_tokens(overlap)


def trait_has_anchor_overlap(query_text: str, label_text: str) -> bool:
    query_norm = normalize_trait_text_for_similarity(query_text)
    label_norm = normalize_trait_text_for_similarity(label_text)
    query_tokens = informative_trait_tokens(query_norm)
    label_tokens = informative_trait_tokens(label_norm)
    if not query_tokens or not label_tokens:
        return False
    query_anchors = trait_anchor_tokens(query_tokens)
    label_anchors = trait_anchor_tokens(label_tokens)
    if not query_anchors or not label_anchors:
        return False
    return not query_anchors.isdisjoint(label_anchors)


def trait_enzyme_cues(text: str) -> set[str]:
    key = normalize_trait_text_for_similarity(text) or norm_key(text)
    if not key:
        return set()
    toks = set(re.findall(r"[a-z0-9]+", key))
    return {tok for tok in toks if tok in ENZYME_CUE_TOKENS}


def candidate_misses_query_enzyme_cue(query_text: str, label_text: str) -> bool:
    query_cues = trait_enzyme_cues(query_text)
    if not query_cues:
        return False
    label_cues = trait_enzyme_cues(label_text)
    if label_cues:
        return False
    return True


def trait_location_hint_tokens(text: str) -> set[str]:
    norm = normalize_trait_text_for_similarity(text)
    if not norm:
        return set()
    tokens = informative_trait_tokens(norm)
    hints: set[str] = set()
    for tok in tokens:
        if len(tok) < 3:
            continue
        if tok.isdigit():
            continue
        if re.fullmatch(r"[a-tv-z][0-9]{2,4}", tok):
            continue
        if tok in TRAIT_STOP_TOKENS:
            continue
        if tok in DISEASE_HINT_TOKENS:
            continue
        if tok in TRAIT_LOCATION_NONSPECIFIC_TOKENS:
            continue
        hints.add(tok)
    return hints


def trait_specificity_loss_flag(
    *,
    query_text: str,
    icd10: str,
    matched_via: str,
    mapped_id_text: str,
    mapped_label_text: str,
    ontology_terms: dict[str, TraitOntologyTerm],
) -> tuple[str, str]:
    method_key = norm_key(matched_via)
    if method_key not in ICD10_PARENT_FALLBACK_METHOD_KEYS:
        return "no", ""

    strict_icd10 = normalize_icd10_code(icd10)
    if not strict_icd10 or "." not in strict_icd10:
        return "no", ""

    input_location_tokens = trait_location_hint_tokens(query_text)
    if not input_location_tokens:
        return "no", ""

    mapped_location_tokens: set[str] = set()
    mapped_ids = [canonicalize_trait_ontology_id(part) for part in split_multi_ids(mapped_id_text)]
    mapped_ids = [item for item in mapped_ids if item]
    mapped_labels = split_multi_labels(mapped_label_text, expected_n=len(mapped_ids))

    if not mapped_ids:
        mapped_location_tokens |= trait_location_hint_tokens(mapped_label_text)
    else:
        for idx, mapped_id in enumerate(mapped_ids):
            label_text = normalize(mapped_labels[idx] if idx < len(mapped_labels) else "")
            term = ontology_terms.get(mapped_id)
            if label_text:
                mapped_location_tokens |= trait_location_hint_tokens(label_text)
            if term is not None and term.label:
                mapped_location_tokens |= trait_location_hint_tokens(term.label)

    if input_location_tokens.isdisjoint(mapped_location_tokens):
        token_preview = "|".join(sorted(input_location_tokens)[:4])
        return "yes", f"location detail in input not represented by mapped term ({token_preview})"
    return "no", ""


def load_ukb_field_title_index(path: Path | None) -> dict[str, str]:
    if path is None or not path.exists():
        return {}

    field_titles: dict[str, str] = {}
    try:
        with path.open("r", encoding="utf-8", newline="") as handle:
            reader = csv.DictReader(handle, delimiter="\t")
            for row in reader:
                field_id = normalize(row.get("field_id", ""))
                title = normalize(row.get("title", ""))
                if not field_id or not title:
                    continue
                field_titles[field_id] = title
    except OSError:
        return {}
    return field_titles


def load_trait_query_inputs(path: Path, *, default_trait_scale: str = "auto") -> list[dict[str, str]]:
    if not path.exists():
        raise FileNotFoundError(f"Input file not found: {path}")
    default_scale_norm = normalize_trait_scale(default_trait_scale)

    suffix = path.suffix.lower()
    if suffix in {".txt", ".list"}:
        rows: list[dict[str, str]] = []
        for idx, line in enumerate(path.read_text(encoding="utf-8").splitlines(), start=1):
            query = normalize(line)
            if not query:
                continue
            rows.append(
                {
                    "row_id": str(idx),
                    "query": query,
                    "input_type": "auto",
                    "trait_scale": default_scale_norm,
                    "source_code": "",
                    "source_data_type": "",
                    "additional_info": "",
                    "icd10": "",
                    "phecode": "",
                }
            )
        return rows

    delimiter = "\t" if suffix in {".tsv", ".tab"} else ","
    with path.open("r", encoding="utf-8", newline="") as handle:
        parsed_rows = list(csv.reader(handle, delimiter=delimiter))
    if not parsed_rows:
        return []

    trait_query_column_keys = [
        normalize_trait_column_key(name)
        for name in TRAIT_QUERY_COLUMNS
        if normalize_trait_column_key(name)
    ]

    if parsed_rows and len(parsed_rows[0]) == 1 and all(len(r) <= 1 for r in parsed_rows):
        first = normalize(parsed_rows[0][0] if parsed_rows[0] else "")
        first_key = normalize_trait_column_key(first)
        start_idx = 1 if first_key in trait_query_column_keys else 0
        rows: list[dict[str, str]] = []
        for idx, row in enumerate(parsed_rows[start_idx:], start=1):
            query = normalize(row[0] if row else "")
            if not query:
                continue
            rows.append(
                {
                    "row_id": str(idx),
                    "query": query,
                    "input_type": "auto",
                    "trait_scale": default_scale_norm,
                    "source_code": "",
                    "source_data_type": "",
                    "additional_info": "",
                    "icd10": "",
                    "phecode": "",
                }
            )
        return rows

    fieldnames = parsed_rows[0]
    field_lookup = {normalize_trait_column_key(field): field for field in fieldnames}

    query_field = next((field_lookup[name] for name in trait_query_column_keys if name in field_lookup), fieldnames[0])
    icd_field = next((field_lookup[name] for name in TRAIT_ICD10_COLUMNS if name in field_lookup), None)
    phe_field = next((field_lookup[name] for name in TRAIT_PHECODE_COLUMNS if name in field_lookup), None)
    type_field = next((field_lookup[name] for name in TRAIT_INPUT_TYPE_COLUMNS if name in field_lookup), None)
    scale_field = next((field_lookup[name] for name in TRAIT_SCALE_COLUMNS if name in field_lookup), None)
    code_field = next((field_lookup[name] for name in TRAIT_CODE_COLUMNS if name in field_lookup), None)
    data_type_field = next((field_lookup[name] for name in TRAIT_DATA_TYPE_COLUMNS if name in field_lookup), None)
    additional_info_field = next(
        (field_lookup[name] for name in TRAIT_ADDITIONAL_INFO_COLUMNS if name in field_lookup),
        None,
    )

    rows: list[dict[str, str]] = []
    with path.open("r", encoding="utf-8", newline="") as handle:
        reader = csv.DictReader(handle, delimiter=delimiter)
        for idx, row in enumerate(reader, start=1):
            raw_query = strip_wrapping_quotes(normalize(row.get(query_field, "")))
            raw_icd = strip_wrapping_quotes(normalize(row.get(icd_field, ""))) if icd_field else ""
            raw_phe = strip_wrapping_quotes(normalize(row.get(phe_field, ""))) if phe_field else ""
            input_type = normalize_trait_input_type(row.get(type_field, "")) if type_field else "auto"
            trait_scale = normalize_trait_scale(row.get(scale_field, "")) if scale_field else default_scale_norm
            raw_code = strip_wrapping_quotes(normalize(row.get(code_field, ""))) if code_field else ""
            raw_data_type = normalize(row.get(data_type_field, "")) if data_type_field else ""
            raw_additional_info = normalize(row.get(additional_info_field, "")) if additional_info_field else ""
            ukb_illness_field_id, ukb_illness_code, ukb_illness_label = parse_ukb_illness_code_sr_token(raw_code)
            if norm_key(raw_query) in TRAIT_EMPTY_QUERY_VALUES and raw_additional_info:
                raw_query = derive_primary_trait_query_from_additional_info(raw_additional_info) or raw_query
            inferred_type_from_data_type = normalize_trait_data_type(raw_data_type)

            if input_type == "auto" and inferred_type_from_data_type != "auto":
                input_type = inferred_type_from_data_type
            elif input_type == "phecode" and ukb_illness_field_id:
                # Guard against mislabeled rows where `code` is actually a UKB field token.
                input_type = "ukb_field"
            parsed_query_icd10, parsed_query_icd10_label = parse_icd10_labeled_trait_text(raw_query)
            query_icd10_candidate = normalize_icd10_code(raw_query)
            query_has_icd10_mention = query_explicitly_mentions_icd10(raw_query)
            additional_info_icd10 = extract_icd10_code_from_xref(raw_additional_info) if raw_additional_info else ""
            if not additional_info_icd10 and raw_additional_info:
                additional_info_seed = derive_primary_trait_query_from_additional_info(raw_additional_info) or raw_additional_info
                parsed_info_icd10, _ = parse_icd10_labeled_trait_text(additional_info_seed)
                if parsed_info_icd10:
                    additional_info_icd10 = normalize_icd10_code(parsed_info_icd10)
            if not raw_icd and is_strict_icd10_code(additional_info_icd10):
                raw_icd = additional_info_icd10
            # Guard against rows whose metadata says phecode but whose query is
            # an explicit ICD10 code + label snippet (for example "ICD10 O13: ...").
            if (
                input_type in {"auto", "phecode", "trait_text"}
                and is_strict_icd10_code(parsed_query_icd10 or query_icd10_candidate)
                and query_has_icd10_mention
            ):
                input_type = "icd10"
                if not raw_icd:
                    raw_icd = parsed_query_icd10 or query_icd10_candidate
            if (
                inferred_type_from_data_type == "icd10"
                and input_type in {"auto", "ukb_field", "phecode", "trait_text"}
            ):
                hinted_icd10 = normalize_icd10_code(
                    raw_icd or parsed_query_icd10 or query_icd10_candidate or raw_code or additional_info_icd10
                )
                if is_strict_icd10_code(hinted_icd10):
                    input_type = "icd10"
                    raw_icd = hinted_icd10
            if ukb_illness_field_id and ukb_illness_label:
                # Decode UKB 20002-style condition token into concrete disease text.
                # This avoids broad field-title matches and preserves condition specificity.
                raw_query = ukb_illness_label
                info_bits = [raw_additional_info] if raw_additional_info else []
                info_bits.append(f"ukb_field={ukb_illness_field_id}")
                if ukb_illness_code:
                    info_bits.append(f"illness_code_sr={ukb_illness_code}")
                raw_additional_info = normalize("; ".join(bit for bit in info_bits if bit))
                if input_type in {"auto", "ukb_field", "phecode"}:
                    input_type = "trait_text"

            normalized_row_icd = normalize_icd10_code(raw_icd) if raw_icd else ""
            if input_type == "icd10":
                if is_strict_icd10_code(normalized_row_icd):
                    raw_icd = normalized_row_icd
                else:
                    raw_icd = ""
                    icd_from_code = normalize_icd10_code(raw_code)
                    if is_strict_icd10_code(icd_from_code):
                        raw_icd = icd_from_code
                    else:
                        icd_from_additional_info = normalize_icd10_code(additional_info_icd10)
                        if is_strict_icd10_code(icd_from_additional_info):
                            raw_icd = icd_from_additional_info
                        else:
                            icd_from_query = normalize_icd10_code(raw_query)
                            if query_supports_inferred_icd10(raw_query, icd_from_query):
                                raw_icd = icd_from_query
            elif normalized_row_icd:
                raw_icd = normalized_row_icd
            if input_type == "phecode" and not raw_phe:
                raw_phe = normalize_phecode(raw_code or raw_query)
            if input_type == "trait_text" and not raw_query:
                raw_query = raw_icd or raw_phe

            if not raw_query and input_type == "ukb_field":
                # Allow metadata-only UKB rows (empty query + numeric code) to route via field code.
                field_code_seed = normalize(raw_code)
                if not field_code_seed:
                    embedded_code_ids = extract_ukb_field_ids(raw_code)
                    if embedded_code_ids:
                        field_code_seed = normalize(embedded_code_ids[0])
                if field_code_seed and re.fullmatch(r"[0-9]{1,7}", field_code_seed):
                    raw_query = f"UKB data field {field_code_seed}"

            if not raw_query and not raw_icd and not raw_phe:
                continue

            if input_type == "auto":
                normalized_icd10 = normalize_icd10_code(raw_icd or parsed_query_icd10 or raw_query)
                if query_supports_inferred_icd10(raw_query, normalized_icd10):
                    input_type = "icd10"
                    if not raw_icd:
                        raw_icd = normalized_icd10
                elif extract_ukb_field_ids(raw_query):
                    input_type = "ukb_field"
                elif looks_like_phecode_token(raw_phe or raw_query):
                    input_type = "phecode"
                    if not raw_phe:
                        raw_phe = normalize_phecode(raw_query)
                else:
                    input_type = "trait_text"

            if input_type == "ukb_field":
                field_code = normalize(raw_code)
                if not field_code:
                    embedded_field_ids = extract_ukb_field_ids(raw_code)
                    if embedded_field_ids:
                        field_code = normalize(embedded_field_ids[0])
                if not field_code:
                    code_match = re.match(r"^\s*([0-9]{1,7})\b", raw_query)
                    field_code = normalize(code_match.group(1)) if code_match else ""
                if field_code and re.fullmatch(r"[0-9]{1,7}", field_code):
                    ukb_token = f"ukb data field {field_code}"
                    if raw_query:
                        if ukb_token not in norm_key(raw_query):
                            raw_query = normalize(f"{raw_query} (UKB data field {field_code})")
                    else:
                        raw_query = normalize(f"UKB data field {field_code}")

            rows.append(
                {
                    "row_id": str(idx),
                    "query": raw_query,
                    "input_type": input_type,
                    "trait_scale": trait_scale,
                    "source_code": raw_code,
                    "source_data_type": raw_data_type,
                    "additional_info": raw_additional_info,
                    "icd10": raw_icd,
                    "phecode": raw_phe,
                }
            )
    return rows


def is_ukb_field_supplement_publication(value: str) -> bool:
    return normalize(value).lower().startswith(normalize(UKB_FIELD_SUPPLEMENT_PUBLICATION).lower())


def is_icd10_supplement_publication(value: str) -> bool:
    return normalize(value).lower().startswith(normalize(ICD10_SUPPLEMENT_PUBLICATION).lower())


def load_trait_cache_index(path: Path, extra_paths: list[Path] | None = None) -> dict[str, Any]:
    if not path.exists():
        raise FileNotFoundError(f"Trait cache not found: {path}")

    cache_paths: list[Path] = [path]
    for extra in extra_paths or []:
        if extra in cache_paths:
            continue
        if extra.exists():
            cache_paths.append(extra)

    records: list[TraitCacheRecord] = []
    icd10_index: dict[str, list[int]] = {}
    icd10_label_index: dict[str, set[str]] = {}
    phecode_index: dict[str, list[int]] = {}
    ukb_field_index: dict[str, list[int]] = {}
    text_exact_index: dict[str, list[int]] = {}
    token_index: dict[str, set[int]] = {}
    token_freq: Counter[str] = Counter()
    rownum = 0
    skipped_known_bad_cache_rows = 0
    missing_cache_markers = {"-", "NA", "N/A", "NONE", "NULL", "NAN"}

    for cache_path in cache_paths:
        with cache_path.open("r", encoding="utf-8", newline="") as handle:
            reader = csv.DictReader(handle, delimiter="\t")
            for row in reader:
                rownum += 1
                reported_trait = normalize(row.get("Curated reported trait") or row.get("DISEASE/TRAIT") or "")
                lookup_text = normalize(row.get("Lookup text") or row.get("DISEASE/TRAIT") or reported_trait)
                raw_icd10 = normalize(row.get("ICD10") or "")
                if raw_icd10.upper() in missing_cache_markers:
                    raw_icd10 = ""
                icd10 = normalize_icd10_code(raw_icd10)
                # Some cache sources store ICD10 only inside the reported trait
                # text (for example "ICD10 G40.3: ...") and leave the ICD10
                # column empty. Index those rows as ICD10 too so exact ICD10
                # routing can reuse high-confidence catalog/cache mappings.
                if not icd10:
                    for text_value in (reported_trait, lookup_text):
                        parsed_code, _parsed_label = parse_icd10_labeled_trait_text(text_value)
                        parsed_code = normalize_icd10_code(parsed_code)
                        if is_strict_icd10_code(parsed_code):
                            icd10 = parsed_code
                            break
                phecode = normalize_phecode(row.get("PheCode") or "")
                publication = normalize(row.get("Publication") or "")
                is_ukb_field_supplement = is_ukb_field_supplement_publication(publication)
                is_icd10_supplement = is_icd10_supplement_publication(publication)

                raw_ids = split_multi_ids(row.get("main ontology URI(s)") or row.get("MAPPED_TRAIT_URI") or "")
                if not raw_ids:
                    continue
                canon_ids: list[str] = []
                for item in raw_ids:
                    oid = canonicalize_trait_ontology_id(item)
                    if not oid:
                        continue
                    if oid not in canon_ids:
                        canon_ids.append(oid)
                if not canon_ids:
                    continue

                raw_labels = split_multi_labels(
                    row.get("main ontology label(s)") or row.get("MAPPED_TRAIT") or "",
                    expected_n=len(canon_ids),
                )
                labels: list[str] = []
                for idx, oid in enumerate(canon_ids):
                    mapped_label = raw_labels[idx] if idx < len(raw_labels) else ""
                    labels.append(normalize(mapped_label))

                ukb_ids: set[str] = set()
                # Use explicit UKB data-field markers from trait text only.
                ukb_ids |= set(extract_explicit_ukb_field_ids(reported_trait))
                ukb_ids |= set(extract_explicit_ukb_field_ids(lookup_text))
                explicit_ukb_field = normalize(row.get("UKBB data field") or row.get("UKB data field") or "")
                if explicit_ukb_field and explicit_ukb_field not in {"-", "NA", "N/A"}:
                    if re.fullmatch(r"\d{1,7}", explicit_ukb_field):
                        ukb_ids.add(explicit_ukb_field)
                    else:
                        ukb_ids |= set(extract_explicit_ukb_field_ids(explicit_ukb_field))

                # Historical cache import artifact: several "Degree bothered by ..."
                # UKB fields (21048-21061) were mapped to health satisfaction,
                # which is semantically wrong for symptom-burden rows.
                if (
                    len(canon_ids) == 1
                    and canon_ids[0] == "EFO_0009724"
                    and norm_key(labels[0]) == "health satisfaction measurement"
                    and any(field_id in KNOWN_BAD_HEALTH_SATISFACTION_DEGREE_BOTHERED_FIELDS for field_id in ukb_ids)
                ):
                    text_scope = norm_key(" ".join(part for part in (reported_trait, lookup_text) if part))
                    if "degree bothered by" in text_scope:
                        skipped_known_bad_cache_rows += 1
                        continue

                record = TraitCacheRecord(
                    rownum=rownum,
                    reported_trait=reported_trait,
                    lookup_text=lookup_text,
                    icd10=icd10,
                    phecode=phecode,
                    mapped_ids=tuple(canon_ids),
                    mapped_labels=tuple(labels),
                    publication=publication,
                    is_ukb_field_supplement=is_ukb_field_supplement,
                    is_icd10_supplement=is_icd10_supplement,
                )
                rec_idx = len(records)
                records.append(record)

                if not is_ukb_field_supplement:
                    if icd10:
                        icd10_index.setdefault(icd10, []).append(rec_idx)
                        label_hints: set[str] = set()
                        for text_value in (reported_trait, lookup_text):
                            parsed_code, parsed_label = parse_icd10_labeled_trait_text(text_value)
                            if parsed_code == icd10 and parsed_label:
                                label_hints.add(parsed_label)
                        if lookup_text and lookup_text != icd10:
                            label_hints.add(lookup_text)
                        for label_hint in label_hints:
                            if label_hint:
                                icd10_label_index.setdefault(icd10, set()).add(label_hint)
                    if phecode:
                        phecode_index.setdefault(phecode, []).append(rec_idx)

                for ukb_field_id in ukb_ids:
                    ukb_field_index.setdefault(ukb_field_id, []).append(rec_idx)

                if not is_ukb_field_supplement and not is_icd10_supplement:
                    for text_value in {reported_trait, lookup_text}:
                        text_norm_variants = trait_cache_exact_norm_variants(text_value)
                        if not text_norm_variants:
                            continue
                        for text_norm in text_norm_variants:
                            text_exact_index.setdefault(text_norm, []).append(rec_idx)
                        for tok in informative_trait_tokens(text_norm_variants[0]):
                            token_index.setdefault(tok, set()).add(rec_idx)
                            token_freq[tok] += 1

    if skipped_known_bad_cache_rows:
        print(
            "[OK] trait cache hygiene: "
            f"skipped {skipped_known_bad_cache_rows} known bad "
            "degree-bothered health-satisfaction rows"
        )

    return {
        "records": records,
        "icd10_index": icd10_index,
        "icd10_label_index": {k: tuple(sorted(v)) for k, v in icd10_label_index.items()},
        "phecode_index": phecode_index,
        "ukb_field_index": ukb_field_index,
        "text_exact_index": text_exact_index,
        "token_index": token_index,
        "token_freq": token_freq,
    }


def load_trait_ontology_index(obo_path: Path) -> dict[str, Any]:
    if not obo_path.exists():
        raise FileNotFoundError(f"EFO OBO not found: {obo_path}")

    terms: dict[str, TraitOntologyTerm] = {}
    obsolete_terms: dict[str, TraitObsoleteTerm] = {}
    exact_index: dict[str, set[str]] = {}
    token_index: dict[str, set[str]] = {}
    token_freq: Counter[str] = Counter()
    icd10_xref_index: dict[str, set[str]] = {}
    xref_label_hints: dict[str, str] = {}
    term_parents: dict[str, tuple[str, ...]] = {}

    current_id = ""
    current_label = ""
    current_synonyms: list[tuple[str, str]] = []
    current_obsolete = False
    current_replaced_by: list[str] = []
    current_consider: list[str] = []
    current_icd10_xrefs: set[str] = set()
    current_preferred_xrefs: set[str] = set()
    current_parents: list[str] = []
    in_term = False

    def flush_term() -> None:
        nonlocal current_id, current_label, current_synonyms, current_obsolete
        nonlocal current_replaced_by, current_consider
        nonlocal current_icd10_xrefs
        nonlocal current_preferred_xrefs
        nonlocal current_parents

        if not current_id:
            current_id = ""
            current_label = ""
            current_synonyms = []
            current_obsolete = False
            current_replaced_by = []
            current_consider = []
            current_icd10_xrefs = set()
            current_preferred_xrefs = set()
            current_parents = []
            return

        prefix = trait_ontology_prefix(current_id)
        prefix_allowed = prefix in TRAIT_PREFERRED_PREFIX_ORDER

        if current_obsolete:
            if prefix_allowed:
                replaced_by: list[str] = []
                for item in current_replaced_by:
                    oid = canonicalize_trait_ontology_id(item)
                    if not oid:
                        continue
                    if trait_ontology_prefix(oid) not in TRAIT_PREFERRED_PREFIX_ORDER:
                        continue
                    if oid not in replaced_by:
                        replaced_by.append(oid)

                consider: list[str] = []
                for item in current_consider:
                    oid = canonicalize_trait_ontology_id(item)
                    if not oid:
                        continue
                    if trait_ontology_prefix(oid) not in TRAIT_PREFERRED_PREFIX_ORDER:
                        continue
                    if oid not in consider:
                        consider.append(oid)

                obsolete_terms[current_id] = TraitObsoleteTerm(
                    term_id=current_id,
                    label=normalize(current_label),
                    replaced_by=tuple(replaced_by),
                    consider=tuple(consider),
                )
            current_id = ""
            current_label = ""
            current_synonyms = []
            current_obsolete = False
            current_replaced_by = []
            current_consider = []
            current_icd10_xrefs = set()
            current_preferred_xrefs = set()
            current_parents = []
            return

        if not current_label:
            current_id = ""
            current_label = ""
            current_synonyms = []
            current_obsolete = False
            current_replaced_by = []
            current_consider = []
            current_icd10_xrefs = set()
            current_preferred_xrefs = set()
            current_parents = []
            return

        if prefix_allowed:
            normalized_label = normalize(current_label)
            label_key = norm_key(normalized_label)
            synonym_values: list[str] = []
            seen_synonym_values: set[str] = set()
            exact_synonym_keys: set[str] = set()
            narrow_synonym_keys: set[str] = set()
            related_synonym_keys: set[str] = set()
            broad_synonym_keys: set[str] = set()
            for raw_synonym, raw_scope in current_synonyms:
                syn_value = normalize(raw_synonym)
                if not syn_value:
                    continue
                if syn_value not in seen_synonym_values:
                    seen_synonym_values.add(syn_value)
                    synonym_values.append(syn_value)
                syn_key = norm_key(syn_value)
                if not syn_key:
                    continue
                if raw_scope == "EXACT":
                    exact_synonym_keys.add(syn_key)
                elif raw_scope == "NARROW":
                    narrow_synonym_keys.add(syn_key)
                elif raw_scope == "RELATED":
                    related_synonym_keys.add(syn_key)
                elif raw_scope == "BROAD":
                    broad_synonym_keys.add(syn_key)
            term = TraitOntologyTerm(
                term_id=current_id,
                label=normalized_label,
                synonyms=tuple(synonym_values),
                label_key=label_key,
                exact_synonym_keys=frozenset(exact_synonym_keys),
                narrow_synonym_keys=frozenset(narrow_synonym_keys),
                related_synonym_keys=frozenset(related_synonym_keys),
                broad_synonym_keys=frozenset(broad_synonym_keys),
            )
            terms[current_id] = term
            parents: list[str] = []
            for raw_parent in current_parents:
                parent_id = canonicalize_trait_ontology_id(raw_parent)
                if not parent_id:
                    continue
                if parent_id not in parents:
                    parents.append(parent_id)
            term_parents[current_id] = tuple(parents)

            phrases = {term.label, *term.synonyms}
            for phrase in phrases:
                phrase_keys = {
                    norm_key(phrase),
                    normalize_trait_semantic_text(phrase),
                }
                for key in phrase_keys:
                    if not key:
                        continue
                    exact_index.setdefault(key, set()).add(current_id)
                    for tok in informative_trait_tokens(key):
                        token_index.setdefault(tok, set()).add(current_id)
                        token_freq[tok] += 1

        icd10_targets = set(current_preferred_xrefs)
        if prefix_allowed:
            icd10_targets.add(current_id)
        if icd10_targets:
            for code in sorted(current_icd10_xrefs):
                icd10_xref_index.setdefault(code, set()).update(icd10_targets)
        if current_label:
            normalized_label = normalize(current_label)
            for xref_id in current_preferred_xrefs:
                if xref_id not in terms and normalized_label:
                    xref_label_hints.setdefault(xref_id, normalized_label)

        current_id = ""
        current_label = ""
        current_synonyms = []
        current_obsolete = False
        current_replaced_by = []
        current_consider = []
        current_icd10_xrefs = set()
        current_preferred_xrefs = set()
        current_parents = []

    with obo_path.open("r", encoding="utf-8", errors="ignore") as handle:
        for raw_line in handle:
            line = raw_line.rstrip("\n")
            if line == "[Term]":
                flush_term()
                in_term = True
                continue
            if line.startswith("[") and line != "[Term]":
                flush_term()
                in_term = False
                continue
            if not in_term:
                continue
            if line.startswith("id: "):
                current_id = canonicalize_trait_ontology_id(line[4:])
            elif line.startswith("name: "):
                current_label = line[6:].strip()
            elif line.startswith("synonym: "):
                match = re.match(r'^synonym:\s+"(.+?)"\s+(EXACT|BROAD|NARROW|RELATED)\b', line)
                if match:
                    current_synonyms.append((match.group(1).strip(), match.group(2).upper()))
            elif line.startswith("replaced_by: "):
                current_replaced_by.append(line.split(":", 1)[1].strip())
            elif line.startswith("consider: "):
                current_consider.append(line.split(":", 1)[1].strip())
            elif line.startswith("is_obsolete: "):
                current_obsolete = line.split(":", 1)[1].strip().lower() == "true"
            elif line.startswith("xref: "):
                xref_text = line[6:].strip()
                xref_token = xref_text.split()[0]
                xref_id = canonicalize_trait_ontology_id(xref_token)
                if trait_ontology_prefix(xref_id) in TRAIT_PREFERRED_PREFIX_ORDER:
                    current_preferred_xrefs.add(xref_id)
                icd10_code = extract_icd10_code_from_xref(xref_text)
                if icd10_code:
                    current_icd10_xrefs.add(icd10_code)
            elif line.startswith("property_value: "):
                property_text = line
                mondo_id = extract_mondo_id(property_text)
                if mondo_id and trait_ontology_prefix(mondo_id) in TRAIT_PREFERRED_PREFIX_ORDER:
                    current_preferred_xrefs.add(mondo_id)
                icd10_code = extract_icd10_code_from_xref(property_text)
                if icd10_code:
                    current_icd10_xrefs.add(icd10_code)
            elif line.startswith("is_a: "):
                parent_part = line[6:].split("!", 1)[0].strip()
                if parent_part:
                    current_parents.append(parent_part)

    flush_term()
    for term_id, label in xref_label_hints.items():
        if term_id in terms or not label:
            continue
        # Do not re-materialize obsolete cross-reference IDs as active terms.
        # These should resolve via replaced_by/consider pathways elsewhere.
        if term_id in obsolete_terms:
            continue
        terms[term_id] = TraitOntologyTerm(
            term_id=term_id,
            label=label,
            synonyms=(),
            label_key=norm_key(label),
        )

    measurement_root = canonicalize_trait_ontology_id(DEFAULT_MEASUREMENT_ROOT)
    measurement_cache: dict[str, bool] = {}
    visiting: set[str] = set()

    def is_measurement_descendant(term_id: str) -> bool:
        if term_id == measurement_root:
            return True
        if term_id in measurement_cache:
            return measurement_cache[term_id]
        if term_id in visiting:
            return False
        visiting.add(term_id)
        parents = term_parents.get(term_id, ())
        result = any(is_measurement_descendant(parent_id) for parent_id in parents)
        visiting.remove(term_id)
        measurement_cache[term_id] = result
        return result

    measurement_term_ids = {
        term_id
        for term_id in terms
        if is_measurement_descendant(term_id)
    }
    return {
        "terms": terms,
        "obsolete_terms": obsolete_terms,
        "exact_index": exact_index,
        "token_index": token_index,
        "token_freq": token_freq,
        "icd10_xref_index": icd10_xref_index,
        "term_parents": term_parents,
        "measurement_term_ids": measurement_term_ids,
    }


def build_trait_cache_term_resolution(
    trait_cache_index: dict[str, Any],
    ontology_index: dict[str, Any],
    *,
    issue_sample_limit: int = 8,
) -> tuple[dict[int, tuple[tuple[str, ...], tuple[str, ...]]], dict[str, int], list[str]]:
    records: list[TraitCacheRecord] = trait_cache_index.get("records", [])
    ontology_terms: dict[str, TraitOntologyTerm] = ontology_index.get("terms", {})
    obsolete_terms: dict[str, TraitObsoleteTerm] = ontology_index.get("obsolete_terms", {})

    resolution: dict[int, tuple[tuple[str, ...], tuple[str, ...]]] = {}
    stats: dict[str, int] = {
        "records_total": len(records),
        "rows_with_obsolete_ids": 0,
        "rows_with_unresolved_ids": 0,
        "rows_without_active_terms": 0,
        "ids_total": 0,
        "ids_active": 0,
        "ids_obsolete": 0,
        "ids_obsolete_replaced_by": 0,
        "ids_obsolete_consider_single": 0,
        "ids_obsolete_unresolved": 0,
        "ids_unknown": 0,
    }
    issues: list[str] = []

    for rec in records:
        resolved_ids: list[str] = []
        unresolved_mondo_ids: list[str] = []
        row_has_obsolete = False
        row_has_unresolved = False

        for raw_id in rec.mapped_ids:
            oid = canonicalize_trait_ontology_id(raw_id)
            if not oid:
                continue
            stats["ids_total"] += 1
            if oid in ontology_terms:
                stats["ids_active"] += 1
                if oid not in resolved_ids:
                    resolved_ids.append(oid)
                continue

            obsolete_meta = obsolete_terms.get(oid)
            if obsolete_meta is not None:
                row_has_obsolete = True
                stats["ids_obsolete"] += 1

                replacements = [rid for rid in obsolete_meta.replaced_by if rid in ontology_terms]
                if replacements:
                    stats["ids_obsolete_replaced_by"] += 1
                    for rid in replacements:
                        if rid not in resolved_ids:
                            resolved_ids.append(rid)
                    continue

                consider = [cid for cid in obsolete_meta.consider if cid in ontology_terms]
                if len(consider) == 1:
                    stats["ids_obsolete_consider_single"] += 1
                    cid = consider[0]
                    if cid not in resolved_ids:
                        resolved_ids.append(cid)
                    continue

                stats["ids_obsolete_unresolved"] += 1
                row_has_unresolved = True
                if len(issues) < issue_sample_limit:
                    issues.append(
                        f"row {rec.rownum}: unresolved obsolete id {oid} "
                        f"for '{rec.reported_trait or rec.lookup_text}'"
                    )
                continue

            stats["ids_unknown"] += 1
            row_has_unresolved = True
            if trait_ontology_prefix(oid) == "MONDO":
                unresolved_mondo_ids.append(oid)
            if len(issues) < issue_sample_limit:
                issues.append(
                    f"row {rec.rownum}: id {oid} not found in ontology "
                    f"for '{rec.reported_trait or rec.lookup_text}'"
                )

        if row_has_obsolete:
            stats["rows_with_obsolete_ids"] += 1
        if row_has_unresolved:
            stats["rows_with_unresolved_ids"] += 1

        if not resolved_ids:
            # Keep unresolved MONDO-only rows as explicit review-required
            # candidates so output can carry `term not in EFO` QC flags.
            if unresolved_mondo_ids:
                fallback_labels: list[str] = []
                for unresolved_id in unresolved_mondo_ids:
                    fallback_label = ""
                    for idx, mapped_id in enumerate(rec.mapped_ids):
                        if canonicalize_trait_ontology_id(mapped_id) == unresolved_id:
                            if idx < len(rec.mapped_labels):
                                fallback_label = normalize(rec.mapped_labels[idx])
                            break
                    fallback_labels.append(fallback_label or unresolved_id)
                resolution[rec.rownum] = (tuple(unresolved_mondo_ids), tuple(fallback_labels))
                continue
            stats["rows_without_active_terms"] += 1
            continue

        resolved_labels = tuple(ontology_terms[oid].label for oid in resolved_ids)
        resolution[rec.rownum] = (tuple(resolved_ids), resolved_labels)

    return resolution, stats, issues


def pick_seed_tokens(tokens: set[str], token_freq: Counter[str], max_tokens: int = 6) -> list[str]:
    if not tokens:
        return []
    items = list(tokens)
    items.sort(key=lambda tok: (token_freq.get(tok, 10**9), len(tok), tok))
    return items[:max_tokens]


@lru_cache(maxsize=300_000)
def _trait_similarity_candidate_profile(candidate_text: str) -> tuple[str, frozenset[str]]:
    cnorm = normalize_trait_text_for_similarity(candidate_text)
    if not cnorm:
        return "", frozenset()
    return cnorm, frozenset(informative_trait_tokens(cnorm))


@lru_cache(maxsize=1_000_000)
def _sequence_ratio(a: str, b: str) -> float:
    return difflib.SequenceMatcher(None, a, b).ratio()


def trait_similarity_score(query: str, query_toks: set[str], candidate_text: str) -> float:
    qnorm = normalize_trait_text_for_similarity(query)
    cnorm, c_toks_frozen = _trait_similarity_candidate_profile(candidate_text)
    if not qnorm or not cnorm:
        return 0.0
    negation_mismatch = trait_negation_mismatch(qnorm, cnorm)
    c_toks = set(c_toks_frozen)
    overlap_tokens = query_toks & c_toks
    overlap = len(overlap_tokens) / max(len(query_toks), 1)
    nonweak_overlap_tokens = trait_nonweak_tokens(overlap_tokens)
    query_anchor_tokens = trait_anchor_tokens(query_toks)
    candidate_anchor_tokens = trait_anchor_tokens(c_toks)
    seq = _sequence_ratio(qnorm, cnorm)
    substring_bonus = 0.1 if len(cnorm) >= 6 and (cnorm in qnorm or qnorm in cnorm) else 0.0
    strict_modifier_mismatches = sum(
        1 for tok in TRAIT_STRICT_MODIFIER_TOKENS if ((tok in query_toks) != (tok in c_toks))
    )
    modifier_penalty = 0.25 * strict_modifier_mismatches
    negation_penalty = 0.12 if negation_mismatch else 0.0
    weak_overlap_penalty = 0.18 if overlap_tokens and not nonweak_overlap_tokens else 0.0
    anchor_penalty = 0.20 if query_anchor_tokens and query_anchor_tokens.isdisjoint(candidate_anchor_tokens) else 0.0
    raw_score = (
        0.6 * overlap
        + 0.4 * seq
        + substring_bonus
        - modifier_penalty
        - negation_penalty
        - weak_overlap_penalty
        - anchor_penalty
    )
    return max(0.0, min(1.0, raw_score))


def trait_modifier_label_mismatch(query_toks: set[str], candidate_label: str) -> bool:
    if not query_toks or not candidate_label:
        return False
    label_norm = normalize_trait_text_for_similarity(candidate_label)
    if not label_norm:
        return False
    label_toks = informative_trait_tokens(label_norm)
    return any((tok in query_toks) != (tok in label_toks) for tok in TRAIT_STRICT_MODIFIER_TOKENS)


def trait_match_scope_rank(
    *,
    query_exact_keys: set[str],
    term: TraitOntologyTerm | None,
    label_text: str,
) -> int:
    if not query_exact_keys:
        return -1
    label_key = norm_key(label_text)
    if label_key and label_key in query_exact_keys:
        return TRAIT_SYNONYM_SCOPE_RANK["LABEL"]
    if term is None:
        return -1
    if query_exact_keys & term.exact_synonym_keys:
        return TRAIT_SYNONYM_SCOPE_RANK["EXACT"]
    if query_exact_keys & term.narrow_synonym_keys:
        return TRAIT_SYNONYM_SCOPE_RANK["NARROW"]
    if query_exact_keys & term.related_synonym_keys:
        return TRAIT_SYNONYM_SCOPE_RANK["RELATED"]
    if query_exact_keys & term.broad_synonym_keys:
        return TRAIT_SYNONYM_SCOPE_RANK["BROAD"]
    return -1


def trait_overspecificity_penalties(
    *,
    query_tokens: set[str],
    label_text: str,
) -> tuple[int, int, int]:
    if not label_text:
        return 0, 0, 0
    label_norm = normalize_trait_text_for_similarity(label_text) or norm_key(label_text)
    label_tokens = informative_trait_tokens(label_norm)
    if not label_tokens:
        return 0, 0, 0
    extra_tokens = label_tokens - query_tokens
    subtype_penalty = len(extra_tokens & TRAIT_OVERSPECIFICITY_HINT_TOKENS)
    extra_penalty = len([tok for tok in extra_tokens if tok not in TRAIT_STOP_TOKENS and len(tok) >= 4])
    overlap = len(label_tokens & query_tokens)
    return subtype_penalty, extra_penalty, overlap


def trait_candidate_lexical_priority(
    candidate: Candidate,
    *,
    query_exact_keys: set[str],
    query_tokens: set[str],
    ontology_terms: dict[str, TraitOntologyTerm],
) -> tuple[int, int, int, int]:
    ids = [canonicalize_trait_ontology_id(item) for item in split_multi_ids(candidate.efo_id)]
    ids = [item for item in ids if item]
    labels = split_multi_labels(candidate.label, expected_n=len(ids))
    if not ids:
        scope_rank = trait_match_scope_rank(
            query_exact_keys=query_exact_keys,
            term=None,
            label_text=normalize(candidate.label),
        )
        subtype_penalty, extra_penalty, overlap = trait_overspecificity_penalties(
            query_tokens=query_tokens,
            label_text=normalize(candidate.label),
        )
        return scope_rank, -subtype_penalty, -extra_penalty, overlap

    best_rank = -1
    best_subtype_penalty = 10**6
    best_extra_penalty = 10**6
    best_overlap = -1
    for idx, term_id in enumerate(ids):
        term = ontology_terms.get(term_id)
        label_text = normalize(labels[idx] if idx < len(labels) else "")
        if not label_text and term is not None:
            label_text = term.label
        scope_rank = trait_match_scope_rank(
            query_exact_keys=query_exact_keys,
            term=term,
            label_text=label_text,
        )
        subtype_penalty, extra_penalty, overlap = trait_overspecificity_penalties(
            query_tokens=query_tokens,
            label_text=label_text,
        )
        rank_tuple = (scope_rank, -subtype_penalty, -extra_penalty, overlap)
        best_tuple = (best_rank, -best_subtype_penalty, -best_extra_penalty, best_overlap)
        if rank_tuple > best_tuple:
            best_rank = scope_rank
            best_subtype_penalty = subtype_penalty
            best_extra_penalty = extra_penalty
            best_overlap = overlap
    return best_rank, -best_subtype_penalty, -best_extra_penalty, best_overlap


def candidate_is_non_disease_entity(
    candidate: Candidate,
    *,
    ontology_terms: dict[str, TraitOntologyTerm],
) -> bool:
    ids = [canonicalize_trait_ontology_id(item) for item in split_multi_ids(candidate.efo_id)]
    ids = [item for item in ids if item]
    if not ids:
        return False
    prefixes = {trait_ontology_prefix(item) for item in ids if item}
    if not prefixes or not prefixes.issubset(TRAIT_NON_DISEASE_ENTITY_PREFIXES):
        return False
    if has_disease_hint(candidate.label):
        return False
    for term_id in ids:
        term = ontology_terms.get(term_id)
        if term is not None and has_disease_hint(term.label):
            return False
    return True


def candidate_is_anatomy_or_substance_entity(candidate: Candidate) -> bool:
    ids = [canonicalize_trait_ontology_id(item) for item in split_multi_ids(candidate.efo_id)]
    ids = [item for item in ids if item]
    if not ids:
        return False
    prefixes = {trait_ontology_prefix(item) for item in ids if item}
    return bool(prefixes) and prefixes.issubset({"UBERON", "CL", "PR", "CHEBI"})


def candidate_descends_from_term(
    candidate: Candidate,
    ancestor_term_id: str,
    *,
    term_parents: dict[str, tuple[str, ...]],
) -> bool:
    ancestor = canonicalize_trait_ontology_id(ancestor_term_id)
    if not ancestor:
        return False
    for item in split_multi_ids(candidate.efo_id):
        term_id = canonicalize_trait_ontology_id(item)
        if not term_id or term_id == ancestor:
            continue
        if ancestor in trait_ancestor_ids(term_id, term_parents=term_parents):
            return True
    return False


TRAIT_LATERALITY_ONLY_KEYS = {
    "left",
    "right",
    "bilateral",
    "unilateral",
}

TRAIT_DESCRIPTOR_ONLY_KEYS = {
    "light",
    "dark",
    "blonde",
    "blond",
    "brown",
    "black",
    "red",
    "blue",
    "green",
    "grey",
    "gray",
    "other",
}


def candidate_is_laterality_only_entity(candidate: Candidate) -> bool:
    return norm_key(candidate.label) in TRAIT_LATERALITY_ONLY_KEYS


def candidate_is_descriptor_only_entity(candidate: Candidate) -> bool:
    return norm_key(candidate.label) in TRAIT_DESCRIPTOR_ONLY_KEYS


def trait_text_has_pediatric_context(text: str) -> bool:
    key = normalize_trait_text_for_similarity(text) or norm_key(text)
    if not key:
        return False
    return bool(set(tokenize(key)) & TRAIT_PEDIATRIC_CONTEXT_TOKENS)


def trait_query_has_pediatric_context(query_text: str) -> bool:
    return trait_text_has_pediatric_context(query_text)


def candidate_has_pediatric_component(
    candidate: Candidate,
    *,
    ontology_terms: dict[str, TraitOntologyTerm] | None = None,
) -> bool:
    ids = [canonicalize_trait_ontology_id(item) for item in split_multi_ids(candidate.efo_id)]
    ids = [item for item in ids if item]
    if ids:
        labels = split_multi_labels(candidate.label, expected_n=len(ids))
        for idx, term_id in enumerate(ids):
            label_text = normalize(labels[idx] if idx < len(labels) else "")
            if not label_text and ontology_terms is not None:
                term = ontology_terms.get(term_id)
                if term is not None:
                    label_text = normalize(term.label)
            if trait_text_has_pediatric_context(label_text):
                return True
        return False
    return trait_text_has_pediatric_context(candidate.label)


NONHUMAN_ANIMAL_HINT_TOKENS = {
    "animal",
    "bovine",
    "equine",
    "canine",
    "feline",
    "murine",
    "porcine",
    "swine",
    "avian",
    "fish",
    "invertebrate",
    "vertebrate",
}


def candidate_is_nonhuman_animal_specific(
    candidate: Candidate,
    *,
    ontology_terms: dict[str, TraitOntologyTerm],
) -> bool:
    haystacks = [normalize(candidate.label)]
    for term_id in split_multi_ids(candidate.efo_id):
        term = ontology_terms.get(canonicalize_trait_ontology_id(term_id))
        if term is not None:
            haystacks.append(term.label)
            haystacks.extend(term.synonyms[:10])
    for text in haystacks:
        toks = set(tokenize(norm_key(text)))
        if toks & NONHUMAN_ANIMAL_HINT_TOKENS:
            return True
    return False


def trait_cache_record_phrase_text(record: TraitCacheRecord) -> str:
    for raw_text in (record.reported_trait, record.lookup_text):
        parsed_code, parsed_label = parse_icd10_labeled_trait_text(raw_text)
        if parsed_label:
            return parsed_label
        cleaned = normalize(
            re.sub(
                rf"^\s*ICD\s*-?\s*10\s+{ICD10_CODE_HEAD_RE}(?:\.[0-9A-Z]{{1,4}})?\s*:?\s*",
                "",
                normalize(raw_text),
                flags=re.IGNORECASE,
            )
        )
        if cleaned and not is_strict_icd10_code(normalize_icd10_code(cleaned)):
            return cleaned
    return ""


def derive_icd10_query_phrase_hint(query: str, icd10: str, additional_info: str) -> str:
    parsed_code, parsed_label = parse_icd10_labeled_trait_text(query)
    if parsed_label and (not icd10 or parsed_code == icd10):
        phrase_seed = parsed_label
    else:
        phrase_seed = normalize(
            re.sub(
                r"/ICD10\s+[A-Z][0-9][0-9A-Z.]*\s*$",
                "",
                normalize(query),
                flags=re.IGNORECASE,
            )
        )
        if not phrase_seed:
            phrase_seed = derive_primary_trait_query_from_additional_info(additional_info)
    fragment = extract_professional_diagnosis_trait_fragment(phrase_seed, additional_info)
    phrase = normalize(fragment or phrase_seed)
    phrase = normalize(re.sub(r"\(\s*ukb\s+data\s+field\s*\d+\s*\)", "", phrase, flags=re.IGNORECASE))
    phrase = normalize(re.sub(r"\(\s*\d+\s*\)$", "", phrase))
    if not phrase:
        return ""
    if not re.search(r"[a-z]", phrase.lower()):
        return ""
    if is_strict_icd10_code(normalize_icd10_code(phrase)):
        return ""
    if norm_key(phrase) in TRAIT_EMPTY_QUERY_VALUES:
        return ""
    return phrase


def filter_icd10_cache_records_by_query_phrase(
    records: list[TraitCacheRecord],
    query_phrase: str,
) -> list[TraitCacheRecord]:
    phrase_key = normalize_trait_text_for_similarity(query_phrase) or norm_key(query_phrase)
    phrase_tokens = informative_trait_tokens(phrase_key)
    if not phrase_tokens:
        return records

    scored: list[tuple[int, float, int, TraitCacheRecord]] = []
    for record in records:
        record_phrase = trait_cache_record_phrase_text(record)
        record_key = normalize_trait_text_for_similarity(record_phrase) or norm_key(record_phrase)
        record_tokens = informative_trait_tokens(record_key)
        if not record_tokens:
            scored.append((0, 0.0, 0, record))
            continue
        overlap = len(phrase_tokens & record_tokens)
        coverage = overlap / max(1, len(phrase_tokens))
        precision = overlap / max(1, len(record_tokens))
        score = coverage + 0.25 * precision
        exact = 1 if record_key == phrase_key else 0
        scored.append((exact, score, overlap, record))

    if not scored:
        return records

    scored.sort(
        key=lambda item: (
            item[0],
            item[1],
            item[2],
            -item[3].rownum,
        ),
        reverse=True,
    )
    best_exact, best_score, best_overlap, _ = scored[0]
    if best_overlap <= 0:
        return records

    winners = [
        record
        for exact, score, overlap, record in scored
        if exact == best_exact and overlap == best_overlap and abs(score - best_score) < 1e-9
    ]
    if not winners or len(winners) == len(records):
        return records
    return winners


def collapse_trait_cache_candidates(
    records: list[TraitCacheRecord],
    *,
    method: str,
    score: float,
    matched_on: str,
    validated_if_unique: bool,
    record_resolver: Any | None = None,
) -> list[Candidate]:
    grouped: dict[tuple[str, str], list[TraitCacheRecord]] = {}
    for record in records:
        if record_resolver is not None:
            resolved = record_resolver(record)
            if not resolved:
                continue
            resolved_ids, resolved_labels = resolved
            mapped_ids = "|".join(resolved_ids)
            mapped_labels = "|".join(resolved_labels)
        else:
            mapped_ids = "|".join(record.mapped_ids)
            mapped_labels = "|".join(record.mapped_labels)
        grouped.setdefault((mapped_ids, mapped_labels), []).append(record)

    unique_count = len(grouped)
    if unique_count == 0:
        return []
    candidates: list[Candidate] = []
    for (mapped_ids, mapped_labels), rows in grouped.items():
        source_rows = ",".join(str(row.rownum) for row in rows[:10])
        publication_set = sorted({row.publication for row in rows if row.publication})
        publication_hint = "|".join(publication_set[:3])
        evidence = f"{matched_on} cache rows={source_rows}"
        if publication_hint:
            evidence += f"; publications={publication_hint}"
        if unique_count > 1:
            evidence += "; multiple cache mappings for key"
        candidates.append(
            Candidate(
                efo_id=mapped_ids,
                label=mapped_labels,
                score=max(0.0, min(1.0, score)),
                matched_via=method,
                evidence=evidence,
                is_validated=validated_if_unique and unique_count == 1,
            )
        )
    return candidates


def pick_preferred_mapping_pair(mapped_ids: str, mapped_labels: str) -> tuple[str, str] | None:
    ids = [canonicalize_trait_ontology_id(item) for item in split_multi_ids(mapped_ids)]
    ids = [item for item in ids if item]
    if not ids:
        return None
    labels = split_multi_labels(mapped_labels, expected_n=len(ids))
    pairs: list[tuple[str, str]] = []
    for idx, item in enumerate(ids):
        label = normalize(labels[idx] if idx < len(labels) else "")
        pairs.append((item, label))
    pairs.sort(
        key=lambda pair: (
            TRAIT_PREFERRED_PREFIX_ORDER.get(trait_ontology_prefix(pair[0]), 999),
            pair[0],
        )
    )
    return pairs[0]


def pick_preferred_ontology_term(
    term_ids: set[str],
    *,
    ontology_terms: dict[str, TraitOntologyTerm],
) -> tuple[str, str] | None:
    if not term_ids:
        return None
    ordered = sorted(
        (term_id for term_id in term_ids if term_id in ontology_terms),
        key=lambda term_id: (
            TRAIT_PREFERRED_PREFIX_ORDER.get(trait_ontology_prefix(term_id), 999),
            term_id,
        ),
    )
    if not ordered:
        return None
    term_id = ordered[0]
    return term_id, ontology_terms[term_id].label


def is_generic_ukb_measurement_mapping(mapped_id: str, mapped_label: str) -> bool:
    oid = canonicalize_trait_ontology_id(mapped_id)
    label = norm_key(mapped_label)
    return oid == UKB_FIELD_SUPPLEMENT_GENERIC_MEASUREMENT_ID or label in {
        "measurement",
        "clinical measurement",
        "time",
        "duration",
        "eye measurement",
        "anthropometric measurement",
    }


def candidate_has_generic_measurement_mapping(mapped_ids: str, mapped_labels: str) -> bool:
    ids = [canonicalize_trait_ontology_id(item) for item in split_multi_ids(mapped_ids)]
    ids = [item for item in ids if item]
    if not ids:
        return is_generic_ukb_measurement_mapping("", mapped_labels)
    labels = split_multi_labels(mapped_labels, expected_n=len(ids))
    for idx, term_id in enumerate(ids):
        label = normalize(labels[idx] if idx < len(labels) else "")
        if is_generic_ukb_measurement_mapping(term_id, label):
            return True
    return False


def candidate_has_forbidden_trait_mapping(mapped_ids: str, mapped_labels: str) -> bool:
    ids = [canonicalize_trait_ontology_id(item) for item in split_multi_ids(mapped_ids)]
    ids = [item for item in ids if item]
    labels = split_multi_labels(mapped_labels, expected_n=len(ids) if ids else None)
    if not ids:
        return norm_key(mapped_labels) in FORBIDDEN_TRAIT_LABEL_KEYS
    for idx, term_id in enumerate(ids):
        label = normalize(labels[idx] if idx < len(labels) else "")
        if term_id in FORBIDDEN_TRAIT_IDS:
            return True
        if norm_key(label) in FORBIDDEN_TRAIT_LABEL_KEYS:
            return True
    return False


def candidate_is_standalone_temporal_mapping(mapped_ids: str, mapped_labels: str) -> bool:
    ids = [canonicalize_trait_ontology_id(item) for item in split_multi_ids(mapped_ids)]
    ids = [item for item in ids if item]
    labels = split_multi_labels(mapped_labels, expected_n=len(ids) if ids else None)
    if len(ids) > 1 or len(labels) > 1:
        return False
    label_key = norm_key(labels[0] if labels else mapped_labels)
    return label_key in STANDALONE_TEMPORAL_TRAIT_KEYS


def trait_qc_risk_reasons(row: dict[str, str]) -> list[str]:
    reasons: list[str] = []
    validation = norm_key(row.get("validation", ""))
    matched_via = norm_key(row.get("matched_via", ""))
    mapped_label = normalize(row.get("mapped_trait_label", ""))

    try:
        confidence = float(row.get("confidence") or "0")
    except ValueError:
        confidence = 0.0

    if row.get("term_not_in_efo"):
        reasons.append("term_not_in_efo")
    evidence_key = norm_key(row.get("evidence", ""))
    if (
        norm_key(row.get("negation", "")) == "yes"
        and validation == "validated"
        and "field_ordinal_measurement_harmonized=" not in evidence_key
    ):
        reasons.append("negation_with_mapping")
    if validation == "validated" and matched_via in {"cache_fuzzy_text", "efo_obo_fuzzy"}:
        reasons.append("validated_fuzzy_match")
    if validation == "validated" and confidence < 0.90:
        reasons.append("validated_low_confidence")
    if norm_key(row.get("specificity_loss_flag", "")) == "yes":
        reasons.append("specificity_loss")
    if is_generic_trait_label(mapped_label) and validation in {"validated", "review_required"}:
        reasons.append("generic_mapped_label")
    if matched_via in ICD10_PARENT_FALLBACK_METHOD_KEYS:
        reasons.append("icd10_parent_fallback")
    if matched_via == "cache_exact_ukb_field_supplement" and is_generic_trait_label(mapped_label):
        reasons.append("ukb_supplement_generic")
    return reasons


def write_trait_qc_risk_tsv(mapped_output: Path, risk_output: Path) -> int:
    risk_rows: list[dict[str, str]] = []
    with mapped_output.open("r", encoding="utf-8", newline="") as handle:
        reader = csv.DictReader(handle, delimiter="\t")
        for row in reader:
            reasons = trait_qc_risk_reasons(row)
            if not reasons:
                continue
            risk_rows.append(
                {
                    "input_row_id": normalize(row.get("input_row_id", "")),
                    "input_query": normalize(row.get("input_query", "")),
                    "input_source_data_type": normalize(row.get("input_source_data_type", "")),
                    "input_type": normalize(row.get("input_type", "")),
                    "mapped_trait_id": normalize(row.get("mapped_trait_id", "")),
                    "mapped_trait_label": normalize(row.get("mapped_trait_label", "")),
                    "validation": normalize(row.get("validation", "")),
                    "matched_via": normalize(row.get("matched_via", "")),
                    "confidence": normalize(row.get("confidence", "")),
                    "specificity_loss_flag": normalize(row.get("specificity_loss_flag", "")),
                    "specificity_loss_notes": normalize(row.get("specificity_loss_notes", "")),
                    "risk_reasons": "|".join(sorted(set(reasons))),
                    "evidence": normalize(row.get("evidence", "")),
                }
            )

    risk_output.parent.mkdir(parents=True, exist_ok=True)
    with risk_output.open("w", encoding="utf-8", newline="") as handle:
        writer = csv.DictWriter(handle, fieldnames=TRAIT_QC_RISK_FIELDS, delimiter="\t", extrasaction="ignore")
        writer.writeheader()
        writer.writerows(risk_rows)
    return len(risk_rows)


def parse_mondo_sssom_icd10_mappings(path: Path) -> tuple[dict[str, set[str]], dict[str, str]]:
    mapping: dict[str, set[str]] = {}
    mondo_label_index: dict[str, str] = {}
    if not path.exists():
        return mapping, mondo_label_index
    with path.open("r", encoding="utf-8", errors="replace", newline="") as handle:
        header_line = ""
        for raw_line in handle:
            if not raw_line:
                continue
            stripped = raw_line.strip()
            if not stripped or stripped.startswith("#"):
                continue
            header_line = raw_line
            break

        if not header_line:
            return mapping, mondo_label_index

        fieldnames = header_line.rstrip("\r\n").split("\t")
        reader = csv.DictReader(handle, fieldnames=fieldnames, delimiter="\t")
        for row in reader:
            subject_id = normalize(row.get("subject_id", ""))
            object_id = normalize(row.get("object_id", ""))
            subject_label = normalize(row.get("subject_label", ""))
            object_label = normalize(row.get("object_label", ""))
            if not subject_id or not object_id:
                continue
            subject_icd10 = extract_icd10_code_from_xref(subject_id)
            object_icd10 = extract_icd10_code_from_xref(object_id)
            subject_mondo = extract_mondo_id(subject_id)
            object_mondo = extract_mondo_id(object_id)

            if subject_icd10 and object_mondo:
                mapping.setdefault(subject_icd10, set()).add(object_mondo)
                if object_label and object_mondo not in mondo_label_index:
                    mondo_label_index[object_mondo] = object_label
            if object_icd10 and subject_mondo:
                mapping.setdefault(object_icd10, set()).add(subject_mondo)
                if subject_label and subject_mondo not in mondo_label_index:
                    mondo_label_index[subject_mondo] = subject_label
    return mapping, mondo_label_index


def parse_cms_icd10_label_rows(zip_path: Path, *, source_url: str) -> tuple[list[dict[str, str]], str]:
    with zipfile.ZipFile(zip_path) as zf:
        member_names = [
            name
            for name in zf.namelist()
            if name.lower().endswith(".txt")
            and "order" in Path(name).name.lower()
            and "addenda" not in Path(name).name.lower()
        ]
        if not member_names:
            raise ValueError(f"No CMS ICD10 tabular-order text file found in {zip_path}")
        member_names.sort(key=lambda name: ("icd10cm_order" not in Path(name).name.lower(), len(name), name))
        member_name = member_names[0]
        raw_lines = zf.read(member_name).decode("utf-8", errors="replace").splitlines()

    rows: list[dict[str, str]] = []
    seen_codes: set[str] = set()
    for raw_line in raw_lines:
        line = raw_line.rstrip("\r\n")
        if len(line) < 17:
            continue
        raw_code = normalize(line[6:13])
        if not raw_code:
            continue
        label = normalize(line[77:] if len(line) > 77 else "") or normalize(line[16:76])
        code = normalize_icd10_code(raw_code)
        if not code or not is_strict_icd10_code(code) or not label or code in seen_codes:
            continue
        seen_codes.add(code)
        rows.append(
            {
                "ICD10": code,
                "label": label,
                "source": "CMS ICD-10-CM tabular order",
                "source_url": source_url,
            }
        )

    if not rows:
        raise ValueError(f"No ICD10 label rows parsed from {zip_path}")
    return rows, member_name


def extract_icd10_alias_candidates(text: str) -> set[str]:
    raw = normalize(text)
    if not raw:
        return set()
    candidates: set[str] = {raw}
    for inner in re.findall(r"\[([^\]]+)\]", raw):
        for part in re.split(r"[|/;,]+", inner):
            alias = normalize(part)
            if alias and len(alias) >= 3:
                candidates.add(alias)
    stripped = normalize(re.sub(r"\[[^\]]+\]", " ", raw))
    if stripped:
        candidates.add(stripped)
    generic_alias_keys = {
        "other",
        "other specified",
        "unspecified",
        "not elsewhere classified",
        "nec",
        "nos",
    }
    filtered: set[str] = set()
    for candidate in candidates:
        key = norm_key(candidate)
        if not key or key in generic_alias_keys:
            continue
        filtered.add(candidate)
    return filtered


def parse_cms_icd10_alias_rows(zip_path: Path, *, source_url: str) -> tuple[list[dict[str, str]], tuple[str, ...]]:
    alias_types: dict[tuple[str, str], set[str]] = {}
    used_members: set[str] = set()

    def add_alias(raw_code: str, text: str, alias_type: str) -> None:
        code = normalize_icd10_code(raw_code)
        if not code or not is_strict_icd10_code(code):
            return
        for alias in extract_icd10_alias_candidates(text):
            alias_types.setdefault((code, alias), set()).add(alias_type)

    with zipfile.ZipFile(zip_path) as zf:
        all_txt_members = [name for name in zf.namelist() if name.lower().endswith(".txt")]
        order_members = [
            name for name in all_txt_members if "order" in Path(name).name.lower()
        ]
        code_members = [
            name for name in all_txt_members if "codes" in Path(name).name.lower()
        ]
        if not order_members and not code_members:
            raise ValueError(f"No CMS ICD10 order/codes text files found in {zip_path}")

        def parse_order_member(member_name: str) -> None:
            used_members.add(member_name)
            raw_lines = zf.read(member_name).decode("utf-8", errors="replace").splitlines()
            member_key = Path(member_name).name.lower()
            long_type = "order_long_addenda" if "addenda" in member_key else "order_long"
            for raw_line in raw_lines:
                line = raw_line.rstrip("\r\n")
                if len(line) < 17:
                    continue
                raw_code = normalize(line[6:13])
                if not raw_code:
                    continue
                long_label = normalize(line[77:] if len(line) > 77 else "")
                if long_label:
                    add_alias(raw_code, long_label, long_type)

        def parse_codes_member(member_name: str) -> None:
            used_members.add(member_name)
            raw_lines = zf.read(member_name).decode("utf-8", errors="replace").splitlines()
            member_key = Path(member_name).name.lower()
            alias_type = "codes_label_addenda" if "addenda" in member_key else "codes_label"
            for raw_line in raw_lines:
                line = raw_line.rstrip("\r\n")
                if not line:
                    continue
                match = re.match(r"^\s*([A-TV-Z][0-9][0-9A-Z]{1,5})\s+(.+?)\s*$", line)
                if not match:
                    continue
                add_alias(match.group(1), match.group(2), alias_type)

        for member in sorted(order_members):
            parse_order_member(member)
        for member in sorted(code_members):
            parse_codes_member(member)

    rows: list[dict[str, str]] = []
    for code, alias in sorted(alias_types.keys(), key=lambda item: (item[0], norm_key(item[1]), item[1])):
        rows.append(
            {
                "ICD10": code,
                "alias": alias,
                "alias_type": "|".join(sorted(alias_types[(code, alias)])),
                "source": "CMS ICD-10-CM tabular order/codes",
                "source_url": source_url,
            }
        )
    if not rows:
        raise ValueError(f"No ICD10 alias rows parsed from {zip_path}")
    return rows, tuple(sorted(used_members))


def build_icd10_label_cache(
    *,
    output_path: Path,
    source_url: str,
    timeout: float,
) -> dict[str, Any]:
    url = normalize(source_url)
    if not url:
        raise ValueError("ICD10 label source URL is required")

    with tempfile.TemporaryDirectory(prefix="icd10-label-cache-") as tmpdir:
        archive_path = Path(tmpdir) / Path(urllib.parse.urlparse(url).path).name
        if not archive_path.name:
            archive_path = Path(tmpdir) / "icd10_labels_source.zip"
        download_to_file(url, archive_path, timeout=timeout)
        archive_size_bytes = archive_path.stat().st_size if archive_path.exists() else 0
        rows, member_name = parse_cms_icd10_label_rows(archive_path, source_url=url)

    output_path.parent.mkdir(parents=True, exist_ok=True)
    with output_path.open("w", encoding="utf-8", newline="") as handle:
        writer = csv.DictWriter(
            handle,
            fieldnames=["ICD10", "label", "source", "source_url"],
            delimiter="\t",
            extrasaction="ignore",
        )
        writer.writeheader()
        writer.writerows(rows)

    return {
        "codes": len(rows),
        "output_path": str(output_path),
        "source_url": url,
        "source_member": member_name,
        "archive_size_bytes": archive_size_bytes,
    }


def build_icd10_label_alias_cache(
    *,
    output_path: Path,
    source_url: str,
    timeout: float,
) -> dict[str, Any]:
    url = normalize(source_url)
    if not url:
        raise ValueError("ICD10 label source URL is required")

    with tempfile.TemporaryDirectory(prefix="icd10-alias-cache-") as tmpdir:
        archive_path = Path(tmpdir) / Path(urllib.parse.urlparse(url).path).name
        if not archive_path.name:
            archive_path = Path(tmpdir) / "icd10_alias_source.zip"
        download_to_file(url, archive_path, timeout=timeout)
        archive_size_bytes = archive_path.stat().st_size if archive_path.exists() else 0
        rows, member_names = parse_cms_icd10_alias_rows(archive_path, source_url=url)

    output_path.parent.mkdir(parents=True, exist_ok=True)
    with output_path.open("w", encoding="utf-8", newline="") as handle:
        writer = csv.DictWriter(
            handle,
            fieldnames=["ICD10", "alias", "alias_type", "source", "source_url"],
            delimiter="\t",
            extrasaction="ignore",
        )
        writer.writeheader()
        writer.writerows(rows)

    code_count = len({normalize_icd10_code(row.get("ICD10", "")) for row in rows if normalize_icd10_code(row.get("ICD10", ""))})
    return {
        "aliases": len(rows),
        "codes": code_count,
        "output_path": str(output_path),
        "source_url": url,
        "source_members": tuple(member_names),
        "archive_size_bytes": archive_size_bytes,
    }


def load_icd10_label_cache(path: Path) -> dict[str, tuple[str, ...]]:
    label_index: dict[str, set[str]] = {}
    if not path.exists():
        return {}
    with path.open("r", encoding="utf-8", newline="") as handle:
        reader = csv.DictReader(handle, delimiter="\t")
        for row in reader:
            code = normalize_icd10_code(row.get("ICD10") or row.get("icd10") or "")
            label = normalize(row.get("label") or row.get("icd10_label") or row.get("description") or "")
            if not code or not is_strict_icd10_code(code) or not label:
                continue
            label_index.setdefault(code, set()).add(label)
    return {code: tuple(sorted(labels)) for code, labels in label_index.items()}


def load_icd10_label_alias_cache(path: Path) -> dict[str, tuple[str, ...]]:
    alias_index: dict[str, set[str]] = {}
    if not path.exists():
        return {}
    with path.open("r", encoding="utf-8", newline="") as handle:
        reader = csv.DictReader(handle, delimiter="\t")
        for row in reader:
            code = normalize_icd10_code(row.get("ICD10") or row.get("icd10") or "")
            alias = normalize(row.get("alias") or row.get("label") or "")
            if not code or not is_strict_icd10_code(code) or not alias:
                continue
            alias_index.setdefault(code, set()).add(alias)
    return {code: tuple(sorted(aliases)) for code, aliases in alias_index.items()}


def build_icd10_supplement_cache(
    *,
    output_path: Path,
    trait_cache_path: Path,
    efo_obo_path: Path,
    mondo_sssom_cache_path: Path,
    mondo_sssom_url: str,
    mondo_download_timeout: float,
    icd10_label_cache_path: Path | None = None,
    icd10_label_alias_cache_path: Path | None = None,
) -> dict[str, Any]:
    trait_cache_index = load_trait_cache_index(trait_cache_path)
    base_icd10_codes = set(trait_cache_index.get("icd10_index", {}).keys())
    ontology_index = load_trait_ontology_index(efo_obo_path)
    ontology_terms: dict[str, TraitOntologyTerm] = ontology_index.get("terms", {})
    obsolete_terms: dict[str, TraitObsoleteTerm] = ontology_index.get("obsolete_terms", {})
    ontology_icd10_xref_index: dict[str, set[str]] = ontology_index.get("icd10_xref_index", {})
    preferred_label_index: dict[str, set[str]] = {}
    preferred_exact_phrase_index: dict[str, set[str]] = {}
    for term_id, term in ontology_terms.items():
        if trait_ontology_prefix(term_id) not in {"EFO", "MONDO"}:
            continue
        if term.label_key:
            preferred_label_index.setdefault(term.label_key, set()).add(term_id)
            preferred_exact_phrase_index.setdefault(term.label_key, set()).add(term_id)
        for syn_key in term.exact_synonym_keys:
            if syn_key:
                preferred_exact_phrase_index.setdefault(syn_key, set()).add(term_id)

    def icd10_label_is_confident_seedable(label_text: str) -> bool:
        label_key = norm_key(label_text)
        if not label_key:
            return False
        # Skip context/admin/status labels that are not direct disease traits.
        if re.search(
            r"\b("
            r"personal history|family history|screening|encounter|aftercare|follow up|follow-up|"
            r"status|presence of|absence of|cause of diseases? classified elsewhere|classified elsewhere|"
            r"administrative|health service|contact with|observation for"
            r")\b",
            label_key,
        ):
            return False
        # Skip low-specificity ICD10 wording for confident auto-seeding.
        if re.search(r"\b(other specified|other|unspecified|not elsewhere classified|nec|nos)\b", label_key):
            return False
        return True

    code_to_term_ids: dict[str, set[str]] = {}
    efo_code_to_term_ids: dict[str, set[str]] = {}
    mondo_code_to_term_ids: dict[str, set[str]] = {}
    mondo_direct_code_to_term_ids: dict[str, set[str]] = {}
    mondo_projected_code_to_term_ids: dict[str, set[str]] = {}
    alias_code_to_term_ids: dict[str, set[str]] = {}
    def resolve_active_term_ids(raw_term_id: str) -> tuple[str, ...]:
        canonical = canonicalize_trait_ontology_id(raw_term_id)
        if not canonical:
            return ()
        if canonical in ontology_terms:
            return (canonical,)
        obsolete_meta = obsolete_terms.get(canonical)
        if obsolete_meta is None:
            return ()
        replacements = [rid for rid in obsolete_meta.replaced_by if rid in ontology_terms]
        if replacements:
            return tuple(dict.fromkeys(replacements))
        consider = [cid for cid in obsolete_meta.consider if cid in ontology_terms]
        if len(consider) == 1:
            return (consider[0],)
        return ()

    for raw_code, term_ids in ontology_icd10_xref_index.items():
        code = normalize_icd10_code(raw_code)
        if not code:
            continue
        for term_id in term_ids:
            resolved_ids = resolve_active_term_ids(term_id)
            for oid in resolved_ids:
                code_to_term_ids.setdefault(code, set()).add(oid)
                efo_code_to_term_ids.setdefault(code, set()).add(oid)

    mondo_codes_added = 0
    mondo_terms_not_in_efo = 0
    mondo_terms_label_projected = 0
    mondo_codes_label_projected = 0
    mondo_downloaded = False
    mondo_download_error = ""
    mondo_cache_source = "none"
    mondo_cache_used = False
    mondo_mapping_codes = 0
    alias_candidates_codes = 0
    alias_codes_added = 0
    alias_codes_ambiguous = 0
    alias_term_matches_total = 0
    alias_exact_synonym_hits = 0
    alias_primary_label_hits = 0
    alias_context_filtered = 0
    mondo_url = normalize(mondo_sssom_url)
    if mondo_url:
        try:
            mondo_sssom_cache_path.parent.mkdir(parents=True, exist_ok=True)
            download_to_file(mondo_url, mondo_sssom_cache_path, timeout=mondo_download_timeout)
            mondo_downloaded = True
            mondo_cache_source = "downloaded"
        except Exception as exc:  # noqa: BLE001 - setup should degrade gracefully offline.
            mondo_download_error = str(exc)
    if mondo_sssom_cache_path.exists() and mondo_sssom_cache_path.stat().st_size > 0:
        try:
            mondo_mapping, mondo_label_index = parse_mondo_sssom_icd10_mappings(mondo_sssom_cache_path)
            mondo_mapping_codes = len(mondo_mapping)
            if mondo_mapping:
                mondo_cache_used = True
                if mondo_cache_source == "none":
                    mondo_cache_source = "cached"

            def resolve_projected_term_from_mondo_label(mondo_id: str) -> str:
                label = normalize(mondo_label_index.get(mondo_id, ""))
                if not label:
                    return ""
                label_key = norm_key(label)
                candidate_ids = preferred_label_index.get(label_key, set())
                if not candidate_ids or len(candidate_ids) != 1:
                    return ""
                projected_term = next(iter(candidate_ids))
                if projected_term not in ontology_terms:
                    return ""
                return projected_term

            for code, term_ids in mondo_mapping.items():
                valid_terms: set[str] = set()
                projected_added = False
                for term_id in term_ids:
                    resolved_ids = resolve_active_term_ids(term_id)
                    if resolved_ids:
                        valid_terms.update(resolved_ids)
                        mondo_direct_code_to_term_ids.setdefault(code, set()).update(resolved_ids)
                        continue
                    canonical = canonicalize_trait_ontology_id(term_id)
                    if canonical and trait_ontology_prefix(canonical) == "MONDO":
                        mondo_terms_not_in_efo += 1
                        projected_term = resolve_projected_term_from_mondo_label(canonical)
                        if projected_term:
                            valid_terms.add(projected_term)
                            mondo_projected_code_to_term_ids.setdefault(code, set()).add(projected_term)
                            mondo_terms_label_projected += 1
                            projected_added = True
                if not valid_terms:
                    continue
                mondo_code_to_term_ids.setdefault(code, set()).update(valid_terms)
                if projected_added:
                    mondo_codes_label_projected += 1
                # Keep EFO ICD10-xref mappings stable; MONDO only backfills codes
                # that have no direct EFO ICD10 xref candidates.
                if code not in efo_code_to_term_ids:
                    before = len(code_to_term_ids.get(code, set()))
                    code_to_term_ids.setdefault(code, set()).update(valid_terms)
                    after = len(code_to_term_ids.get(code, set()))
                    if after > before:
                        mondo_codes_added += 1
        except Exception as exc:  # noqa: BLE001 - setup should degrade gracefully offline.
            if not mondo_download_error:
                mondo_download_error = str(exc)

    official_label_index: dict[str, tuple[str, ...]] = {}
    if icd10_label_cache_path is not None and icd10_label_cache_path.exists():
        official_label_index = load_icd10_label_cache(icd10_label_cache_path)
    alias_label_index: dict[str, tuple[str, ...]] = {}
    if icd10_label_alias_cache_path is not None and icd10_label_alias_cache_path.exists():
        alias_label_index = load_icd10_label_alias_cache(icd10_label_alias_cache_path)

    alias_candidate_codes = set(official_label_index.keys()) | set(alias_label_index.keys())
    alias_candidates_codes = len(alias_candidate_codes)
    for code in sorted(alias_candidate_codes):
        if code in code_to_term_ids:
            continue
        if code in base_icd10_codes:
            continue
        labels = list(official_label_index.get(code, ()))
        labels.extend(alias_label_index.get(code, ()))
        if not labels:
            continue
        matched_terms: set[str] = set()
        used_exact_synonym = False
        used_primary_label = False
        for label in labels:
            label_key = norm_key(label)
            if not label_key:
                continue
            if not icd10_label_is_confident_seedable(label):
                alias_context_filtered += 1
                continue
            candidate_ids = preferred_exact_phrase_index.get(label_key, set())
            if len(candidate_ids) != 1:
                continue
            candidate_id = next(iter(candidate_ids))
            term = ontology_terms.get(candidate_id)
            if term is None:
                continue
            if is_generic_trait_label(term.label):
                continue
            informative_tokens = [tok for tok in tokenize(term.label) if tok not in TRAIT_STOP_TOKENS]
            if len(informative_tokens) < 1:
                continue
            if label_key == term.label_key:
                used_primary_label = True
            elif label_key in term.exact_synonym_keys:
                used_exact_synonym = True
            matched_terms.add(candidate_id)
        if len(matched_terms) == 1:
            alias_term_matches_total += 1
            alias_codes_added += 1
            if used_primary_label:
                alias_primary_label_hits += 1
            if used_exact_synonym:
                alias_exact_synonym_hits += 1
            alias_code_to_term_ids[code] = set(matched_terms)
            code_to_term_ids.setdefault(code, set()).update(matched_terms)
        elif len(matched_terms) > 1:
            alias_term_matches_total += len(matched_terms)
            alias_codes_ambiguous += 1

    method_counts: Counter[str] = Counter()
    supplement_rows: list[dict[str, str]] = []
    total_codes = 0
    base_covered_codes = 0

    sortable_codes = sorted(
        code_to_term_ids.keys(),
        key=lambda code: (code[:1], int(re.sub(r"\D", "", code[:3]) or 0), code),
    )
    for code in sortable_codes:
        total_codes += 1
        if code in base_icd10_codes:
            base_covered_codes += 1
            continue
        selected_from_efo = code in efo_code_to_term_ids
        if selected_from_efo:
            candidate_term_ids = efo_code_to_term_ids.get(code, set())
        else:
            candidate_term_ids = mondo_code_to_term_ids.get(code, set()) or code_to_term_ids.get(code, set())
        selected = pick_preferred_ontology_term(candidate_term_ids, ontology_terms=ontology_terms)
        if selected is None:
            continue
        mapped_id, mapped_label = selected
        method = "icd10_supplement_efo_obo_xref"
        if not selected_from_efo:
            direct_terms = mondo_direct_code_to_term_ids.get(code, set())
            projected_terms = mondo_projected_code_to_term_ids.get(code, set())
            alias_terms = alias_code_to_term_ids.get(code, set())
            if mapped_id in alias_terms and mapped_id not in direct_terms and mapped_id not in projected_terms:
                method = "icd10_supplement_icd10_alias_exact"
            elif mapped_id in projected_terms and mapped_id not in direct_terms:
                method = "icd10_supplement_mondo_sssom_label_projected"
            else:
                method = "icd10_supplement_mondo_sssom"
        method_counts[method] += 1
        supplement_rows.append(
            {
                "UKBB data field": "-",
                "ICD10": code,
                "PheCode": "-",
                "Lookup text": f"ICD10 {code} {mapped_label}",
                "Curated reported trait": f"ICD10 {code}: {mapped_label}",
                "main ontology URI(s)": mapped_id,
                "main ontology label(s)": mapped_label,
                "Publication": ICD10_SUPPLEMENT_PUBLICATION,
                "User submitted trait": "-",
                "qc_status": "review_required",
                "qc_resolution_modes": method,
                "qc_label_match_modes": method,
                "qc_unresolved_ids": "",
                "final_update_applied": "yes",
                "final_update_reason": "icd10_supplement_cache_generated",
            }
        )

    existing_rows: list[dict[str, str]] = []
    existing_codes: set[str] = set()
    if output_path.exists():
        try:
            with output_path.open("r", encoding="utf-8", newline="") as handle:
                reader = csv.DictReader(handle, delimiter="\t")
                for row in reader:
                    code = normalize_icd10_code(row.get("ICD10", ""))
                    if not code or code in existing_codes:
                        continue
                    existing_codes.add(code)
                    existing_rows.append({column: row.get(column, "") for column in TRAIT_CACHE_COLUMNS})
        except Exception:
            existing_rows = []
            existing_codes = set()

    appended_rows = 0
    output_rows = list(supplement_rows)
    if existing_rows:
        output_rows = list(existing_rows)
        for row in supplement_rows:
            code = normalize_icd10_code(row.get("ICD10", ""))
            if not code or code in existing_codes:
                continue
            output_rows.append(row)
            existing_codes.add(code)
            appended_rows += 1
    else:
        appended_rows = len(supplement_rows)

    output_path.parent.mkdir(parents=True, exist_ok=True)
    with output_path.open("w", encoding="utf-8", newline="") as handle:
        writer = csv.DictWriter(
            handle,
            fieldnames=TRAIT_CACHE_COLUMNS,
            delimiter="\t",
            extrasaction="ignore",
        )
        writer.writeheader()
        writer.writerows(output_rows)

    return {
        "total_codes": total_codes,
        "base_covered_codes": base_covered_codes,
        "supplement_rows": len(supplement_rows),
        "output_rows": len(output_rows),
        "existing_rows_preserved": len(existing_rows),
        "appended_rows": appended_rows,
        "method_efo_obo_xref": method_counts.get("icd10_supplement_efo_obo_xref", 0),
        "method_mondo_sssom": method_counts.get("icd10_supplement_mondo_sssom", 0),
        "method_icd10_alias_exact": method_counts.get("icd10_supplement_icd10_alias_exact", 0),
        "method_mondo_sssom_label_projected": method_counts.get(
            "icd10_supplement_mondo_sssom_label_projected", 0
        ),
        "method_mondo_sssom_efo_obo_xref": method_counts.get(
            "icd10_supplement_mondo_sssom_efo_obo_xref", 0
        ),
        "mondo_url_used": mondo_url,
        "mondo_cache_path": str(mondo_sssom_cache_path),
        "mondo_cache_source": mondo_cache_source,
        "mondo_cache_used": mondo_cache_used,
        "mondo_mapping_codes": mondo_mapping_codes,
        "mondo_downloaded": mondo_downloaded,
        "mondo_codes_added": mondo_codes_added,
        "mondo_terms_not_in_efo": mondo_terms_not_in_efo,
        "mondo_terms_label_projected": mondo_terms_label_projected,
        "mondo_codes_label_projected": mondo_codes_label_projected,
        "alias_candidates_codes": alias_candidates_codes,
        "alias_codes_added": alias_codes_added,
        "alias_codes_ambiguous": alias_codes_ambiguous,
        "alias_term_matches_total": alias_term_matches_total,
        "alias_primary_label_hits": alias_primary_label_hits,
        "alias_exact_synonym_hits": alias_exact_synonym_hits,
        "alias_context_filtered": alias_context_filtered,
        "mondo_download_error": mondo_download_error,
    }


def build_ukb_field_supplement_cache(
    *,
    output_path: Path,
    trait_cache_path: Path,
    efo_obo_path: Path,
    ukb_field_catalog_path: Path | None,
    ukb_field_metadata_path: Path | None,
    ukb_category_catalog_path: Path | None,
    ukb_category_tree_path: Path | None,
) -> dict[str, int]:
    if ukb_field_metadata_path is None or not ukb_field_metadata_path.exists():
        raise FileNotFoundError(
            "UKB field metadata is required to build supplemental field cache: "
            f"{ukb_field_metadata_path}"
        )

    trait_cache_index = load_trait_cache_index(trait_cache_path)
    ontology_index = load_trait_ontology_index(efo_obo_path)
    trait_cache_resolution, _, _ = build_trait_cache_term_resolution(trait_cache_index, ontology_index)
    records: list[TraitCacheRecord] = trait_cache_index.get("records", [])
    ukb_field_index: dict[str, list[int]] = trait_cache_index.get("ukb_field_index", {})
    text_exact_index: dict[str, list[int]] = trait_cache_index.get("text_exact_index", {})
    ontology_terms: dict[str, TraitOntologyTerm] = ontology_index.get("terms", {})
    ontology_exact_index: dict[str, set[str]] = ontology_index.get("exact_index", {})
    ontology_token_index: dict[str, set[str]] = ontology_index.get("token_index", {})
    ontology_token_freq: Counter[str] = ontology_index.get("token_freq", Counter())

    ukb_field_titles = load_ukb_field_title_index(ukb_field_catalog_path)
    metadata_field_titles = load_ukb_field_title_index(ukb_field_metadata_path)
    for field_id, title in metadata_field_titles.items():
        if field_id in ukb_field_titles:
            continue
        ukb_field_titles[field_id] = title

    ukb_field_to_category, ukb_category_to_fields = load_ukb_field_category_index(ukb_field_metadata_path)
    ukb_category_titles = load_ukb_category_title_index(ukb_category_catalog_path)
    ukb_category_parents = load_ukb_category_parent_index(ukb_category_tree_path)

    def resolve_record(record: TraitCacheRecord) -> tuple[tuple[str, ...], tuple[str, ...]] | None:
        resolved = trait_cache_resolution.get(record.rownum)
        if resolved is not None:
            return resolved
        if record.mapped_ids:
            return record.mapped_ids, record.mapped_labels
        return None

    def choose_mapping_from_records(
        matched_records: list[TraitCacheRecord],
        *,
        method: str,
        matched_on: str,
    ) -> tuple[str, str, str] | None:
        candidates = collapse_trait_cache_candidates(
            matched_records,
            method=method,
            score=0.9,
            matched_on=matched_on,
            validated_if_unique=False,
            record_resolver=resolve_record,
        )
        if len(candidates) != 1:
            return None
        pair = pick_preferred_mapping_pair(candidates[0].efo_id, candidates[0].label)
        if pair is None:
            return None
        mapped_id, mapped_label = pair
        return mapped_id, mapped_label, method

    def choose_mapping_from_ontology_fuzzy(
        text: str,
        *,
        method: str,
        min_score: float = 0.88,
        min_margin: float = 0.04,
    ) -> tuple[str, str, str] | None:
        query_norm = normalize_trait_text_for_similarity(text)
        query_tokens = informative_trait_tokens(query_norm)
        if not query_norm or not query_tokens:
            return None
        seed_tokens = pick_seed_tokens(query_tokens, ontology_token_freq, max_tokens=7)
        candidate_term_ids: set[str] = set()
        for tok in seed_tokens:
            candidate_term_ids |= ontology_token_index.get(tok, set())
        if not candidate_term_ids:
            return None

        scored_terms: list[tuple[float, str]] = []
        for term_id in candidate_term_ids:
            term = ontology_terms.get(term_id)
            if term is None:
                continue
            best_score = trait_similarity_score(query_norm, query_tokens, term.label)
            for syn in term.synonyms[:10]:
                best_score = max(best_score, trait_similarity_score(query_norm, query_tokens, syn))
            if best_score <= 0.0:
                continue
            scored_terms.append((best_score, term_id))
        if not scored_terms:
            return None

        scored_terms.sort(
            key=lambda item: (
                item[0],
                -TRAIT_PREFERRED_PREFIX_ORDER.get(trait_ontology_prefix(item[1]), 999),
                item[1],
            ),
            reverse=True,
        )
        top_score, top_id = scored_terms[0]
        second_score = scored_terms[1][0] if len(scored_terms) > 1 else 0.0
        if top_score < min_score:
            return None
        if (top_score - second_score) < min_margin:
            return None
        top_term = ontology_terms.get(top_id)
        if top_term is None:
            return None
        return top_term.term_id, top_term.label, method

    def category_context(category_id: str) -> tuple[str, tuple[str, ...]]:
        category_title = normalize(ukb_category_titles.get(category_id, ""))
        path_titles = ukb_category_path_titles(
            category_id,
            category_titles=ukb_category_titles,
            category_parents=ukb_category_parents,
        )
        return category_title, path_titles

    category_default_mapping: dict[str, tuple[str, str, str]] = {}
    for category_id in sorted({normalize(cat) for cat in ukb_field_to_category.values() if normalize(cat)}):
        category_title, path_titles = category_context(category_id)
        category_field_ids = tuple(normalize(item) for item in ukb_category_to_fields.get(category_id, ()) if normalize(item))
        matched_record_idxs: list[int] = []
        seen_rec_idxs: set[int] = set()
        for field_id in category_field_ids:
            for rec_idx in ukb_field_index.get(field_id, []):
                record = records[rec_idx]
                if record.is_ukb_field_supplement:
                    continue
                if rec_idx in seen_rec_idxs:
                    continue
                seen_rec_idxs.add(rec_idx)
                matched_record_idxs.append(rec_idx)
        if matched_record_idxs:
            matched_records = [records[idx] for idx in matched_record_idxs]
            chosen = choose_mapping_from_records(
                matched_records,
                method="ukb_field_supplement_category_cache_unique",
                matched_on="UKB category field set",
            )
            if chosen is not None and is_generic_ukb_measurement_mapping(chosen[0], chosen[1]):
                chosen = None
            if chosen is not None:
                category_default_mapping[category_id] = chosen
                continue

        category_exact_keys: list[str] = []
        for variant in ukb_category_query_variants(category_id, category_title, path_titles):
            key = norm_key(variant)
            if key and key not in category_exact_keys:
                category_exact_keys.append(key)
        for title in path_titles:
            key = norm_key(title)
            if key and key not in category_exact_keys:
                category_exact_keys.append(key)

        matched_record_idxs = []
        seen_rec_idxs = set()
        for key in category_exact_keys:
            for rec_idx in text_exact_index.get(key, []):
                record = records[rec_idx]
                if record.is_ukb_field_supplement:
                    continue
                if rec_idx in seen_rec_idxs:
                    continue
                seen_rec_idxs.add(rec_idx)
                matched_record_idxs.append(rec_idx)
        if matched_record_idxs:
            matched_records = [records[idx] for idx in matched_record_idxs]
            chosen = choose_mapping_from_records(
                matched_records,
                method="ukb_field_supplement_category_text_exact",
                matched_on="UKB category title/path text",
            )
            if chosen is not None and is_generic_ukb_measurement_mapping(chosen[0], chosen[1]):
                chosen = None
            if chosen is not None:
                category_default_mapping[category_id] = chosen
                continue

        exact_term_ids = exact_ontology_term_ids_for_keys(
            category_exact_keys,
            ontology_exact_index=ontology_exact_index,
            ontology_terms=ontology_terms,
        )
        selected_term = pick_preferred_ontology_term(exact_term_ids, ontology_terms=ontology_terms)
        if selected_term is not None:
            term_id, term_label = selected_term
            category_default_mapping[category_id] = (
                term_id,
                term_label,
                "ukb_field_supplement_category_ontology_exact",
            )
            continue

        category_text = " ".join([category_title, *path_titles]).lower()
        looks_disease = (
            has_disease_hint(category_text)
            or any(phrase in category_text for phrase in UKB_DISEASE_CATEGORY_PHRASES)
        )
        if looks_disease:
            category_default_mapping[category_id] = (
                UKB_FIELD_SUPPLEMENT_GENERIC_DISEASE_ID,
                UKB_FIELD_SUPPLEMENT_GENERIC_DISEASE_LABEL,
                "ukb_field_supplement_generic_disease",
            )
        else:
            category_default_mapping[category_id] = (
                UKB_FIELD_SUPPLEMENT_GENERIC_MEASUREMENT_ID,
                UKB_FIELD_SUPPLEMENT_GENERIC_MEASUREMENT_LABEL,
                "ukb_field_supplement_generic_measurement",
            )

    base_covered_fields = set(ukb_field_index.keys())
    supplement_rows: list[dict[str, str]] = []
    method_counts: Counter[str] = Counter()
    total_fields = 0

    def make_row(field_id: str, field_title: str, mapped_id: str, mapped_label: str, method: str) -> dict[str, str]:
        clean_title = normalize(field_title) or f"UKB field {field_id}"
        return {
            "UKBB data field": field_id,
            "ICD10": "-",
            "PheCode": "-",
            "Lookup text": clean_title,
            "Curated reported trait": f"{clean_title} (UKB data field {field_id})",
            "main ontology URI(s)": mapped_id,
            "main ontology label(s)": mapped_label,
            "Publication": UKB_FIELD_SUPPLEMENT_PUBLICATION,
            "User submitted trait": "-",
            "qc_status": "review_required",
            "qc_resolution_modes": method,
            "qc_label_match_modes": method,
            "qc_unresolved_ids": "",
            "final_update_applied": "yes",
            "final_update_reason": "ukb_field_supplement_cache_generated",
        }

    sortable_fields = sorted(
        ukb_field_titles.items(),
        key=lambda item: (int(item[0]) if item[0].isdigit() else 10**9, item[0]),
    )
    for field_id, field_title in sortable_fields:
        if not field_id:
            continue
        total_fields += 1
        if field_id in base_covered_fields:
            continue

        chosen_mapping: tuple[str, str, str] | None = None
        field_exact_keys: list[str] = []
        for variant in ukb_title_query_variants(field_id, field_title):
            key = norm_key(variant)
            if key and key not in field_exact_keys:
                field_exact_keys.append(key)

        matched_record_idxs: list[int] = []
        seen_rec_idxs: set[int] = set()
        for key in field_exact_keys:
            for rec_idx in text_exact_index.get(key, []):
                record = records[rec_idx]
                if record.is_ukb_field_supplement:
                    continue
                if rec_idx in seen_rec_idxs:
                    continue
                seen_rec_idxs.add(rec_idx)
                matched_record_idxs.append(rec_idx)
        if matched_record_idxs:
            matched_records = [records[idx] for idx in matched_record_idxs]
            chosen_mapping = choose_mapping_from_records(
                matched_records,
                method="ukb_field_supplement_field_title_cache_exact",
                matched_on="UKB field title",
            )
            if (
                chosen_mapping is not None
                and is_generic_ukb_measurement_mapping(chosen_mapping[0], chosen_mapping[1])
            ):
                chosen_mapping = None

        if chosen_mapping is None:
            exact_term_ids = exact_ontology_term_ids_for_keys(
                field_exact_keys,
                ontology_exact_index=ontology_exact_index,
                ontology_terms=ontology_terms,
            )
            selected_term = pick_preferred_ontology_term(exact_term_ids, ontology_terms=ontology_terms)
            if selected_term is not None:
                term_id, term_label = selected_term
                chosen_mapping = (
                    term_id,
                    term_label,
                    "ukb_field_supplement_field_title_ontology_exact",
                )
                if is_generic_ukb_measurement_mapping(chosen_mapping[0], chosen_mapping[1]):
                    chosen_mapping = None

        if chosen_mapping is None:
            chosen_mapping = choose_mapping_from_ontology_fuzzy(
                field_title,
                method="ukb_field_supplement_field_title_ontology_fuzzy",
                min_score=0.95,
                min_margin=0.02,
            )

        if chosen_mapping is None:
            category_id = normalize(ukb_field_to_category.get(field_id, ""))
            chosen_mapping = category_default_mapping.get(category_id)

        if chosen_mapping is None:
            chosen_mapping = (
                UKB_FIELD_SUPPLEMENT_GENERIC_MEASUREMENT_ID,
                UKB_FIELD_SUPPLEMENT_GENERIC_MEASUREMENT_LABEL,
                "ukb_field_supplement_generic_measurement",
            )

        mapped_id, mapped_label, method = chosen_mapping
        method_counts[method] += 1
        supplement_rows.append(make_row(field_id, field_title, mapped_id, mapped_label, method))

    output_path.parent.mkdir(parents=True, exist_ok=True)
    with output_path.open("w", encoding="utf-8", newline="") as handle:
        writer = csv.DictWriter(
            handle,
            fieldnames=TRAIT_CACHE_COLUMNS,
            delimiter="\t",
            extrasaction="ignore",
        )
        writer.writeheader()
        writer.writerows(supplement_rows)

    return {
        "total_fields": total_fields,
        "base_covered_fields": len(base_covered_fields & set(ukb_field_titles)),
        "supplement_rows": len(supplement_rows),
        "method_category_cache_unique": method_counts.get("ukb_field_supplement_category_cache_unique", 0),
        "method_category_text_exact": method_counts.get("ukb_field_supplement_category_text_exact", 0),
        "method_category_ontology_exact": method_counts.get("ukb_field_supplement_category_ontology_exact", 0),
        "method_field_title_cache_exact": method_counts.get("ukb_field_supplement_field_title_cache_exact", 0),
        "method_field_title_ontology_exact": method_counts.get("ukb_field_supplement_field_title_ontology_exact", 0),
        "method_field_title_ontology_fuzzy": method_counts.get("ukb_field_supplement_field_title_ontology_fuzzy", 0),
        "method_generic_disease": method_counts.get("ukb_field_supplement_generic_disease", 0),
        "method_generic_measurement": method_counts.get("ukb_field_supplement_generic_measurement", 0),
    }


def confidence_bucket(score: float) -> str:
    if score >= 0.93:
        return "high"
    if score >= 0.82:
        return "medium"
    return "low"


def make_trait_provenance(
    *,
    method: str,
    input_type: str,
    trait_scale: str,
    input_value: str,
    matched_on: str,
    mapped_ids: str,
    mapped_labels: str,
    source_file: str,
    score: float,
    validated: bool,
) -> str:
    confidence = confidence_bucket(score)
    needs_review = "no" if validated else "yes"
    normalized_input = norm_key(input_value)
    return (
        "mapping_provenance=v1;"
        f"method={method};"
        f"input_type={input_type};"
        f"trait_scale={trait_scale};"
        f"input_value={input_value};"
        f"normalized_input={normalized_input};"
        f"matched_on={matched_on};"
        f"mapped_ids={mapped_ids};"
        f"mapped_labels={mapped_labels};"
        f"source_file={source_file};"
        f"confidence={confidence};"
        f"needs_review={needs_review}"
    )


def trait_candidate_prefix_rank(candidate_id: str) -> int:
    parts = split_multi_ids(candidate_id)
    if not parts:
        return 999
    best = 999
    for part in parts:
        rank = TRAIT_PREFERRED_PREFIX_ORDER.get(trait_ontology_prefix(part), 999)
        if rank < best:
            best = rank
    return best


def candidate_has_go_mapping(candidate_id: str) -> bool:
    parts = split_multi_ids(candidate_id)
    if not parts:
        return False
    return any(trait_ontology_prefix(part) == "GO" for part in parts)


def candidate_has_hp_mapping(candidate_id: str) -> bool:
    parts = split_multi_ids(candidate_id)
    if not parts:
        return False
    return any(trait_ontology_prefix(part) == "HP" for part in parts)


def candidate_has_uberon_mapping(candidate_id: str) -> bool:
    parts = split_multi_ids(candidate_id)
    if not parts:
        return False
    return any(trait_ontology_prefix(part) == "UBERON" for part in parts)


def candidate_is_disease_like(
    candidate: Candidate,
    *,
    ontology_terms: dict[str, TraitOntologyTerm],
) -> bool:
    ids = [canonicalize_trait_ontology_id(part) for part in split_multi_ids(candidate.efo_id)]
    ids = [item for item in ids if item]
    if any(trait_ontology_prefix(item) == "MONDO" for item in ids):
        return True
    if has_disease_hint(candidate.label):
        return True
    return any(
        term is not None and has_disease_hint(term.label)
        for term in (ontology_terms.get(item) for item in ids)
    )


def mondo_import_qc(
    mapped_id_text: str,
    *,
    ontology_terms: dict[str, TraitOntologyTerm],
) -> tuple[str, str]:
    mapped_ids = [canonicalize_trait_ontology_id(part) for part in split_multi_ids(mapped_id_text)]
    mapped_ids = [item for item in mapped_ids if item]
    if not mapped_ids:
        return "", ""

    missing_mondo_ids = [
        item
        for item in mapped_ids
        if trait_ontology_prefix(item) == "MONDO" and item not in ontology_terms
    ]
    if not missing_mondo_ids:
        return "", ""

    has_active_non_mondo = any(
        item in ontology_terms and trait_ontology_prefix(item) in {"EFO", "OBA", "HP", "NCIT"}
        for item in mapped_ids
    )
    if has_active_non_mondo:
        return "", ""

    return "term not in EFO", "|".join(missing_mondo_ids)


def trait_term_branch(
    *,
    term_id: str,
    label: str,
    ontology_terms: dict[str, TraitOntologyTerm],
    measurement_term_ids: set[str],
) -> str:
    oid = canonicalize_trait_ontology_id(term_id)
    term = ontology_terms.get(oid)
    text = norm_key(label or (term.label if term is not None else ""))
    toks = tokenize(text)
    prefix = trait_ontology_prefix(oid)

    if oid in measurement_term_ids:
        return "measurement"
    if prefix == "OBA":
        return "measurement"
    if toks & MEASUREMENT_HINT_TOKENS:
        return "measurement"
    if has_disease_hint(text):
        return "non_measurement"
    if prefix in {"MONDO", "HP"}:
        return "non_measurement"
    if text:
        # Default unresolved trait labels to non-measurement so quantitative
        # inputs only auto-validate when measurement evidence is explicit.
        return "non_measurement"
    return "unknown"


def trait_candidate_branch(
    *,
    mapped_id_text: str,
    mapped_label_text: str,
    ontology_terms: dict[str, TraitOntologyTerm],
    measurement_term_ids: set[str],
) -> str:
    mapped_ids = [canonicalize_trait_ontology_id(part) for part in split_multi_ids(mapped_id_text)]
    mapped_ids = [item for item in mapped_ids if item]
    if not mapped_ids:
        return "unknown"

    labels = split_multi_labels(mapped_label_text, expected_n=len(mapped_ids))
    measurement_count = 0
    non_measurement_count = 0
    unknown_count = 0
    for idx, term_id in enumerate(mapped_ids):
        label = normalize(labels[idx] if idx < len(labels) else "")
        branch = trait_term_branch(
            term_id=term_id,
            label=label,
            ontology_terms=ontology_terms,
            measurement_term_ids=measurement_term_ids,
        )
        if branch == "measurement":
            measurement_count += 1
        elif branch == "non_measurement":
            non_measurement_count += 1
        else:
            unknown_count += 1

    if measurement_count and non_measurement_count:
        return "mixed"
    if measurement_count:
        return "measurement"
    if non_measurement_count:
        return "non_measurement"
    if unknown_count:
        return "unknown"
    return "unknown"


def ukb_field_prefers_measurement_scale(query: str, field_titles: tuple[str, ...]) -> bool:
    query_norm = normalize_trait_text_for_similarity(query) or norm_key(query)
    title_norm = " ".join(
        normalize_trait_text_for_similarity(title) or norm_key(title)
        for title in field_titles
        if normalize(title)
    ).strip()
    combined = f"{query_norm} {title_norm}".strip()
    if not combined:
        return False
    tokens = set(re.findall(r"[a-z0-9]+", combined))
    if any(pattern.search(query) for pattern in UKB_BINARY_RESPONSE_HINT_PATTERNS):
        if any(pattern.search(combined) for pattern in UKB_BINARY_MEASUREMENT_PREFERRED_HINT_PATTERNS):
            return True
        # Keep explicit binary behavior/exposure responses eligible for binary
        # ontology traits unless measurement evidence is much stronger.
        behavior_tokens = {"consume", "consumed", "consumption", "drinking", "smoking", "use"}
        if not (tokens & (UKB_MEASUREMENT_LIKE_HINT_TOKENS - behavior_tokens)):
            return False
    if tokens & UKB_MEASUREMENT_LIKE_HINT_TOKENS:
        return True
    if re.search(r"\b(?:minutes?|hours?|secs?|seconds?|times?)\b", combined, re.IGNORECASE):
        return True
    if re.search(r"\b\d+\s*(?:-|to)\s*\d+\b", combined):
        return True
    if any(pattern.search(query) for pattern in UKB_ORDINAL_RESPONSE_HINT_PATTERNS):
        return True
    return False


def ukb_field_is_medication_use(
    *,
    field_ids: tuple[str, ...],
    field_titles: tuple[str, ...],
    query: str,
    additional_info: str,
) -> bool:
    if "20003" in field_ids:
        return True
    combined = " ".join(
        part
        for part in (
            query,
            additional_info,
            *field_titles,
        )
        if normalize(part)
    )
    key = normalize_trait_text_for_similarity(combined) or norm_key(combined)
    if not key:
        return False
    if (
        "insulin" in key
        and (
            "diabetes" in key
            or "mellitis diagnosis" in key
            or "mellitus diagnosis" in key
            or "within one year" in key
        )
    ):
        return True
    medication_markers = (
        "treatment or medication code",
        "treatment or medication use",
        "medication for ",
        "substances taken for ",
        "vitamin and mineral supplements",
        "cholesterol lowering medication",
        "blood pressure medication",
        "pain relief",
        "laxatives",
    )
    return any(marker in key for marker in medication_markers)


def query_has_family_history_context(
    *,
    query: str,
    field_titles: tuple[str, ...],
    category_labels: tuple[str, ...],
    category_paths: tuple[str, ...],
    additional_info: str,
) -> bool:
    combined = " ".join(
        part
        for part in (query, additional_info, *field_titles, *category_labels, *category_paths)
        if normalize(part)
    )
    key = normalize_trait_text_for_similarity(combined) or norm_key(combined)
    if not key:
        return False
    return "family history" in key or bool(FAMILY_HISTORY_PREFIX_RE.match(normalize(query)))


def extract_family_history_trait_fragment(query: str, additional_info: str) -> str:
    candidates = [normalize(query), derive_primary_trait_query_from_additional_info(additional_info), normalize(additional_info)]
    for raw in candidates:
        text = normalize(raw)
        if not text:
            continue
        text = re.sub(r"\([^)]*\)\s*$", "", text).strip()
        text = FAMILY_HISTORY_PREFIX_RE.sub("", text).strip()
        text = re.sub(r"^\s*-\s*", "", text).strip()
        text = re.sub(r"^\s*(?:do\s+not\s+know|none\s+of\s+the\s+above)\b.*$", "", text, flags=re.IGNORECASE).strip()
        text = re.sub(
            r"\s*-\s*(?:yes|no|prefer not to answer|do not know|none of the above)\b.*$",
            "",
            text,
            flags=re.IGNORECASE,
        ).strip()
        text = re.sub(r"^\s*cancer\b", "lung cancer", text, flags=re.IGNORECASE)
        text = normalize_trait_phrase_aliases(text)
        if not text:
            continue
        return normalize(text)
    return ""


def extract_professional_diagnosis_trait_fragment(query: str, additional_info: str) -> str:
    candidates = [normalize(query), derive_primary_trait_query_from_additional_info(additional_info), normalize(additional_info)]
    wrapper_patterns = (
        re.compile(r"^\s*self report\s*-\s*", re.IGNORECASE),
        re.compile(r"^\s*non cancer illness code self reported\s*-\s*", re.IGNORECASE),
        re.compile(r"^\s*mental health problems ever diagnosed by a professional\s*\d*\s*", re.IGNORECASE),
        re.compile(r"^\s*mental health problems ever diagnosed by a professional\s*-\s*", re.IGNORECASE),
    )
    for raw in candidates:
        text = normalize(raw)
        if not text:
            continue
        text = re.sub(r"\([^)]*\)\s*$", "", text).strip()
        text = normalize(re.sub(r"\(\s*ukb\s+data\s+field\s*[^)]*\)", "", text, flags=re.IGNORECASE))
        text = normalize(re.sub(r"\(\s*(?:gene-based burden|firth correction|spa correction)[^)]*\)", "", text, flags=re.IGNORECASE))
        text = normalize(re.sub(r"\(\s*\d+\s*\)$", "", text))
        text = re.sub(r"\s*/\s*icd10\s+[a-z]\d[\da-z.]*\s*$", "", text, flags=re.IGNORECASE).strip()
        for pattern in wrapper_patterns:
            text = pattern.sub("", text).strip()
        text = text.replace("ocd", "obsessive compulsive disorder")
        text = text.replace("social anxiety or social phobia", "social anxiety disorder")
        text = text.replace("anxiety nerves or generalized anxiety disorder", "generalized anxiety disorder")
        text = text.replace("psychological over eating or binge eating", "binge eating")
        text = text.replace("any other type of psychosis or psychotic illness", "psychosis")
        text = re.sub(r"\bany other phobia\b.*$", "specific phobia", text, flags=re.IGNORECASE)
        text = normalize_trait_phrase_aliases(text)
        if text:
            return text
    return ""


@lru_cache(maxsize=300_000)
def query_has_professional_diagnosis_context(query: str, additional_info: str) -> bool:
    combined = " ".join(
        part
        for part in (
            normalize(query),
            derive_primary_trait_query_from_additional_info(additional_info),
            normalize(additional_info),
        )
        if part
    )
    key = norm_key(combined)
    if not key:
        return False
    return bool(
        re.search(
            r"\b(?:diagnosed\s+by\s+a\s+professional|doctor[-\s]*diagnosed|doctor\s+diagnosed)\b",
            key,
            flags=re.IGNORECASE,
        )
    )


def query_prefers_intervertebral_disc_displacement(query: str, additional_info: str) -> bool:
    combined = " ".join(
        part
        for part in (
            normalize(query),
            extract_professional_diagnosis_trait_fragment(query, additional_info),
            derive_primary_trait_query_from_additional_info(additional_info),
            normalize(additional_info),
        )
        if part
    ).lower()
    if not combined:
        return False
    has_disc_displacement_phrase = bool(
        re.search(r"\b(?:prolapsed|slipped|herniated)\s+disc\b", combined)
        or re.search(r"\bdisc\s+prolaps(?:e|ed|ing)\b", combined)
        or re.search(r"\bdisc\s+herniation\b", combined)
    )
    if not has_disc_displacement_phrase:
        return False
    # Keep level-specific rows eligible for narrower spinal-disease mappings.
    if re.search(r"\b(?:lumbar|lumbosacral|cervical|thoracic)\b", combined):
        return False
    # Avoid hijacking true slipped-capital-femoral-epiphysis style rows.
    if re.search(r"\b(?:epiphys(?:is|eal|es)|capital\s+femoral|scfe)\b", combined):
        return False
    return True


def normalize_trait_phrase_aliases(text: str) -> str:
    raw = text or ""
    raw = re.sub(r"([a-z0-9])([A-Z])", r"\1 \2", raw)
    raw = re.sub(r"([A-Z])([A-Z][a-z])", r"\1 \2", raw)
    value = normalize(raw)
    if not value:
        return ""
    value = re.sub(r"\bwearingglasses\b", "wearing glasses", value, flags=re.IGNORECASE)
    if "rgc" in value.lower():
        rgc_glasses_onset_context = bool(
            re.search(
                r"\bstarted\s+wearing\s+glasses(?:\s+or)?\s+contacts?\s+(?:before|after)\s+40\b",
                value,
                flags=re.IGNORECASE,
            )
        )
        case_control_match = re.match(r"^\s*(.+?)\s+cases?\s+vs\s+.+?\s+controls?\b", value, flags=re.IGNORECASE)
        if case_control_match:
            value = case_control_match.group(1)
        value = re.sub(r"\(\s*rgc\s*\)", " ", value, flags=re.IGNORECASE)
        value = re.sub(r"\brgc\b", " ", value, flags=re.IGNORECASE)
        value = re.sub(r"\b(?:cc|composites?|strict|loose|possible|probable|new|cases?|controls?|vs|noafib)\b", " ", value, flags=re.IGNORECASE)
        value = re.sub(r"\bmed\b", " medication use ", value, flags=re.IGNORECASE)
        value = re.sub(r"\b(?:adult|childhood|any)\b", " ", value, flags=re.IGNORECASE)
        value = re.sub(
            r"\bstarted\s+wearing\s+glasses(?:\s+or)?\s+contacts?\s+(?:before|after)\s+40\b",
            " ",
            value,
            flags=re.IGNORECASE,
        )
        value = re.sub(r"^\s*tag\s+", " ", value, flags=re.IGNORECASE)
        rgc_replacements = (
            (r"\bald\b", "alcoholic liver disease"),
            (r"\banticoag\b", "antithrombotic agent"),
            (r"\bhf\b", "heart failure"),
            (r"\bt2\s*d\b", "type 2 diabetes mellitus"),
            (r"\bt1\s*d\b", "type 1 diabetes mellitus"),
            (r"\bt2d\b", "type 2 diabetes mellitus"),
            (r"\bt1d\b", "type 1 diabetes mellitus"),
            (r"\bhtn\b", "hypertension"),
            (r"\bckd\b", "chronic kidney disease"),
            (r"\bcad\b", "coronary artery disease"),
            (r"\bcvd\b", "cardiovascular disease"),
            (r"\bibd\b", "inflammatory bowel disease"),
            (r"\bmi\b", "myocardial infarction"),
            (r"\bvte\b", "venous thromboembolism"),
            (r"\bdvt\b", "deep vein thrombosis"),
            (r"\bpe\b", "pulmonary embolism"),
            (r"\bbp\b", "blood pressure"),
            (r"\bnasal polyps\b", "nasal polyposis"),
            (r"\bairways medication use\b", "drug use measurement"),
            (r"\blipid\s*lowering\s+medication use\b", "cholesterol lowering medication"),
            (r"\bbleed(?:ing)?\b", "abnormal bleeding"),
        )
        for pattern, replacement in rgc_replacements:
            value = re.sub(pattern, replacement, value, flags=re.IGNORECASE)
        if "inflammatory bowel disease" in norm_key(value):
            value = re.sub(r"\bcd\b", "Crohn disease", value, flags=re.IGNORECASE)
            value = re.sub(r"\buc\b", "ulcerative colitis", value, flags=re.IGNORECASE)
        if not normalize(value) and rgc_glasses_onset_context:
            value = "refractive error measurement"
    value = re.sub(
        r"\bcopd\s+chronic obstructive pulmonary disease\b",
        "chronic obstructive pulmonary disease",
        value,
        flags=re.IGNORECASE,
    )
    replacements = (
        (
            r"^\s*disorders of ([a-z][a-z-]*(?: [a-z][a-z-]*){0,3}) metabolism\s*$",
            r"disorder of \1 metabolism",
        ),
        (r"\bcopd\b", "chronic obstructive pulmonary disease"),
        (r"\btb\b", "tuberculosis"),
        (r"\bibs\b", "irritable bowel syndrome"),
        (r"\buterine endometrial cancer\b", "endometrial cancer"),
        (r"\bcoeliac\b", "celiac"),
        (r"\bmyxoedema\b", "myxedema"),
        (r"\bparkinsons disease\b", "Parkinson disease"),
        (r"\brodent ulcer\b", "basal cell carcinoma"),
        (r"\bbladder cancer\b", "urinary bladder cancer"),
        (r"\bsevere depression\b", "depressive disorder"),
        (r"\bcholelithiasis(?:\s+or)?\s+gall stones\b", "cholelithiasis"),
        (r"\bgall stones\b", "gallstones"),
        (r"\bsleep apnoea\b", "sleep apnea"),
        (r"\bdorsalgia\b", "back pain"),
        (r"\bnon[-\s]*melanoma skin cancer\b", "non-melanoma skin carcinoma"),
        (r"\bcorneal power\b", "corneal topography"),
    )
    for pattern, replacement in replacements:
        value = re.sub(pattern, replacement, value, flags=re.IGNORECASE)
    value = re.sub(
        r"\b(type\s*2 diabetes(?: mellitus)?)\b(?:\s+(?:new|strict|possible|probable|loose))+",
        r"\1",
        value,
        flags=re.IGNORECASE,
    )
    value = re.sub(r"\btype\s*2 diabetes\b", "type 2 diabetes mellitus", value, flags=re.IGNORECASE)
    value = re.sub(r"\s+", " ", value).strip()
    return normalize(value)


def extract_degree_bothered_trait_fragment(query: str, additional_info: str) -> str:
    candidates = [normalize(query), derive_primary_trait_query_from_additional_info(additional_info), normalize(additional_info)]
    pattern = re.compile(
        r"^\s*degree bothered by\s+(.+?)\s+in the\s+(?:last|past)\s+(?:3|three)\s+months\b",
        re.IGNORECASE,
    )
    for raw in candidates:
        text = normalize(raw)
        if not text:
            continue
        match = pattern.search(text)
        if not match:
            continue
        fragment = normalize(match.group(1))
        if not fragment:
            continue
        fragment = normalize_trait_phrase_aliases(fragment)
        if "menstrual cramps" in fragment:
            return "dysmenorrheic pain measurement"
        if "pain in arms" in fragment and "joints" in fragment:
            return "pain measurement"
        if "pain problems during intercourse" in fragment or "pain during intercourse" in fragment:
            return "pain measurement"
        if "feeling heart pound race" in fragment:
            return "palpitations"
        if "fainting spells" in fragment or "fainting" in fragment:
            return "syncope"
        if "urinary frequency" in fragment or "bladder irritability" in fragment:
            return "urinary urgency"
        if "feeling tired all the time" in fragment or "tired all the time" in fragment:
            return "fatigue"
        return fragment
    return ""


def trait_query_is_medication_use(query: str, additional_info: str) -> bool:
    parsed_icd10, _parsed_label = parse_icd10_labeled_trait_text(query)
    if parsed_icd10 or query_explicitly_mentions_icd10(query):
        return False
    combined = " ".join(part for part in (query, additional_info) if normalize(part))
    alias_hint = normalize_trait_phrase_aliases(combined)
    key = normalize_trait_text_for_similarity(" ".join(part for part in (combined, alias_hint) if normalize(part))) or norm_key(combined)
    if not key:
        return False
    if "rgc" in key and bool(re.search(r"\bmed\b", key)):
        return True
    medication_markers = (
        "treatment or medication code",
        "treatment or medication use",
        "medication use",
        "medication for ",
        "vitamin and mineral supplements",
        "cholesterol lowering medication",
        "blood pressure medication",
        "pain relief",
        "laxatives",
    )
    return any(marker in key for marker in medication_markers)


def classify_ukb_medication_use_term(query: str, additional_info: str) -> tuple[str, str]:
    combined = " ".join(part for part in (query, additional_info) if normalize(part))
    alias_hint = normalize_trait_phrase_aliases(combined)
    combined_key = normalize_trait_text_for_similarity(" ".join(part for part in (combined, alias_hint) if normalize(part))) or norm_key(combined)
    combined_search_text = " ".join(part for part in (combined, alias_hint) if normalize(part))
    if (
        "insulin" in combined_key
        and ("diabetes" in combined_key or "mellitis diagnosis" in combined_key or "mellitus diagnosis" in combined_key)
    ):
        return "EFO_0009924", "Drugs used in diabetes use measurement"
    if "insulin" in combined_key and "ukb data field 6177" in combined_key:
        return "EFO_0009924", "Drugs used in diabetes use measurement"
    if "treatment or medication use" in combined_key and (
        "vitamin" in combined_key or "mineral" in combined_key
    ):
        return "EFO_0009116", "vitamin supplement exposure measurement"
    generic_phrase_rules = (
        ("vitamin and mineral supplements", "EFO_0009116", "vitamin supplement exposure measurement"),
        ("cholesterol lowering medication", "EFO_0803367", "antihyperlipidemic drug use measurement"),
        ("blood pressure medication", "EFO_0009927", "antihypertensive use measurement"),
        ("metformin medication use", "EFO_0009924", "Drugs used in diabetes use measurement"),
        ("oral diabetes medication use", "EFO_0009924", "Drugs used in diabetes use measurement"),
        ("pain relief", "EFO_0007012", "NSAID use measurement"),
        ("medication for heartburn", "EFO_0007010", "drug use measurement"),
        ("laxatives", "EFO_0007010", "drug use measurement"),
    )
    for phrase, term_id, label in generic_phrase_rules:
        if phrase in combined_key:
            return term_id, label
    for pattern, term_id, label in UKB_MEDICATION_USE_CLASS_RULES:
        if pattern.search(combined_search_text):
            return term_id, label
    return "EFO_0007010", "drug use measurement"


def preferred_exact_term_for_phrase(
    phrase: str,
    *,
    ontology_exact_index: dict[str, set[str]],
    ontology_terms: dict[str, TraitOntologyTerm],
) -> tuple[str, str]:
    phrase_norm = norm_key(phrase)
    exact_ids = exact_ontology_term_ids_for_keys(
        trait_query_exact_norm_variants(phrase),
        ontology_exact_index=ontology_exact_index,
        ontology_terms=ontology_terms,
    )
    if not exact_ids:
        return "", ""
    exact_label_ids = [
        term_id
        for term_id in exact_ids
        if norm_key(ontology_terms.get(term_id, TraitOntologyTerm(term_id, "", ())).label) == phrase_norm
    ]
    candidate_ids = exact_label_ids or list(exact_ids)
    ordered = sorted(
        candidate_ids,
        key=lambda tid: (
            TRAIT_PREFERRED_PREFIX_ORDER.get(trait_ontology_prefix(tid), 999),
            tid,
        ),
    )
    term_id = ordered[0]
    term = ontology_terms.get(term_id)
    if term is None:
        return "", ""
    return term_id, term.label


def preferred_exact_term_for_phrase_with_required_tokens(
    phrase: str,
    *,
    required_tokens: tuple[str, ...],
    ontology_exact_index: dict[str, set[str]],
    ontology_terms: dict[str, TraitOntologyTerm],
) -> tuple[str, str]:
    exact_ids = exact_ontology_term_ids_for_keys(
        trait_query_exact_norm_variants(phrase),
        ontology_exact_index=ontology_exact_index,
        ontology_terms=ontology_terms,
    )
    if not exact_ids:
        return "", ""
    filtered_ids = []
    for term_id in exact_ids:
        term = ontology_terms.get(term_id)
        if term is None:
            continue
        label_key = normalize(term.label).replace("-", " ")
        if all(token in label_key for token in required_tokens):
            filtered_ids.append(term_id)
    if not filtered_ids:
        return preferred_exact_term_for_phrase(
            phrase,
            ontology_exact_index=ontology_exact_index,
            ontology_terms=ontology_terms,
        )
    ordered = sorted(
        filtered_ids,
        key=lambda tid: (
            TRAIT_PREFERRED_PREFIX_ORDER.get(trait_ontology_prefix(tid), 999),
            tid,
        ),
    )
    term_id = ordered[0]
    term = ontology_terms.get(term_id)
    if term is None:
        return "", ""
    return term_id, term.label


def preferred_exact_cancer_family_term_for_phrase(
    phrase: str,
    *,
    ontology_exact_index: dict[str, set[str]],
    ontology_terms: dict[str, TraitOntologyTerm],
) -> tuple[str, str]:
    phrase_key = normalize_trait_text_for_similarity(phrase) or norm_key(phrase)
    if not phrase_key:
        return "", ""

    exact_ids = exact_ontology_term_ids_for_keys(
        trait_query_exact_norm_variants(phrase),
        ontology_exact_index=ontology_exact_index,
        ontology_terms=ontology_terms,
    )
    if not exact_ids:
        # Fallback for composite phrases like
        # "large bowel cancer colorectal cancer" where the signal lives in
        # embedded cancer subphrases.
        phrase_token_list = [tok for tok in re.findall(r"[a-z0-9]+", phrase_key) if tok]
        for size in range(min(6, len(phrase_token_list)), 1, -1):
            for start in range(0, len(phrase_token_list) - size + 1):
                ngram_tokens = phrase_token_list[start : start + size]
                if "cancer" not in ngram_tokens:
                    continue
                ngram = " ".join(ngram_tokens).strip()
                if not ngram:
                    continue
                exact_ids |= exact_ontology_term_ids_for_keys(
                    (ngram,),
                    ontology_exact_index=ontology_exact_index,
                    ontology_terms=ontology_terms,
                )
    if not exact_ids:
        return "", ""

    phrase_tokens = set(tokenize(phrase_key))
    phrase_location_hints = trait_location_hint_tokens(phrase)
    ranked: list[tuple[int, int, int, int, str]] = []
    for term_id in exact_ids:
        term = ontology_terms.get(term_id)
        if term is None:
            continue
        label_key = normalize_trait_text_for_similarity(term.label) or norm_key(term.label)
        label_tokens = set(tokenize(label_key))
        if "benign" in label_tokens:
            continue
        has_carcinoma = "carcinoma" in label_tokens
        has_cancer = "cancer" in label_tokens
        has_oncologic_generic = bool(label_tokens & {"neoplasm", "tumor", "tumour", "malignancy"})
        # Prefer explicit cancer/neoplasm wording over carcinoma-only labels
        # when the query itself is cancer-family phrasing.
        if has_cancer:
            family_rank = 2
        elif has_oncologic_generic and not has_carcinoma:
            family_rank = 1
        else:
            family_rank = 0
        location_overlap = 0
        if phrase_location_hints:
            location_overlap = len(phrase_location_hints & trait_location_hint_tokens(term.label))
        lexical_overlap = len(phrase_tokens & label_tokens)
        ranked.append(
            (
                family_rank,
                location_overlap,
                lexical_overlap,
                -TRAIT_PREFERRED_PREFIX_ORDER.get(trait_ontology_prefix(term_id), 999),
                term_id,
            )
        )
    if not ranked:
        return "", ""
    ranked.sort(reverse=True)
    best_id = ranked[0][4]
    best_term = ontology_terms.get(best_id)
    if best_term is None:
        return "", ""
    return best_id, best_term.label


def phrase_rule_exact_candidate(
    *,
    phrase: str,
    score: float,
    matched_via: str,
    evidence: str,
    validated: bool,
    ontology_exact_index: dict[str, set[str]],
    ontology_terms: dict[str, TraitOntologyTerm],
) -> Candidate | None:
    term_id, term_label = preferred_exact_term_for_phrase(
        phrase,
        ontology_exact_index=ontology_exact_index,
        ontology_terms=ontology_terms,
    )
    if not term_id:
        return None
    return Candidate(
        efo_id=term_id,
        label=term_label,
        score=score,
        matched_via=matched_via,
        evidence=evidence,
        is_validated=validated,
    )


def phrase_rule_exact_multi_candidate(
    *,
    phrases: tuple[str, ...],
    score: float,
    matched_via: str,
    evidence: str,
    validated: bool,
    ontology_exact_index: dict[str, set[str]],
    ontology_terms: dict[str, TraitOntologyTerm],
) -> Candidate | None:
    ids: list[str] = []
    labels: list[str] = []
    seen_ids: set[str] = set()
    for phrase in phrases:
        term_id, term_label = preferred_exact_term_for_phrase(
            phrase,
            ontology_exact_index=ontology_exact_index,
            ontology_terms=ontology_terms,
        )
        if not term_id or term_id in seen_ids:
            continue
        seen_ids.add(term_id)
        ids.append(term_id)
        labels.append(term_label)
    if len(ids) < 2:
        return None
    return Candidate(
        efo_id="|".join(ids),
        label="|".join(labels),
        score=score,
        matched_via=matched_via,
        evidence=evidence,
        is_validated=validated,
    )


def temporal_phrase_pair_candidate(
    *,
    query_text: str,
    ontology_exact_index: dict[str, set[str]],
    ontology_terms: dict[str, TraitOntologyTerm],
) -> Candidate | None:
    def _clean_fragment(fragment_text: str) -> str:
        fragment = normalize(fragment_text)
        if not fragment:
            return ""
        fragment = re.sub(r"^\s*(?:with|of|for)\s+", "", fragment, flags=re.IGNORECASE)
        fragment = re.sub(r"\b(?:classified elsewhere|not elsewhere classified)\b", " ", fragment, flags=re.IGNORECASE)
        fragment = re.sub(r"\bunspecified\b", " ", fragment, flags=re.IGNORECASE)
        fragment = re.sub(r"\([^)]*\)", " ", fragment)
        fragment = normalize(fragment)
        if not fragment:
            return ""
        return normalize_trait_phrase_aliases(fragment) or fragment

    query_variants: list[str] = []
    for variant in (normalize(query_text), normalize_trait_text_for_similarity(query_text)):
        variant_norm = normalize(variant)
        if variant_norm and variant_norm not in query_variants:
            query_variants.append(variant_norm)
    if not query_variants:
        return None

    temporal_pairs = (
        (r"\bage at first episode of\s+(.+)$", "age at onset"),
        (r"\bage at onset of\s+(.+)$", "age at onset"),
        (r"\bage of onset of\s+(.+)$", "age at onset"),
        (r"\bage when\s+(.+?)\s+first occurred\b", "age at onset"),
        (r"\bage at which\s+(.+?)\s+first occurred\b", "age at onset"),
        (r"\bage at diagnosis of\s+(.+)$", "age at diagnosis"),
        (r"\bage (?:first )?diagnosed with\s+(.+)$", "age at diagnosis"),
        (r"\bage when\s+(.+?)\s+first diagnosed\b", "age at diagnosis"),
        (r"\bage at which\s+(.+?)\s+first diagnosed\b", "age at diagnosis"),
        (r"\binterpolated age of participant when\s+(.+?)\s+first diagnosed\b", "age at diagnosis"),
    )
    for query_key in query_variants:
        for pattern, temporal_phrase in temporal_pairs:
            match = re.search(pattern, query_key)
            if not match:
                continue
            fragment = _clean_fragment(match.group(1))
            if not fragment:
                continue
            time_id, time_label = preferred_exact_term_for_phrase(
                temporal_phrase,
                ontology_exact_index=ontology_exact_index,
                ontology_terms=ontology_terms,
            )
            disease_id = ""
            disease_label = ""
            for candidate_phrase in (fragment, normalize(match.group(1))):
                candidate_phrase = normalize(candidate_phrase)
                if not candidate_phrase:
                    continue
                disease_id, disease_label = preferred_exact_term_for_phrase(
                    candidate_phrase,
                    ontology_exact_index=ontology_exact_index,
                    ontology_terms=ontology_terms,
                )
                if disease_id and disease_label:
                    break
            if time_id and disease_id:
                return Candidate(
                    efo_id=f"{time_id}|{disease_id}",
                    label=f"{time_label}|{disease_label}",
                    score=0.95,
                    matched_via="temporal_condition_composite_exact",
                    evidence=f"paired temporal-condition ontology match for '{fragment}'",
                    is_validated=False,
                )
    return None


def exact_ontology_term_ids_for_keys(
    query_keys: Iterable[str],
    *,
    ontology_exact_index: dict[str, set[str]],
    ontology_terms: dict[str, TraitOntologyTerm],
) -> set[str]:
    filtered: set[str] = set()
    for raw_key in query_keys:
        key = norm_key(raw_key)
        if not key:
            continue
        key_token_count = len(re.findall(r"[a-z0-9]+", key))
        weak_query_key = key in TRAIT_WEAK_EXACT_QUERY_KEYS
        for term_id in ontology_exact_index.get(key, set()):
            oid = canonicalize_trait_ontology_id(term_id)
            term = ontology_terms.get(oid)
            if term is None:
                continue
            scope_rank = trait_match_scope_rank(
                query_exact_keys={key},
                term=term,
                label_text=term.label,
            )
            if key_token_count <= 1 and scope_rank < TRAIT_SYNONYM_SCOPE_RANK["EXACT"]:
                continue
            if weak_query_key and scope_rank < TRAIT_SYNONYM_SCOPE_RANK["EXACT"]:
                continue
            filtered.add(oid)
    return filtered


def trait_scale_mismatch(trait_scale: str, candidate_branch: str) -> bool:
    scale = normalize_trait_scale(trait_scale)
    if scale == "auto":
        return False
    if scale == "quantitative":
        return candidate_branch in {"non_measurement", "mixed"}
    if scale == "binary":
        return candidate_branch in {"measurement", "mixed"}
    return False


def trait_scale_score_adjustment(trait_scale: str, candidate_branch: str) -> float:
    scale = normalize_trait_scale(trait_scale)
    if scale == "auto" or candidate_branch == "unknown":
        return 0.0
    if trait_scale_mismatch(scale, candidate_branch):
        return -0.20
    return 0.06


